  kind: "koofr";
}

export interface AzureBlobStorageConfig {
  containerSasUrl: string;
  containerName: string;
  remotePrefix: string;
  generateFolderObject: boolean;
  partsConcurrency: number;
  kind: "azureblobstorage";
}

export interface OnedriveFullConfig {
  accessToken: string;
  clientID: string;
  authority: string;
  refreshToken: string;
  accessTokenExpiresInSeconds: number;
  accessTokenExpiresAtTime: number;
  deltaLink: string;
  username: string;
  credentialsShouldBeDeletedAtTime?: number;
  remoteBaseDir?: string;
  emptyFile: "skip" | "error";
  kind: "onedrivefull";
}

// ─────────────────────────────────────────────────────────────────────────────

export type SyncDirectionType =
  | "bidirectional"
  | "incremental_pull_only"
  | "incremental_push_only"
  | "incremental_pull_and_delete_only"
  | "incremental_push_and_delete_only";

export type CipherMethodType = "rclone-base64" | "openssl-base64" | "unknown";

export type QRExportType = "basic_and_advanced" | SUPPORTED_SERVICES_TYPE;

export interface ProfilerConfig {
  enable?: boolean;
  enablePrinting?: boolean;
  recordSize?: boolean;
}

export interface BYOCPluginSettings {
  s3: S3Config;
  webdav: WebdavConfig;
  dropbox: DropboxConfig;
  onedrive: OnedriveConfig;
  onedrivefull: OnedriveFullConfig;
  webdis: WebdisConfig;
  googledrive: GoogleDriveConfig;
  box: BoxConfig;
  pcloud: PCloudConfig;
  yandexdisk: YandexDiskConfig;
  koofr: KoofrConfig;
  azureblobstorage: AzureBlobStorageConfig;

  password: string;
  serviceType: SUPPORTED_SERVICES_TYPE;
  currLogLevel?: string;
  autoRunEveryMilliseconds?: number;
  initRunAfterMilliseconds?: number;
  syncOnSaveAfterMilliseconds?: number;

  concurrency?: number;
  syncConfigDir?: boolean;
  syncBookmarks?: boolean;
  syncUnderscoreItems?: boolean;
  lang?: LangTypeAndAuto;
  agreeToUseSyncV3?: boolean;
  skipSizeLargerThan?: number;
  ignorePaths?: string[];
  onlyAllowPaths?: string[];
  enableStatusBarInfo?: boolean;
  deleteToWhere?: "system" | "obsidian";
  conflictAction?: ConflictActionType;

  protectModifyPercentage?: number;
  syncDirection?: SyncDirectionType;

  obfuscateSettingFile?: boolean;

  encryptionMethod?: CipherMethodType;

  profiler?: ProfilerConfig;

  /** Migration version — tracks which migration has been applied */
  migrationVersion?: number;

  /** @deprecated */
  agreeToUploadExtraMetadata?: boolean;
  /** @deprecated */
  vaultRandomID?: string;
  /** @deprecated */
  logToDB?: boolean;
  /** @deprecated */
  howToCleanEmptyFolder?: EmptyFolderCleanType;
  /** @deprecated - removed in BYOC, kept for migration compat */
  pro?: Record<string, unknown>;
}

export const PLUGIN_ID = "obsidian-byoc";
export const PLUGIN_NAME = "BYOC";

// ─── URI / Callback Constants ─────────────────────────────────────────────────

/** Primary URI for BYOC */
export const COMMAND_URI = "bring-your-own-cloud";
/** Legacy alias — accepts old remotely-save:// links */
export const COMMAND_URI_LEGACY = "remotely-save";
export const COMMAND_CALLBACK = "bring-your-own-cloud-cb";
export const COMMAND_CALLBACK_ONEDRIVE = "bring-your-own-cloud-cb-onedrive";
export const COMMAND_CALLBACK_DROPBOX = "bring-your-own-cloud-cb-dropbox";
export const COMMAND_CALLBACK_ONEDRIVEFULL = "bring-your-own-cloud-cb-onedrivefull";
export const COMMAND_CALLBACK_BOX = "bring-your-own-cloud-cb-box";
export const COMMAND_CALLBACK_PCLOUD = "bring-your-own-cloud-cb-pcloud";
export const COMMAND_CALLBACK_YANDEXDISK = "bring-your-own-cloud-cb-yandexdisk";
export const COMMAND_CALLBACK_KOOFR = "bring-your-own-cloud-cb-koofr";
export const COMMAND_CALLBACK_GOOGLEDRIVE = "bring-your-own-cloud-cb-googledrive";

export interface UriParams {
  func?: string;
  vault?: string;
  ver?: string;
  data?: string;
}

export type EmptyFolderCleanType = "skip" | "clean_both";

export type ConflictActionType =
  | "keep_newer"
  | "keep_larger"
  | "smart_conflict";

export type DecisionTypeForMixedEntity =
  | "only_history"
  | "equal"
  | "local_is_modified_then_push"
  | "remote_is_modified_then_pull"
  | "local_is_created_then_push"
  | "remote_is_created_then_pull"
  | "local_is_created_too_large_then_do_nothing"
  | "remote_is_created_too_large_then_do_nothing"
  | "local_is_deleted_thus_also_delete_remote"
  | "remote_is_deleted_thus_also_delete_local"
  | "conflict_created_then_keep_local"
  | "conflict_created_then_keep_remote"
  | "conflict_created_then_smart_conflict"
  | "conflict_created_then_do_nothing"
  | "conflict_modified_then_keep_local"
  | "conflict_modified_then_keep_remote"
  | "conflict_modified_then_smart_conflict"
  | "folder_existed_both_then_do_nothing"
  | "folder_existed_local_then_also_create_remote"
  | "folder_existed_remote_then_also_create_local"
  | "folder_to_be_created"
  | "folder_to_skip"
  | "folder_to_be_deleted_on_both"
  | "folder_to_be_deleted_on_remote"
  | "folder_to_be_deleted_on_local"
  // ── Rename detections (post-planner pass) ─────────────────────────────────
  | "rename_local_to_remote"   // Local rename: update remote to match
  | "rename_remote_to_local";  // Remote rename: update local to match

/**
 * Uniform representation of a file/folder entity.
 * Everything should be flat and primitive so it can be copied.
 */
export interface Entity {
  key?: string;
  keyEnc?: string;
  keyRaw: string;
  mtimeCli?: number;
  mtimeCliFmt?: string;
  ctimeCli?: number;
  ctimeCliFmt?: string;
  mtimeSvr?: number;
  mtimeSvrFmt?: string;
  prevSyncTime?: number;
  prevSyncTimeFmt?: string;
  size?: number;
  sizeEnc?: number;
  sizeRaw: number;
  hash?: string;
  etag?: string;
  synthesizedFolder?: boolean;
  synthesizedFile?: boolean;
}

export interface UploadedType {
  entity: Entity;
  mtimeCli?: number;
}

export interface MixedEntity {
  key: string;
  local?: Entity;
  prevSync?: Entity;
  remote?: Entity;

  decisionBranch?: number;
  decision?: DecisionTypeForMixedEntity;
  conflictAction?: ConflictActionType;

  /** For rename decisions: the original (old) path the file was renamed FROM. */
  renameFrom?: string;

  change?: boolean;
  sideNotes?: any;
}

/** @deprecated */
export interface FileOrFolderMixedState {
  key: string;
  existLocal?: boolean;
  existRemote?: boolean;
  mtimeLocal?: number;
  mtimeRemote?: number;
  deltimeLocal?: number;
  deltimeRemote?: number;
  sizeLocal?: number;
  sizeLocalEnc?: number;
  sizeRemote?: number;
  sizeRemoteEnc?: number;
  changeRemoteMtimeUsingMapping?: boolean;
  changeLocalMtimeUsingMapping?: boolean;
  decision?: string;
  decisionBranch?: number;
  syncDone?: "done";
  remoteEncryptedKey?: string;
  mtimeLocalFmt?: string;
  mtimeRemoteFmt?: string;
  deltimeLocalFmt?: string;
  deltimeRemoteFmt?: string;
}

export const DEFAULT_DEBUG_FOLDER = "_debug_byoc/";
export const DEFAULT_SYNC_PLANS_HISTORY_FILE_PREFIX = "sync_plans_hist_exported_on_";
export const DEFAULT_LOG_HISTORY_FILE_PREFIX = "log_hist_exported_on_";
export const DEFAULT_PROFILER_RESULT_FILE_PREFIX = "profiler_results_exported_on_";

export type SyncTriggerSourceType =
  | "manual"
  | "dry"
  | "auto"
  | "auto_once_init"
  | "auto_sync_on_save";

export const REMOTELY_SAVE_VERSION_2022 = "0.3.25";
export const REMOTELY_SAVE_VERSION_2024PREPARE = "0.3.32";
export const BYOC_VERSION_1_0_0 = "1.0.0";

/** Smart conflict merge threshold: files larger than this use duplicate strategy */
export const SMART_CONFLICT_MERGE_SIZE_LIMIT = 1_000_000; // 1 MB

import { base64url } from "rfc4648";
import { reverseString } from "./misc";

import type { BYOCPluginSettings } from "./baseTypes";

const DEFAULT_README: string =
  "The file contains sensitive info, so DO NOT take screenshot of, copy, or share it to anyone! It's also generated automatically, so do not edit it manually.";

interface MessyConfigType {
  readme: string;
  d: string;
}

/**
 * this should accept the result after loadData();
 */
export const messyConfigToNormal = (
  x: MessyConfigType | BYOCPluginSettings | null | undefined
): BYOCPluginSettings | null | undefined => {
  // console.debug("loading, original config on disk:");
  // console.debug(x);
  if (x === null || x === undefined) {
    console.debug("the messy config is null or undefined, skip");
    return x;
  }
  if ("readme" in x && "d" in x) {
    // we should decode
    const y = JSON.parse(
      (
        base64url.parse(reverseString(x["d"]), {
          out: Buffer.allocUnsafe as any,
          loose: true,
        }) as Buffer
      ).toString("utf-8")
    );
    // console.debug("loading, parsed config is:");
    // console.debug(y);
    return y;
  } else {
    // return as is
    // console.debug("loading, parsed config is the same");
    return x;
  }
};

/**
 * this should accept the result of original config
 */
export const normalConfigToMessy = (
  x: BYOCPluginSettings | null | undefined
) => {
  if (x === null || x === undefined) {
    console.debug("the normal config is null or undefined, skip");
    return x;
  }
  const y = {
    readme: DEFAULT_README,
    d: reverseString(
      base64url.stringify(Buffer.from(JSON.stringify(x), "utf-8"), {
        pad: false,
      })
    ),
  };
  // console.debug("encoding, encoded config is:");
  // console.debug(y);
  return y;
};

import type { Vault } from "obsidian";

/** SyncPlanType — local stub; full type defined in Batch 2 sync engine */
type SyncPlanType = Record<string, unknown>;
import {
  DEFAULT_DEBUG_FOLDER,
  DEFAULT_PROFILER_RESULT_FILE_PREFIX,
  DEFAULT_SYNC_PLANS_HISTORY_FILE_PREFIX,
} from "./baseTypes";
import {
  readAllProfilerResultsByVault,
  readAllSyncPlanRecordTextsByVault,
} from "./localdb";
import type { InternalDBs } from "./localdb";
import { mkdirpInVault } from "./misc";

const getSubsetOfSyncPlan = (x: string, onlyChange: boolean) => {
  if (!onlyChange) {
    return x;
  }
  const y: SyncPlanType = JSON.parse(x);
  const z: SyncPlanType = Object.fromEntries(
    Object.entries(y).filter(([key, val]) => {
      if (key === "/$@meta") {
        return true;
      }
      const v = val as { change?: unknown };
      return v.change === undefined || v.change === true;
    })
  );
  return JSON.stringify(z, null, 2);
};

export const exportVaultSyncPlansToFiles = async (
  db: InternalDBs,
  vault: Vault,
  vaultRandomID: string,
  howMany: number,
  onlyChange: boolean
) => {
  console.debug("exporting sync plans");
  await mkdirpInVault(DEFAULT_DEBUG_FOLDER, vault);
  const records = await readAllSyncPlanRecordTextsByVault(db, vaultRandomID);
  let md = "";
  if (records.length === 0) {
    md = "No sync plans history found";
  } else {
    if (howMany <= 0) {
      md =
        "Sync plans found:\n\n" +
        records
          .map(
            (x) => "```json\n" + getSubsetOfSyncPlan(x, onlyChange) + "\n```\n"
          )
          .join("\n");
    } else {
      md =
        "Sync plans found:\n\n" +
        records
          .map(
            (x) => "```json\n" + getSubsetOfSyncPlan(x, onlyChange) + "\n```\n"
          )
          .slice(0, howMany)
          .join("\n");
    }
  }
  const ts = Date.now();
  const filePath = `${DEFAULT_DEBUG_FOLDER}${DEFAULT_SYNC_PLANS_HISTORY_FILE_PREFIX}${ts}.md`;
  await vault.create(filePath, md, {
    mtime: ts,
  });
  console.debug("finish exporting sync plans");
};

export const exportVaultProfilerResultsToFiles = async (
  db: InternalDBs,
  vault: Vault,
  vaultRandomID: string
) => {
  console.debug("exporting profiler results");
  await mkdirpInVault(DEFAULT_DEBUG_FOLDER, vault);
  const records = await readAllProfilerResultsByVault(db, vaultRandomID);
  let md = "";
  if (records.length === 0) {
    md = "No profiler results found";
  } else {
    md =
      "Profiler results found:\n\n" +
      records.map((x) => "```\n" + x + "\n```\n").join("\n");
  }
  const ts = Date.now();
  const filePath = `${DEFAULT_DEBUG_FOLDER}${DEFAULT_PROFILER_RESULT_FILE_PREFIX}${ts}.md`;
  await vault.create(filePath, md, {
    mtime: ts,
  });
  console.debug("finish exporting profiler results");
};

import { base32, base64url } from "rfc4648";
import { bufferToArrayBuffer, hexStringToTypedArray } from "./misc";

const DEFAULT_ITER = 20000;

// base32.stringify(Buffer.from('Salted__'))
export const MAGIC_ENCRYPTED_PREFIX_BASE32 = "KNQWY5DFMRPV";
// base64.stringify(Buffer.from('Salted__'))
export const MAGIC_ENCRYPTED_PREFIX_BASE64URL = "U2FsdGVkX";

const getKeyIVFromPassword = async (
  salt: Uint8Array,
  password: string,
  rounds: number = DEFAULT_ITER
) => {
  const k1 = await activeWindow.crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(password).buffer,
    { name: "PBKDF2" },
    false,
    ["deriveKey", "deriveBits"]
  );

  const k2 = (await activeWindow.crypto.subtle.deriveBits(
    {
      name: "PBKDF2",
      salt: salt as any,
      iterations: rounds,
      hash: "SHA-256",
    },
    k1,
    256 + 128
  ));

  return k2;
};

export const encryptArrayBuffer = async (
  arrBuf: ArrayBuffer,
  password: string,
  rounds: number = DEFAULT_ITER,
  saltHex = ""
) => {
  let salt: Uint8Array;
  if (saltHex !== "") {
    salt = hexStringToTypedArray(saltHex);
  } else {
    salt = activeWindow.crypto.getRandomValues(new Uint8Array(8));
  }

  const derivedKey = await getKeyIVFromPassword(salt, password, rounds);
  const key = derivedKey.slice(0, 32);
  const iv = derivedKey.slice(32, 32 + 16);

  const keyCrypt = await activeWindow.crypto.subtle.importKey(
    "raw",
    key,
    { name: "AES-CBC" },
    false,
    ["encrypt", "decrypt"]
  );

  const enc = (await activeWindow.crypto.subtle.encrypt(
    { name: "AES-CBC", iv },
    keyCrypt,
    arrBuf
  ));

  const prefix = new TextEncoder().encode("Salted__");

  const res = new Uint8Array([...prefix, ...salt, ...new Uint8Array(enc)]);

  return bufferToArrayBuffer(res);
};

export const decryptArrayBuffer = async (
  arrBuf: ArrayBuffer,
  password: string,
  rounds: number = DEFAULT_ITER
) => {
  const prefix = arrBuf.slice(0, 8);
  const salt = arrBuf.slice(8, 16);
  const derivedKey = await getKeyIVFromPassword(
    new Uint8Array(salt),
    password,
    rounds
  );
  const key = derivedKey.slice(0, 32);
  const iv = derivedKey.slice(32, 32 + 16);

  const keyCrypt = await activeWindow.crypto.subtle.importKey(
    "raw",
    key,
    { name: "AES-CBC" },
    false,
    ["encrypt", "decrypt"]
  );

  const dec = (await activeWindow.crypto.subtle.decrypt(
    { name: "AES-CBC", iv },
    keyCrypt,
    arrBuf.slice(16)
  ));

  return dec;
};

export const encryptStringToBase32 = async (
  text: string,
  password: string,
  rounds: number = DEFAULT_ITER,
  saltHex = ""
) => {
  const enc = await encryptArrayBuffer(
    bufferToArrayBuffer(new TextEncoder().encode(text)) as ArrayBuffer,
    password,
    rounds,
    saltHex
  );
  return base32.stringify(new Uint8Array(enc), { pad: false });
};

export const decryptBase32ToString = async (
  text: string,
  password: string,
  rounds: number = DEFAULT_ITER
) => {
  return new TextDecoder().decode(
    await decryptArrayBuffer(
      bufferToArrayBuffer(base32.parse(text, { loose: true })) as ArrayBuffer,
      password,
      rounds
    )
  );
};

export const encryptStringToBase64url = async (
  text: string,
  password: string,
  rounds: number = DEFAULT_ITER,
  saltHex = ""
) => {
  const enc = await encryptArrayBuffer(
    bufferToArrayBuffer(new TextEncoder().encode(text)) as ArrayBuffer,
    password,
    rounds,
    saltHex
  );
  return base64url.stringify(new Uint8Array(enc), { pad: false });
};

export const decryptBase64urlToString = async (
  text: string,
  password: string,
  rounds: number = DEFAULT_ITER
) => {
  return new TextDecoder().decode(
    await decryptArrayBuffer(
      bufferToArrayBuffer(base64url.parse(text, { loose: true })) as ArrayBuffer,
      password,
      rounds
    )
  );
};

export const getSizeFromOrigToEnc = (x: number) => {
  if (x < 0 || Number.isNaN(x) || !Number.isInteger(x)) {
    throw Error(`getSizeFromOrigToEnc: x=${x} is not a valid size`);
  }
  return (Math.floor(x / 16) + 1) * 16 + 16;
};

export const getSizeFromEncToOrig = (x: number) => {
  if (x < 32 || Number.isNaN(x) || !Number.isInteger(x)) {
    throw Error(`getSizeFromEncToOrig: ${x} is not a valid size`);
  }
  if (x % 16 !== 0) {
    throw Error(
      `getSizeFromEncToOrig: ${x} is not a valid encrypted file size`
    );
  }
  return {
    minSize: ((x - 16) / 16 - 1) * 16,
    maxSize: ((x - 16) / 16 - 1) * 16 + 15,
  };
};

import {
  Cipher as CipherRCloneCryptPack,
  encryptedSize,
} from "@fyears/rclone-crypt";

// @ts-ignore
import EncryptWorker from "./encryptRClone.worker";

interface RecvMsg {
  status: "ok" | "error";
  outputName?: string;
  outputContent?: ArrayBuffer;
  error?: any;
}

export const getSizeFromOrigToEnc = encryptedSize;

export class CipherRclone {
  readonly password: string;
  readonly cipher: CipherRCloneCryptPack;
  readonly workers: Worker[];
  init: boolean;
  workerIdx: number;
  constructor(password: string, workerNum: number) {
    this.password = password;
    this.init = false;
    this.workerIdx = 0;

    // console.debug("begin creating CipherRCloneCryptPack");
    this.cipher = new CipherRCloneCryptPack("base64");
    // console.debug("finish creating CipherRCloneCryptPack");

    // console.debug("begin creating EncryptWorker");
    this.workers = [];
    for (let i = 0; i < workerNum; ++i) {
      this.workers.push(new (EncryptWorker as any)() as Worker);
    }

    // console.debug("finish creating EncryptWorker");
  }

  closeResources() {
    for (let i = 0; i < this.workers.length; ++i) {
      this.workers[i].terminate();
    }
  }

  async prepareByCallingWorker(): Promise<void> {
    if (this.init) {
      return;
    }
    // console.debug("begin prepareByCallingWorker");
    await this.cipher.key(this.password, "");
    // console.debug("finish getting key");

    const res: Promise<void>[] = [];
    for (let i = 0; i < this.workers.length; ++i) {
      res.push(
        new Promise((resolve, reject) => {
          const channel = new MessageChannel();

          channel.port2.onmessage = (event) => {
            // console.debug("main: receiving msg in prepare");
            const { status } = event.data as RecvMsg;
            if (status === "ok") {
              // console.debug("main: receiving init ok in prepare");
              this.init = true;
              resolve(); // return the class object itself
            } else {
              reject(new Error("error after prepareByCallingWorker"));
            }
          };

          channel.port2.onmessageerror = (event) => {
            // console.debug("main: receiving error in prepare");
            reject(new Error(`messageerror: ${String(event.data)}`));
          };

          // console.debug("main: before postMessage in prepare");
          this.workers[i].postMessage(
            {
              action: "prepare",
              dataKeyBuf: this.cipher.dataKey.buffer,
              nameKeyBuf: this.cipher.nameKey.buffer,
              nameTweakBuf: this.cipher.nameTweak.buffer,
            },
            [channel.port1 /* buffer no transfered because we need to copy */]
          );
        })
      );
    }
    await Promise.all(res);
  }

  async encryptNameByCallingWorker(inputName: string): Promise<string> {
    // console.debug("main: start encryptNameByCallingWorker");
    await this.prepareByCallingWorker();
    // console.debug(
    //   "main: really start generate promise in encryptNameByCallingWorker"
    // );
    ++this.workerIdx;
    const whichWorker = this.workerIdx % this.workers.length;
    return await new Promise((resolve, reject) => {
      const channel = new MessageChannel();

      channel.port2.onmessage = (event) => {
        // console.debug("main: receiving msg in encryptNameByCallingWorker");
        const { outputName } = event.data as RecvMsg;
        if (outputName === undefined) {
          reject(new Error("unknown outputName after encryptNameByCallingWorker"));
        } else {
          resolve(outputName);
        }
      };

      channel.port2.onmessageerror = (event) => {
        // console.debug("main: receiving error in encryptNameByCallingWorker");
        reject(new Error(`messageerror: ${String(event.data)}`));
      };

      // console.debug("main: before postMessage in encryptNameByCallingWorker");
      this.workers[whichWorker].postMessage(
        {
          action: "encryptName",
          inputName: inputName,
        },
        [channel.port1]
      );
    });
  }

  async decryptNameByCallingWorker(inputName: string): Promise<string> {
    await this.prepareByCallingWorker();
    ++this.workerIdx;
    const whichWorker = this.workerIdx % this.workers.length;
    return await new Promise((resolve, reject) => {
      const channel = new MessageChannel();

      channel.port2.onmessage = (event) => {
        // console.debug("main: receiving msg in decryptNameByCallingWorker");
        const { outputName, status } = event.data as RecvMsg;

        if (status === "error") {
          reject(new Error("error"));
        } else {
          if (outputName === undefined) {
            reject(new Error("unknown outputName after decryptNameByCallingWorker"));
          } else {
            resolve(outputName);
          }
        }
      };

      channel.port2.onmessageerror = (event) => {
        // console.debug("main: receiving error in decryptNameByCallingWorker");
        reject(new Error(`messageerror: ${String(event.data)}`));
        channel;
      };

      // console.debug("main: before postMessage in decryptNameByCallingWorker");
      this.workers[whichWorker].postMessage(
        {
          action: "decryptName",
          inputName: inputName,
        },
        [channel.port1]
      );
    });
  }

  async encryptContentByCallingWorker(
    input: ArrayBuffer
  ): Promise<ArrayBuffer> {
    await this.prepareByCallingWorker();
    ++this.workerIdx;
    const whichWorker = this.workerIdx % this.workers.length;
    return await new Promise((resolve, reject) => {
      const channel = new MessageChannel();

      channel.port2.onmessage = (event) => {
        // console.debug("main: receiving msg in encryptContentByCallingWorker");
        const { outputContent } = event.data as RecvMsg;
        if (outputContent === undefined) {
          reject(new Error("unknown outputContent after encryptContentByCallingWorker"));
        } else {
          resolve(outputContent);
        }
      };

      channel.port2.onmessageerror = (event) => {
        // console.debug("main: receiving error in encryptContentByCallingWorker");
        reject(new Error(`messageerror: ${String(event.data)}`));
      };

      // console.debug(
      //   "main: before postMessage in encryptContentByCallingWorker"
      // );
      this.workers[whichWorker].postMessage(
        {
          action: "encryptContent",
          inputContent: input,
        },
        [
          channel.port1,
          // input // the array buffer might be re-used later, so we CANNOT transfer here
        ]
      );
    });
  }

  async decryptContentByCallingWorker(
    input: ArrayBuffer
  ): Promise<ArrayBuffer> {
    await this.prepareByCallingWorker();
    ++this.workerIdx;
    const whichWorker = this.workerIdx % this.workers.length;
    return await new Promise((resolve, reject) => {
      const channel = new MessageChannel();

      channel.port2.onmessage = (event) => {
        // console.debug("main: receiving msg in decryptContentByCallingWorker");
        const { outputContent, status } = event.data as RecvMsg;

        if (status === "error") {
          reject(new Error("error"));
        } else {
          if (outputContent === undefined) {
            reject(new Error("unknown outputContent after decryptContentByCallingWorker"));
          } else {
            resolve(outputContent);
          }
        }
      };

      channel.port2.onmessageerror = (event) => {
        // console.debug(
        //   "main: receiving onmessageerror in decryptContentByCallingWorker"
        // );
        reject(new Error(`messageerror: ${String(event.data)}`));
      };

      // console.debug(
      //   "main: before postMessage in decryptContentByCallingWorker"
      // );
      this.workers[whichWorker].postMessage(
        {
          action: "decryptContent",
          inputContent: input,
        },
        [
          channel.port1,
          input, // not transfer for safety
        ]
      );
    });
  }
}

import { type App, Modal, Notice, Setting, setIcon } from "obsidian";
import type { FakeFs } from "./fsAll";
import { getClient } from "./fsGetter";

/**
 * Default folder name to suggest in the picker's create input.
 *
 * - If the user already has a configured remoteBaseDir, that wins (they're
 *   re-picking and the current value is the right starting point).
 * - Otherwise we prefix the vault name with "Obsidian - " so the folder is
 *   self-describing in their cloud's root listing. Multiple vaults from
 *   the same user cluster together alphabetically.
 * - Skip the prefix when the vault name already starts with "obsidian"
 *   (case-insensitive) — avoids "Obsidian - Obsidian Vault" etc.
 */
export function suggestedFolderName(app: App, currentValue?: string): string {
  const trimmed = currentValue?.trim();
  if (trimmed && trimmed.length > 0) return trimmed;
  const vault = app.vault.getName();
  return /^obsidian/i.test(vault) ? vault : `Obsidian - ${vault}`;
}

/**
 * Render the current remote folder location as a styled breadcrumb in a
 * Setting's description area: `Provider › segment › leaf`.
 *
 * Splits on "/" so nested paths are forward-compatible with future tree
 * navigation. The final leaf gets the accent color so it reads as the
 * "current location" rather than just a label.
 */
export function renderFolderBreadcrumb(
  setting: Setting,
  providerLabel: string,
  currentFolder: string
): void {
  const breadcrumb = setting.descEl.createDiv({
    cls: "byoc-folder-breadcrumb",
  });
  breadcrumb.createSpan({
    cls: "byoc-folder-breadcrumb__root",
    text: providerLabel,
  });
  const segments = currentFolder.split("/").filter((s) => s.length > 0);
  for (const seg of segments) {
    breadcrumb.createSpan({ cls: "byoc-folder-breadcrumb__sep", text: "›" });
    breadcrumb.createSpan({ cls: "byoc-folder-breadcrumb__leaf", text: seg });
  }
}

/**
 * Single helper for opening the folder picker for any provider. Used by:
 *   1. Post-OAuth callbacks in main.ts (run after auth completes)
 *   2. Settings → Change folder buttons in each provider's settings panel
 *
 * Sets `awaitingFolderSelection` while the picker is open so sync triggers
 * bail out, then clears it on pick. Refreshes the settings tab on pick so
 * the breadcrumb display reflects the new folder immediately.
 *
 * `plugin: any` avoids a circular import on BYOCPlugin.
 */
export function openFolderPickerForProvider(opts: {
  app: App;
  plugin: any;
  providerKey: string;
  providerLabel: string;
}): void {
  const { app, plugin, providerKey, providerLabel } = opts;
  plugin.awaitingFolderSelection = true;
  const fs = getClient(plugin.settings, app.vault.getName(), () =>
    plugin.saveSettings()
  );
  const current = plugin.settings[providerKey]?.remoteBaseDir;
  new RemoteFolderPickerModal(
    app,
    fs,
    providerLabel,
    suggestedFolderName(app, current),
    async (folderName) => {
      plugin.settings[providerKey].remoteBaseDir = folderName;
      await plugin.saveSettings();
      plugin.awaitingFolderSelection = false;
      plugin.settingTab?.display();
      new Notice(`BYOC will sync to "${folderName}".`);
    }
  ).open();
}

/**
 * Post-OAuth folder picker. Opens immediately after a successful auth
 * exchange so the user can choose where their vault lives in their cloud
 * before the first sync runs. Without this, the plugin defaults
 * remoteBaseDir to the vault name — which usually points at an empty
 * folder, making the first sync plan look like "delete everything locally".
 *
 * The caller is responsible for blocking sync triggers while this modal
 * is open (see `BYOCPlugin.awaitingFolderSelection`).
 */
export class RemoteFolderPickerModal extends Modal {
  private busy = false;
  /** Folders at the cloud root, populated after listFoldersAtRoot resolves.
   *  Used by the Create & use button to detect when the typed name matches
   *  an existing folder — in that case we just pick the existing one
   *  instead of trying to create a duplicate. */
  private folders: string[] = [];

  constructor(
    app: App,
    private readonly fs: FakeFs,
    private readonly providerLabel: string,
    private readonly suggestedName: string,
    private readonly onPicked: (folderName: string) => void
  ) {
    super(app);
  }

  async onOpen() {
    this.titleEl.setText(`Choose ${this.providerLabel} folder`);
    this.modalEl.addClass("byoc-folder-picker");

    const { contentEl } = this;
    contentEl.empty();

    contentEl.createEl("p", {
      cls: "byoc-folder-picker__desc",
      text: "Pick a folder in your cloud, or create a new one.",
    });

    // Create section first — keeps the input above the on-screen keyboard
    // on mobile. Visually this trades the "existing first" convention for
    // a layout that just works under iOS without scroll-into-view tricks.
    contentEl.createEl("div", {
      cls: "byoc-folder-picker__section-label",
      text: "Create new",
    });
    this.renderCreate(contentEl);

    contentEl.createEl("div", {
      cls: "byoc-folder-picker__section-label",
      text: "Existing folders",
    });

    const listWrap = contentEl.createDiv({ cls: "byoc-folder-picker__list" });
    this.renderLoading(listWrap);

    try {
      this.folders = await this.fs.listFoldersAtRoot();
      this.renderList(listWrap, this.folders);
    } catch (err) {
      console.error("[BYOC] listFoldersAtRoot failed:", err);
      this.renderError(listWrap, err);
    }
  }

  private renderLoading(host: HTMLElement) {
    host.empty();
    host.addClass("byoc-folder-picker__list--state");
    const wrap = host.createDiv({ cls: "byoc-folder-picker__loading" });
    wrap.createDiv({ cls: "byoc-folder-picker__loader" });
    wrap.createSpan({ text: "Loading folders…" });
  }

  private renderError(host: HTMLElement, err: any) {
    host.empty();
    host.addClass("byoc-folder-picker__list--state");
    const wrap = host.createDiv({ cls: "byoc-folder-picker__error" });
    wrap.createEl("p", {
      cls: "byoc-folder-picker__error-msg",
      text: `Could not list folders: ${err?.message ?? err}`,
    });
    const retry = wrap.createEl("button", {
      cls: "byoc-folder-picker__retry",
      text: "Retry",
    });
    retry.addEventListener("click", async () => {
      this.renderLoading(host);
      try {
        const folders = await this.fs.listFoldersAtRoot();
        this.renderList(host, folders);
      } catch (e) {
        this.renderError(host, e);
      }
    });
  }

  private renderList(host: HTMLElement, folders: string[]) {
    host.empty();
    if (folders.length === 0) {
      host.addClass("byoc-folder-picker__list--state");
      host.createDiv({
        cls: "byoc-folder-picker__empty",
        text: "No folders at the root yet. Create one below.",
      });
      return;
    }
    host.removeClass("byoc-folder-picker__list--state");
    for (const name of folders) {
      const row = host.createEl("button", { cls: "byoc-folder-picker__row" });
      const iconEl = row.createDiv({ cls: "byoc-folder-picker__row-icon" });
      setIcon(iconEl, "folder");
      row.createDiv({ cls: "byoc-folder-picker__row-name", text: name });
      const chev = row.createDiv({ cls: "byoc-folder-picker__row-chev" });
      setIcon(chev, "chevron-right");
      row.addEventListener("click", () => this.pick(name));
    }
  }

  private renderCreate(host: HTMLElement) {
    const wrap = host.createDiv({ cls: "byoc-folder-picker__create" });
    const input = wrap.createEl("input", {
      cls: "byoc-folder-picker__input",
      attr: { type: "text", placeholder: "Folder name" },
    });
    input.value = this.suggestedName;
    const btn = wrap.createEl("button", {
      cls: "byoc-folder-picker__create-btn mod-cta",
      text: "Create & use",
    });
    btn.addEventListener("click", async () => {
      if (this.busy) return;
      const name = input.value.trim();
      if (!name) {
        new Notice("Folder name is required.");
        input.focus();
        return;
      }

      // If a folder with this name already exists, just use it instead of
      // calling the create API. The user's intent is "I want this folder
      // name" — whether it's pre-existing or freshly created is plumbing.
      // Case-insensitive so "Obsidian - Vault" and "obsidian - vault" don't
      // collide on case-sensitive providers and still resolve to the right
      // folder on case-insensitive ones.
      const existing = this.folders.find(
        (f) => f.toLowerCase() === name.toLowerCase()
      );
      if (existing) {
        new Notice(`Using existing folder "${existing}".`);
        this.pick(existing);
        return;
      }

      this.busy = true;
      btn.disabled = true;
      btn.textContent = "Creating…";
      try {
        await this.fs.createFolderAtRoot(name);
        this.pick(name);
      } catch (err) {
        // Provider returned "already exists" — race condition or hidden
        // folder we couldn't enumerate. Treat it as success and use the
        // name; the next sync will resolve to whatever's there.
        const msg = String((err as any)?.message ?? err).toLowerCase();
        if (
          msg.includes("already exists") ||
          msg.includes("already_exists") ||
          msg.includes("exist")
        ) {
          new Notice(`Folder "${name}" already exists. Using it.`);
          this.pick(name);
          return;
        }
        console.error("[BYOC] createFolderAtRoot failed:", err);
        new Notice(`Could not create folder: ${(err as any)?.message ?? err}`);
        this.busy = false;
        btn.disabled = false;
        btn.textContent = "Create & use";
      }
    });
  }

  private pick(folderName: string) {
    this.onPicked(folderName);
    this.close();
  }

  onClose() {
    this.contentEl.empty();
  }
}

import isEqual from "lodash/isEqual";
import { nanoid } from "nanoid";
import type { Entity } from "./baseTypes";

export abstract class FakeFs {
  abstract kind: string;
  abstract walk(): Promise<Entity[]>;
  abstract walkPartial(): Promise<Entity[]>;
  abstract stat(key: string): Promise<Entity>;
  abstract mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity>;
  abstract writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity>;
  abstract readFile(key: string): Promise<ArrayBuffer>;
  abstract rename(key1: string, key2: string): Promise<void>;
  /** Returns true if this provider supports atomic rename without copy+delete. */
  abstract supportsRename(): boolean;
  abstract rm(key: string): Promise<void>;
  abstract checkConnect(callbackFunc?: any): Promise<boolean>;
  async checkConnectCommonOps(callbackFunc?: any) {
    try {
      console.debug(`check connect: create folder`);
      const folderName = `rs-test-folder-${nanoid()}/`;
      await this.mkdir(folderName);
      // await delay(3000);

      console.debug(`check connect: upload file`);
      const filename = `${folderName}rs-test-file-${nanoid()}`;
      const ctime = Date.now();
      const mtime1 = Date.now();
      const content1 = new ArrayBuffer(100);
      await this.writeFile(filename, content1, mtime1, ctime);
      // await delay(3000);

      console.debug(`check connect: overwrite file`);
      const mtime2 = Date.now();
      const content2 = new ArrayBuffer(200);
      await this.writeFile(filename, content2, mtime2, ctime);
      // await delay(3000);

      console.debug(`check connect: download file`);
      const content3 = await this.readFile(filename);
      if (!isEqual(content2, content3)) {
        throw Error(`downloaded file is not equal with uploaded file!`);
      }
      // await delay(3000);

      console.debug(`check connect: delete file`);
      await this.rm(filename);
      // await delay(3000);

      console.debug(`check connect: delete folder`);
      await this.rm(folderName);
      // await delay(3000);

      return true;
    } catch (err) {
      console.error(err);
      callbackFunc?.(err);
      return false;
    }
  }
  abstract getUserDisplayName(): Promise<string>;
  abstract revokeAuth(): Promise<void>;
  abstract allowEmptyFile(): boolean;

  /**
   * List folder names at the cloud root (ignoring this.remoteBaseDir).
   * Used by the post-OAuth folder picker so users can choose where their
   * vault lives in their cloud, instead of silently defaulting to the
   * vault name and triggering a destructive first-sync plan.
   *
   * Default: throws. Override in providers that support OAuth folder picking.
   */
  async listFoldersAtRoot(): Promise<string[]> {
    throw new Error(`[BYOC] listFoldersAtRoot not implemented for ${this.kind}`);
  }

  /**
   * Create a folder at the cloud root (ignoring this.remoteBaseDir).
   * Used by the folder picker's "Create new folder" option.
   *
   * Default: throws. Override in providers that support OAuth folder picking.
   */
  async createFolderAtRoot(name: string): Promise<void> {
    throw new Error(`[BYOC] createFolderAtRoot not implemented for ${this.kind}`);
  }
}

/**
 * BYOC — Box Filesystem Adapter
 * Clean-room implementation using Box Content API v2.
 * OAuth2 authorization code flow with silent token refresh.
 */

import { request } from "obsidian";
import {
  BOX_CLIENT_ID,
  BOX_CLIENT_SECRET,
  COMMAND_CALLBACK_BOX,
  DEFAULT_CONTENT_TYPE,
  type BoxConfig,
  type Entity,
} from "./baseTypes";
import { FakeFs } from "./fsAll";
import { retryFetch } from "./misc";

const BOX_API = "https://api.box.com/2.0";
const BOX_UPLOAD_API = "https://upload.box.com/api/2.0";
const BOX_AUTH_URL = "https://account.box.com/api/oauth2/authorize";
const BOX_TOKEN_URL = "https://api.box.com/oauth2/token";
const REDIRECT_URI = "https://bringyourowncloud.xyz/auth/box/callback";

export const DEFAULT_BOX_CONFIG: BoxConfig = {
  accessToken: "",
  accessTokenExpiresInMs: 0,
  accessTokenExpiresAtTimeMs: 0,
  refreshToken: "",
  remoteBaseDir: "",
  credentialsShouldBeDeletedAtTimeMs: 0,
  kind: "box",
};

////////////////////////////////////////////////////////////////////////////////
// OAuth2 Helpers
////////////////////////////////////////////////////////////////////////////////

export function generateAuthUrl(): string {
  const params = new URLSearchParams({
    response_type: "code",
    client_id: BOX_CLIENT_ID,
    redirect_uri: REDIRECT_URI,
  });
  return `${BOX_AUTH_URL}?${params.toString()}`;
}

export async function sendAuthReq(
  code: string,
  errorCallBack: (e: unknown) => Promise<void>
): Promise<any> {
  try {
    const rsp = await request({
      url: BOX_TOKEN_URL,
      method: "POST",
      contentType: "application/x-www-form-urlencoded",
      body: new URLSearchParams({
        grant_type: "authorization_code",
        code: code,
        client_id: BOX_CLIENT_ID,
        client_secret: BOX_CLIENT_SECRET,
        redirect_uri: REDIRECT_URI,
      }).toString(),
    });
    return JSON.parse(rsp);
  } catch (e) {
    console.error(e);
    await errorCallBack(e);
  }
}

async function refreshAccessToken(
  refreshToken: string
): Promise<any> {
  const rsp = await request({
    url: BOX_TOKEN_URL,
    method: "POST",
    contentType: "application/x-www-form-urlencoded",
    body: new URLSearchParams({
      grant_type: "refresh_token",
      refresh_token: refreshToken,
      client_id: BOX_CLIENT_ID,
      client_secret: BOX_CLIENT_SECRET,
    }).toString(),
  });
  return JSON.parse(rsp);
}

interface BoxOAuthRes {
  access_token: string;
  refresh_token: string;
  expires_in: number;
}

export async function setConfigBySuccessfullAuthInplace(
  config: BoxConfig,
  authRes: Record<string, unknown>,
  saveFunc: () => Promise<void>
): Promise<void> {
  const r = authRes as unknown as BoxOAuthRes;
  config.accessToken = r.access_token;
  config.refreshToken = r.refresh_token;
  config.accessTokenExpiresInMs = r.expires_in * 1000;
  config.accessTokenExpiresAtTimeMs =
    Date.now() + r.expires_in * 1000 - 300_000;
  // BYOC: No forced expiry
  config.credentialsShouldBeDeletedAtTimeMs = 0;
  await saveFunc();
}

////////////////////////////////////////////////////////////////////////////////
// Internal Helpers
////////////////////////////////////////////////////////////////////////////////

/**
 * Box uses folder IDs, not paths. We need to resolve a path to a folder ID.
 * This caches folder IDs as we discover them.
 */
class BoxPathResolver {
  private cache: Map<string, string> = new Map([["", "0"]]); // root = "0"

  async resolve(
    path: string,
    getJson: (url: string) => Promise<any>,
    createIfMissing = false,
    postJson?: (url: string, body: unknown) => Promise<unknown>
  ): Promise<string> {
    if (path === "" || path === "/") return "0";

    // Normalize: remove leading/trailing slashes
    const normalized = path.replace(/^\/+|\/+$/g, "");
    if (this.cache.has(normalized)) return this.cache.get(normalized)!;

    // Walk segments
    const segments = normalized.split("/");
    let parentId = "0";

    for (let i = 0; i < segments.length; i++) {
      const seg = segments[i];
      const partialPath = segments.slice(0, i + 1).join("/");

      if (this.cache.has(partialPath)) {
        parentId = this.cache.get(partialPath)!;
        continue;
      }

      // Search for folder in parent
      const searchUrl = `${BOX_API}/folders/${parentId}/items?fields=id,name,type&limit=1000`;
      const res = await getJson(searchUrl);
      const entries = res.entries || [];

      const match = entries.find(
        (e: any) => e.name === seg && e.type === "folder"
      );

      if (match) {
        parentId = match.id;
        this.cache.set(partialPath, parentId);
      } else if (createIfMissing && postJson) {
        // Create the folder
        const created = await postJson(`${BOX_API}/folders`, {
          name: seg,
          parent: { id: parentId },
        });
        parentId = (created as { id: string }).id;
        this.cache.set(partialPath, parentId);
      } else {
        throw Error(`[BYOC] Box: folder '${seg}' not found in parent ${parentId}`);
      }
    }

    return parentId;
  }

  set(path: string, id: string) {
    this.cache.set(path.replace(/^\/+|\/+$/g, ""), id);
  }
}

function fromBoxItemToEntity(item: any, baseDirPrefix: string): Entity {
  let key = "";

  // Build the key from path_collection
  if (item.path_collection?.entries) {
    const parts = item.path_collection.entries
      .map((e: any) => e.name)
      .filter((n: string) => n !== "All Files");
    parts.push(item.name);
    key = parts.join("/");

    // Strip the base dir prefix
    if (baseDirPrefix && key.startsWith(`${baseDirPrefix}/`)) {
      key = key.slice(baseDirPrefix.length + 1);
    } else if (key === baseDirPrefix) {
      key = "";
    }
  } else {
    key = item.name || "";
  }

  const isFolder = item.type === "folder";
  if (isFolder && !key.endsWith("/")) {
    key = `${key}/`;
  }

  const mtime = item.modified_at
    ? new Date(item.modified_at).getTime()
    : Date.now();
  const ctime = item.created_at
    ? new Date(item.created_at).getTime()
    : mtime;

  return {
    key: key,
    keyRaw: key,
    mtimeSvr: mtime,
    mtimeCli: mtime,
    ctimeCli: ctime,
    size: isFolder ? 0 : (item.size ?? 0),
    sizeRaw: isFolder ? 0 : (item.size ?? 0),
    etag: item.etag,
  };
}

