export class FakeFsBox extends FakeFs {
  kind = "box";
  private config: BoxConfig;
  private vaultName: string;
  private saveFunc: () => Promise<void>;
  private pathResolver: BoxPathResolver;
  private remoteBaseDir: string;

  constructor(
    config: BoxConfig,
    vaultName: string,
    saveFunc: () => Promise<void>
  ) {
    super();
    this.config = config;
    this.vaultName = vaultName;
    this.saveFunc = saveFunc;
    this.pathResolver = new BoxPathResolver();
    this.remoteBaseDir = config.remoteBaseDir || vaultName || "";
  }

  private async ensureToken(): Promise<string> {
    if (!this.config.accessToken || !this.config.refreshToken) {
      throw Error("[BYOC] Box: user has not authorized yet.");
    }

    if (this.config.accessTokenExpiresAtTimeMs > Date.now()) {
      return this.config.accessToken;
    }

    // Refresh
    const res = await refreshAccessToken(this.config.refreshToken);
    if (res.error) {
      throw Error(`[BYOC] Box refresh error: ${res.error_description}`);
    }
    this.config.accessToken = res.access_token;
    this.config.refreshToken = res.refresh_token;
    this.config.accessTokenExpiresInMs = res.expires_in * 1000;
    this.config.accessTokenExpiresAtTimeMs =
      Date.now() + res.expires_in * 1000 - 300_000;
    await this.saveFunc();
    return this.config.accessToken;
  }

   


  private async _getJson(url: string): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${BOX_API}${url}`;
    return JSON.parse(
      await request({
        url: fullUrl,
        method: "GET",
        headers: { Authorization: `Bearer ${token}` },
      })
    );
  }

   


  private async _postJson(url: string, body: any): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${BOX_API}${url}`;
    return JSON.parse(
      await request({
        url: fullUrl,
        method: "POST",
        contentType: "application/json",
        body: JSON.stringify(body),
        headers: { Authorization: `Bearer ${token}` },
      })
    );
  }

   


  private async _putJson(url: string, body: any): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${BOX_API}${url}`;
    return JSON.parse(
      await request({
        url: fullUrl,
        method: "PUT",
        contentType: "application/json",
        body: JSON.stringify(body),
        headers: { Authorization: `Bearer ${token}` },
      })
    );
  }

  private async _delete(url: string): Promise<void> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${BOX_API}${url}`;
    await retryFetch(fullUrl, {
      method: "DELETE",
      headers: { Authorization: `Bearer ${token}` },
    });
  }

  private async getBaseFolderId(): Promise<string> {
    return this.pathResolver.resolve(
      this.remoteBaseDir,
      (u) => this._getJson(u),
      true,
      (u, b) => this._postJson(u, b)
    );
  }

  /**
   * Recursively list all items in a Box folder.
   */
  private async listFolder(
    folderId: string,
    pathPrefix: string
  ): Promise<any[]> {
    const items: any[] = [];
    let offset = 0;
    const limit = 1000;

    while (true) {
      const res = await this._getJson(
        `${BOX_API}/folders/${folderId}/items?fields=id,name,type,size,modified_at,created_at,etag,path_collection&limit=${limit}&offset=${offset}`
      );
      const entries = res.entries || [];
      for (const entry of entries) {
        items.push(entry);
        if (entry.type === "folder") {
          const subItems = await this.listFolder(
            entry.id,
            `${pathPrefix}${entry.name}/`
          );
          items.push(...subItems);
        }
      }
      offset += entries.length;
      if (offset >= (res.total_count ?? entries.length)) break;
      if (entries.length === 0) break;
    }

    return items;
  }

  async listFoldersAtRoot(): Promise<string[]> {
    const res = await this._getJson(
      `${BOX_API}/folders/0/items?fields=id,name,type&limit=1000`
    );
    return (res.entries || [])
      .filter((e: any) => e.type === "folder")
      .map((e: any) => e.name as string)
      .sort((a: string, b: string) => a.localeCompare(b));
  }

  async createFolderAtRoot(name: string): Promise<void> {
    await this._postJson(`${BOX_API}/folders`, {
      name,
      parent: { id: "0" },
    });
  }

  async walk(): Promise<Entity[]> {
    const baseFolderId = await this.getBaseFolderId();
    const items = await this.listFolder(baseFolderId, "");

    return items.map((item) => {
      const isFolder = item.type === "folder";
      // Build key from the item — we need to resolve relative to our base
      let key = "";
      if (item.path_collection?.entries) {
        const parts = item.path_collection.entries.map((e: any) => e.name);
        parts.push(item.name);
        // Remove "All Files" and the base dir prefix
        const fullPath = parts.filter((n: string) => n !== "All Files").join("/");
        if (fullPath.startsWith(`${this.remoteBaseDir}/`)) {
          key = fullPath.slice(this.remoteBaseDir.length + 1);
        } else {
          key = item.name;
        }
      } else {
        key = item.name;
      }

      if (isFolder && !key.endsWith("/")) key = `${key}/`;

      const mtime = item.modified_at ? new Date(item.modified_at).getTime() : 0;
      const ctime = item.created_at ? new Date(item.created_at).getTime() : mtime;

      return {
        key, keyRaw: key,
        mtimeSvr: mtime, mtimeCli: mtime, ctimeCli: ctime,
        size: isFolder ? 0 : (item.size ?? 0),
        sizeRaw: isFolder ? 0 : (item.size ?? 0),
        etag: item.etag,
      };
    });
  }

  async walkPartial(): Promise<Entity[]> {
    return this.walk();
  }

  async stat(key: string): Promise<Entity> {
    const isFolder = key.endsWith("/");
    if (isFolder) {
      const folderId = await this.pathResolver.resolve(
        `${this.remoteBaseDir}/${key.replace(/\/+$/, "")}`,
        (u) => this._getJson(u)
      );
      const res = await this._getJson(
        `${BOX_API}/folders/${folderId}?fields=id,name,type,size,modified_at,created_at`
      );
      return fromBoxItemToEntity(res, this.remoteBaseDir);
    }

    // For files, find by navigating to parent + searching
    const parentPath = key.includes("/")
      ? key.slice(0, key.lastIndexOf("/"))
      : "";
    const fileName = key.includes("/")
      ? key.slice(key.lastIndexOf("/") + 1)
      : key;

    const parentFolderId = await this.pathResolver.resolve(
      parentPath ? `${this.remoteBaseDir}/${parentPath}` : this.remoteBaseDir,
      (u) => this._getJson(u)
    );

    const res = await this._getJson(
      `${BOX_API}/folders/${parentFolderId}/items?fields=id,name,type,size,modified_at,created_at,etag`
    );
    const match = (res.entries || []).find(
      (e: any) => e.name === fileName && e.type === "file"
    );
    if (!match) throw Error(`[BYOC] Box: file '${key}' not found`);

    return {
      key, keyRaw: key,
      mtimeSvr: match.modified_at ? new Date(match.modified_at).getTime() : 0,
      mtimeCli: match.modified_at ? new Date(match.modified_at).getTime() : 0,
      size: match.size ?? 0,
      sizeRaw: match.size ?? 0,
      etag: match.etag,
    };
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    const fullPath = `${this.remoteBaseDir}/${key.replace(/\/+$/, "")}`;
    await this.pathResolver.resolve(
      fullPath,
      (u) => this._getJson(u),
      true,
      (u, b) => this._postJson(u, b)
    );
    return { key, keyRaw: key, size: 0, sizeRaw: 0 };
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    const parentPath = key.includes("/")
      ? key.slice(0, key.lastIndexOf("/"))
      : "";
    const fileName = key.includes("/")
      ? key.slice(key.lastIndexOf("/") + 1)
      : key;

    const parentFolderId = await this.pathResolver.resolve(
      parentPath ? `${this.remoteBaseDir}/${parentPath}` : this.remoteBaseDir,
      (u) => this._getJson(u),
      true,
      (u, b) => this._postJson(u, b)
    );

    const token = await this.ensureToken();

    // Check if file already exists (for overwrite)
    let existingFileId: string | null = null;
    try {
      const res = await this._getJson(
        `${BOX_API}/folders/${parentFolderId}/items?fields=id,name,type&limit=1000`
      );
      const match = (res.entries || []).find(
        (e: any) => e.name === fileName && e.type === "file"
      );
      if (match) existingFileId = match.id;
    } catch {
      // ignore
    }

    if (existingFileId) {
      // Upload new version
      const formData = new FormData();
      formData.append("file", new Blob([content]), fileName);
      const resp = await retryFetch(
        `${BOX_UPLOAD_API}/files/${existingFileId}/content`,
        {
          method: "POST",
          headers: { Authorization: `Bearer ${token}` },
          body: formData,
        }
      );
      if (!resp.ok) {
        throw Error(`[BYOC] Box: upload new version failed: ${resp.status}`);
      }
    } else {
      // Upload new file
      const formData = new FormData();
      formData.append(
        "attributes",
        JSON.stringify({ name: fileName, parent: { id: parentFolderId } })
      );
      formData.append("file", new Blob([content]), fileName);
      const resp = await retryFetch(`${BOX_UPLOAD_API}/files/content`, {
        method: "POST",
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      });
      if (!resp.ok) {
        throw Error(`[BYOC] Box: upload new file failed: ${resp.status}`);
      }
    }

    return {
      key, keyRaw: key,
      mtimeCli: mtime, ctimeCli: ctime,
      size: content.byteLength,
      sizeRaw: content.byteLength,
    };
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    // Find file ID first
    const parentPath = key.includes("/")
      ? key.slice(0, key.lastIndexOf("/"))
      : "";
    const fileName = key.includes("/")
      ? key.slice(key.lastIndexOf("/") + 1)
      : key;

    const parentFolderId = await this.pathResolver.resolve(
      parentPath ? `${this.remoteBaseDir}/${parentPath}` : this.remoteBaseDir,
      (u) => this._getJson(u)
    );

    const res = await this._getJson(
      `${BOX_API}/folders/${parentFolderId}/items?fields=id,name,type&limit=1000`
    );
    const match = (res.entries || []).find(
      (e: any) => e.name === fileName && e.type === "file"
    );
    if (!match) throw Error(`[BYOC] Box: file '${key}' not found for read`);

    const token = await this.ensureToken();
    const resp = await retryFetch(`${BOX_API}/files/${match.id}/content`, {
      headers: { Authorization: `Bearer ${token}` },
      redirect: "follow",
    });
    if (!resp.ok) {
      throw Error(`[BYOC] Box: readFile failed: ${resp.status}`);
    }
    return resp.arrayBuffer();
  }

  async rename(key1: string, key2: string): Promise<void> {
    // Box rename = update name on file/folder object
    const content = await this.readFile(key1);
    const now = Date.now();
    await this.writeFile(key2, content, now, now);
    await this.rm(key1);
  }

  async rm(key: string): Promise<void> {
    const isFolder = key.endsWith("/");
    const parentPath = key.includes("/")
      ? key.slice(0, key.lastIndexOf("/") || undefined).replace(/\/+$/, "")
      : "";
    const name = isFolder
      ? key.replace(/\/+$/, "").split("/").pop()!
      : key.split("/").pop()!;

    const parentFolderId = await this.pathResolver.resolve(
      parentPath ? `${this.remoteBaseDir}/${parentPath}` : this.remoteBaseDir,
      (u) => this._getJson(u)
    );

    const res = await this._getJson(
      `${BOX_API}/folders/${parentFolderId}/items?fields=id,name,type&limit=1000`
    );
    const itemType = isFolder ? "folder" : "file";
    const match = (res.entries || []).find(
      (e: any) => e.name === name && e.type === itemType
    );
    if (!match) return; // Already gone

    if (isFolder) {
      await this._delete(`${BOX_API}/folders/${match.id}?recursive=true`);
    } else {
      await this._delete(`${BOX_API}/files/${match.id}`);
    }
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    return this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    const res = await this._getJson(`${BOX_API}/users/me?fields=name`);
    return res.name || "Box User";
  }

  async revokeAuth(): Promise<void> {
    this.config.accessToken = "";
    this.config.refreshToken = "";
    await this.saveFunc();
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return true;
  }
}

import { Dropbox, DropboxAuth } from "dropbox";
import type { DropboxResponse, DropboxResponseError, files } from "dropbox";
import random from "lodash/random";
import { requestUrl } from "obsidian";
import {
  COMMAND_CALLBACK_DROPBOX,
  DROPBOX_APP_KEY,
  type DropboxConfig,
  type Entity,
} from "./baseTypes";
import { FakeFs } from "./fsAll";
import {
  bufferToArrayBuffer,
  delay,
  getFolderLevels,
  getParentFolder,
  hasEmojiInText,
  headersToRecord,
} from "./misc";

export { Dropbox } from "dropbox";

export const DEFAULT_DROPBOX_CONFIG: DropboxConfig = {
  accessToken: "",
  clientID: DROPBOX_APP_KEY ?? "",
  refreshToken: "",
  accessTokenExpiresInSeconds: 0,
  accessTokenExpiresAtTime: 0,
  accountID: "",
  username: "",
  credentialsShouldBeDeletedAtTime: 0,
};

const getDropboxPath = (fileOrFolderPath: string, remoteBaseDir: string) => {
  let key = fileOrFolderPath;
  if (fileOrFolderPath === "/" || fileOrFolderPath === "") {
    // special
    key = `/${remoteBaseDir}`;
  } else if (fileOrFolderPath.startsWith("/")) {
    console.warn(
      `why the path ${fileOrFolderPath} starts with '/'? but we just go on.`
    );
    key = `/${remoteBaseDir}${fileOrFolderPath}`;
  } else {
    key = `/${remoteBaseDir}/${fileOrFolderPath}`;
  }
  if (key.endsWith("/")) {
    key = key.slice(0, key.length - 1);
  }
  return key;
};

const getNormPath = (fileOrFolderPath: string, remoteBaseDir: string) => {
  if (
    !(
      fileOrFolderPath === `/${remoteBaseDir}` ||
      fileOrFolderPath.startsWith(`/${remoteBaseDir}/`)
    )
  ) {
    throw Error(
      `"${fileOrFolderPath}" doesn't starts with "/${remoteBaseDir}/"`
    );
  }
  return fileOrFolderPath.slice(`/${remoteBaseDir}/`.length);
};

const fromDropboxItemToEntity = (
  x:
    | files.FileMetadataReference
    | files.FolderMetadataReference
    | files.DeletedMetadataReference,
  remoteBaseDir: string
): Entity => {
  let key = getNormPath(x.path_display!, remoteBaseDir);
  if (x[".tag"] === "folder" && !key.endsWith("/")) {
    key = `${key}/`;
  }

  if (x[".tag"] === "folder") {
    return {
      key: key,
      keyRaw: key,
      size: 0,
      sizeRaw: 0,
    };
  } else if (x[".tag"] === "file") {
    const mtimeCli = Date.parse(x.client_modified).valueOf();
    const mtimeSvr = Date.parse(x.server_modified).valueOf();
    return {
      key: key,
      keyRaw: key,
      mtimeCli: mtimeCli,
      mtimeSvr: mtimeSvr,
      size: x.size,
      sizeRaw: x.size,
      hash: x.content_hash,
    };
  } else {
    // x[".tag"] === "deleted"
    throw Error("do not support deleted tag");
  }
};

/**
 * https://github.com/remotely-save/remotely-save/issues/567
 * https://www.dropboxforum.com/t5/Dropbox-API-Support-Feedback/Case-Sensitivity-in-API-2/td-p/191279
 * @param entities
 */
export const fixEntityListCasesInplace = (entities: { key?: string }[]) => {
  for (const iterator of entities) {
    if (iterator.key === undefined) {
      throw Error(`dropbox list should all have key, but meet undefined`);
    }
  }

  entities.sort((a, b) => a.key!.length - b.key!.length);
  // console.debug(JSON.stringify(entities,null,2));

  const caseMapping: Record<string, string> = { "": "" };
  for (const e of entities) {
    // console.debug(`looking for: ${JSON.stringify(e, null, 2)}`);

    let parentFolder = getParentFolder(e.key!);
    if (parentFolder === "/") {
      parentFolder = "";
    }
    const parentFolderLower = parentFolder.toLocaleLowerCase();
    const segs = e.key!.split("/");
    if (e.key!.endsWith("/")) {
      // folder
      if (Object.prototype.hasOwnProperty.call(caseMapping, parentFolderLower)) {
        const newKey = `${caseMapping[parentFolderLower]}${segs
          .slice(-2)
          .join("/")}`;
        caseMapping[newKey.toLocaleLowerCase()] = newKey;
        e.key = newKey;
        // console.debug(JSON.stringify(caseMapping,null,2));
        // continue;
      } else {
        throw Error(`${parentFolder} doesn't have cases record??`);
      }
    } else {
      // file
      if (Object.prototype.hasOwnProperty.call(caseMapping, parentFolderLower)) {
        const newKey = `${caseMapping[parentFolderLower]}${segs
          .slice(-1)
          .join("/")}`;
        e.key = newKey;
        // continue;
      } else {
        throw Error(`${parentFolder} doesn't have cases record??`);
      }
    }
  }

  return entities;
};

////////////////////////////////////////////////////////////////////////////////
// Other usual common methods
////////////////////////////////////////////////////////////////////////////////

interface ErrSubType {
  error: {
    retry_after: number;
  };
}

async function retryReq<T>(
  reqFunc: () => Promise<DropboxResponse<T>>,
  extraHint = ""
): Promise<DropboxResponse<T> | undefined> {
  const waitSeconds = [1, 2, 4, 8]; // hard code exponential backoff
  for (let idx = 0; idx < waitSeconds.length; ++idx) {
    try {
      if (idx !== 0) {
        console.warn(
          `${extraHint === "" ? "" : extraHint + ": "}The ${
            idx + 1
          }-th try starts at time ${Date.now()}`
        );
      }
      return await reqFunc();
    } catch (e: unknown) {
      const err = e as DropboxResponseError<ErrSubType>;
      if (err.status === undefined) {
        // then the err is not DropboxResponseError
        throw e instanceof Error ? e : new Error(String(e));
      }
      if (err.status !== 429) {
        // then the err is not "too many requests", give up
        throw new Error(`Dropbox API error ${err.status}: ${JSON.stringify(err)}`);
      }

      if (idx === waitSeconds.length - 1) {
        // the last retry also failed, give up
        throw new Error(
          `${
            extraHint === "" ? "" : extraHint + ": "
          }"429 too many requests", after retrying for ${
            idx + 1
          } times still failed.`
        );
      }

      const headers = headersToRecord(err.headers);
      const svrSec =
        err.error.error.retry_after ||
        Number.parseInt(headers["retry-after"] || "1") ||
        1;
      const fallbackSec = waitSeconds[idx];
      const secMin = Math.max(svrSec, fallbackSec);
      const secMax = Math.max(secMin * 1.8, 2);
      console.warn(
        `${
          extraHint === "" ? "" : extraHint + ": "
        }We have "429 too many requests" error of ${
          idx + 1
        }-th try, at time ${Date.now()}, and wait for ${secMin} ~ ${secMax} seconds to retry. Original info: ${JSON.stringify(
          err.error,
          null,
          2
        )}`
      );
      await delay(random(secMin * 1000, secMax * 1000));
    }
  }
}

////////////////////////////////////////////////////////////////////////////////
// Dropbox authorization using PKCE
// see https://dropbox.tech/developers/pkce--what-and-why-
////////////////////////////////////////////////////////////////////////////////

export const getAuthUrlAndVerifier = async (
  appKey: string,
  needManualPatse = false
) => {
  const auth = new DropboxAuth({
    clientId: appKey,
  });

  const callback = needManualPatse
    ? undefined
    : `obsidian://${COMMAND_CALLBACK_DROPBOX}`;
  const authUrl = (
    await auth.getAuthenticationUrl(
      callback as any,
      undefined,
      "code",
      "offline",
      undefined,
      "none",
      true
    )
  ).toString();
  const verifier = auth.getCodeVerifier();
  return {
    authUrl: authUrl,
    verifier: verifier,
  };
};

export interface DropboxSuccessAuthRes {
  access_token: string;
  token_type: "bearer";
  expires_in: string;
  refresh_token?: string;
  scope?: string;
  uid?: string;
  account_id?: string;
}

export const sendAuthReq = async (
  appKey: string,
  verifier: string,
  authCode: string,
  errorCallBack: (e: unknown) => void | Promise<void>
) => {
  try {
    const resp1 = await requestUrl({
      url: "https://api.dropboxapi.com/oauth2/token",
      method: "POST",
      contentType: "application/x-www-form-urlencoded",
      body: new URLSearchParams({
        code: authCode,
        grant_type: "authorization_code",
        code_verifier: verifier,
        client_id: appKey,
        redirect_uri: `obsidian://${COMMAND_CALLBACK_DROPBOX}`,
      }).toString(),
      throw: false,
    });
    const resp2 = resp1.json as DropboxSuccessAuthRes;
    return resp2;
  } catch (e) {
    console.error(e);
    if (errorCallBack !== undefined) {
      await errorCallBack(e);
    }
  }
};

export const sendRefreshTokenReq = async (
  appKey: string,
  refreshToken: string
) => {
  try {
    console.debug("start auto getting refreshed Dropbox access token.");
    const resp1 = await requestUrl({
      url: "https://api.dropboxapi.com/oauth2/token",
      method: "POST",
      contentType: "application/x-www-form-urlencoded",
      body: new URLSearchParams({
        grant_type: "refresh_token",
        refresh_token: refreshToken,
        client_id: appKey,
      }).toString(),
      throw: false,
    });
    const resp2 = resp1.json as DropboxSuccessAuthRes;
    console.debug("finish auto getting refreshed Dropbox access token.");
    return resp2;
  } catch (e) {
    console.error(e);
    throw e;
  }
};

export const setConfigBySuccessfullAuthInplace = async (
  config: DropboxConfig,
  authRes: DropboxSuccessAuthRes,
  saveUpdatedConfigFunc: () => Promise<void> | undefined
) => {
  console.debug("start updating local info of Dropbox token");

  config.accessToken = authRes.access_token;
  config.accessTokenExpiresInSeconds = Number.parseInt(authRes.expires_in);
  config.accessTokenExpiresAtTime =
    Date.now() + Number.parseInt(authRes.expires_in) * 1000 - 10 * 1000;

  // BYOC: No forced expiry — credentials persist until revoked by user
  config.credentialsShouldBeDeletedAtTime = 0;

  if (authRes.refresh_token !== undefined) {
    config.refreshToken = authRes.refresh_token;
    config.accountID = authRes.account_id!;
  }

  if (saveUpdatedConfigFunc !== undefined) {
    await saveUpdatedConfigFunc();
  }

  console.debug("finish updating local info of Dropbox token");
};

