// real exported interface
////////////////////////////////////////////////////////////////////////////////

export class FakeFsDropbox extends FakeFs {
  kind: "dropbox";
  dropboxConfig: DropboxConfig;
  remoteBaseDir: string;
  saveUpdatedConfigFunc: () => Promise<void>;
  dropbox!: Dropbox;
  vaultFolderExists: boolean;
  foldersCreatedBefore: Set<string>;

  constructor(
    dropboxConfig: DropboxConfig,
    vaultName: string,
    saveUpdatedConfigFunc: () => Promise<void>
  ) {
    super();
    this.kind = "dropbox";
    this.dropboxConfig = dropboxConfig;
    this.remoteBaseDir = this.dropboxConfig.remoteBaseDir || vaultName || "";
    this.saveUpdatedConfigFunc = saveUpdatedConfigFunc;
    this.vaultFolderExists = false;
    this.foldersCreatedBefore = new Set();
  }

  async _init() {
    // check token
    if (
      this.dropboxConfig.accessToken === "" ||
      this.dropboxConfig.refreshToken === ""
    ) {
      throw Error("The user has not manually auth yet.");
    }
    const currentTs = Date.now();
    const customHeaders = {
      "Cache-Control": "no-cache",
    };
    if (this.dropboxConfig.accessTokenExpiresAtTime > currentTs) {
      this.dropbox = new Dropbox({
        accessToken: this.dropboxConfig.accessToken,
        customHeaders: customHeaders,
      });
    } else {
      if (this.dropboxConfig.refreshToken === "") {
        throw Error(
          "We need to automatically refresh token but none is stored."
        );
      }
      const resp = await sendRefreshTokenReq(
        this.dropboxConfig.clientID,
        this.dropboxConfig.refreshToken
      );

      setConfigBySuccessfullAuthInplace(
        this.dropboxConfig,
        resp,
        this.saveUpdatedConfigFunc
      );
      this.dropbox = new Dropbox({
        accessToken: this.dropboxConfig.accessToken,
        customHeaders: customHeaders,
      });
    }

    // check vault folder
    // console.debug(`checking remote has folder /${this.remoteBaseDir}`);
    if (this.vaultFolderExists) {
      // console.debug(`already checked, /${this.remoteBaseDir} exist before`)
    } else {
      const res = await this.dropbox.filesListFolder({
        path: "",
        recursive: false,
      });
      for (const item of res.result.entries) {
        if (item.path_display === `/${this.remoteBaseDir}`) {
          this.vaultFolderExists = true;
          break;
        }
      }
      if (!this.vaultFolderExists) {
        console.debug(`remote does not have folder /${this.remoteBaseDir}`);

        if (hasEmojiInText(`/${this.remoteBaseDir}`)) {
          throw new Error(
            `/${this.remoteBaseDir}: Error: Dropbox does not support emoji in folder names.`
          );
        }

        await this.dropbox.filesCreateFolderV2({
          path: `/${this.remoteBaseDir}`,
        });
        console.debug(`remote folder /${this.remoteBaseDir} created`);
        this.vaultFolderExists = true;
      } else {
        // console.debug(`remote folder /${this.remoteBaseDir} exists`);
      }
    }

    return this;
  }

  async listFoldersAtRoot(): Promise<string[]> {
    await this._init();
    const res = await this.dropbox.filesListFolder({
      path: "",
      recursive: false,
    });
    return res.result.entries
      .filter((x) => x[".tag"] === "folder")
      .map((x) => x.name)
      .sort((a, b) => a.localeCompare(b));
  }

  async createFolderAtRoot(name: string): Promise<void> {
    await this._init();
    await this.dropbox.filesCreateFolderV2({ path: `/${name}` });
  }

  async walk(): Promise<Entity[]> {
    return await this._walk(false);
  }

  async walkPartial(): Promise<Entity[]> {
    return await this._walk(true);
  }

  async _walk(partial: boolean): Promise<Entity[]> {
    await this._init();

    let res = await this.dropbox.filesListFolder({
      path: `/${this.remoteBaseDir}`,
      recursive: !partial,
      include_deleted: false,
      limit: partial ? 10 : 1000,
    });
    if (res.status !== 200) {
      throw Error(JSON.stringify(res));
    }
    // console.debug(res);

    const contents = res.result.entries;
    const unifiedContents = contents
      .filter((x) => x[".tag"] !== "deleted")
      .filter((x) => x.path_display !== `/${this.remoteBaseDir}`)
      .map((x) => fromDropboxItemToEntity(x, this.remoteBaseDir));

    if (!partial) {
      while (res.result.has_more) {
        res = await this.dropbox.filesListFolderContinue({
          cursor: res.result.cursor,
        });
        if (res.status !== 200) {
          throw Error(JSON.stringify(res));
        }

        const contents2 = res.result.entries;
        const unifiedContents2 = contents2
          .filter((x) => x[".tag"] !== "deleted")
          .filter((x) => x.path_display !== `/${this.remoteBaseDir}`)
          .map((x) => fromDropboxItemToEntity(x, this.remoteBaseDir));
        unifiedContents.push(...unifiedContents2);
      }
    }

    fixEntityListCasesInplace(unifiedContents);

    return unifiedContents;
  }

  async stat(key: string): Promise<Entity> {
    await this._init();
    return await this._statFromRoot(getDropboxPath(key, this.remoteBaseDir));
  }

  async _statFromRoot(key: string): Promise<Entity> {
    // if (key === "" || key === "/") {
    //   // filesGetMetadata doesn't support root folder
    //   // we instead try to list files
    //   // if no error occurs, we ensemble a fake result.
    //   const rsp = await retryReq(() =>
    //     client.dropbox.filesListFolder({
    //       path: `/${client.key}`,
    //       recursive: false, // don't need to recursive here
    //     })
    //   );
    //   if (rsp.status !== 200) {
    //     throw Error(JSON.stringify(rsp));
    //   }
    //   return {
    //     key: remotePath,
    //     lastModified: undefined,
    //     size: 0,
    //     remoteType: "dropbox",
    //     etag: undefined,
    //   } as Entity;
    // }

    const rsp = await retryReq(() =>
      this.dropbox.filesGetMetadata({
        path: key,
      })
    );
    if (rsp === undefined) {
      throw Error("dropbox.filesGetMetadata undefinded");
    }
    if (rsp.status !== 200) {
      throw Error(JSON.stringify(rsp));
    }
    return fromDropboxItemToEntity(rsp.result, this.remoteBaseDir);
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    if (!key.endsWith("/")) {
      throw Error(`you should not call mkdir on ${key}`);
    }
    await this._init();

    const uploadFile = getDropboxPath(key, this.remoteBaseDir);

    return await this._mkdirFromRoot(uploadFile, mtime, ctime);
  }

  async _mkdirFromRoot(
    key: string,
    mtime?: number,
    ctime?: number
  ): Promise<Entity> {
    if (hasEmojiInText(key)) {
      throw new Error(
        `${key}: Error: Dropbox does not support emoji in file / folder names.`
      );
    }
    if (this.foldersCreatedBefore?.has(key)) {
      // created, pass
    } else {
      try {
        await retryReq(
          () =>
            this.dropbox.filesCreateFolderV2({
              path: key,
            }),
          key // just a hint
        );
        this.foldersCreatedBefore?.add(key);
      } catch (e: unknown) {
        const err = e as DropboxResponseError<files.CreateFolderError>;
        if (err.status === undefined) {
          throw e instanceof Error ? e : new Error(String(e));
        }
        if (err.status === 409) {
          // pass
          this.foldersCreatedBefore?.add(key);
        } else {
          throw new Error(`Dropbox createFolder ${err.status}: ${JSON.stringify(err)}`);
        }
      }
    }
    return await this._statFromRoot(key);
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    if (key.endsWith("/")) {
      throw Error(`you should not call writeFile on ${key}`);
    }

    await this._init();
    const uploadFile = getDropboxPath(key, this.remoteBaseDir);

    return await this._writeFileFromRoot(
      uploadFile,
      content,
      mtime,
      ctime,
      key
    );
  }

  async _writeFileFromRoot(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number,
    origKey: string
  ): Promise<Entity> {
    if (hasEmojiInText(origKey)) {
      throw new Error(
        `${origKey}: Error: Dropbox does not support emoji in file / folder names.`
      );
    }

    const mtimeFixed = Math.floor(mtime / 1000.0) * 1000;
    const ctimeFixed = Math.floor(ctime / 1000.0) * 1000;
    const mtimeStr = new Date(mtimeFixed)
      .toISOString()
      .replace(/\.\d{3}Z$/, "Z");

    // in dropbox, we don't need to create folders before uploading! cool!
    // TODO: filesUploadSession for larger files (>=150 MB)

    await retryReq(
      () =>
        this.dropbox.filesUpload({
          path: key,
          contents: content,
          mode: {
            ".tag": "overwrite",
          },
          client_modified: mtimeStr,
        }),
      origKey // hint
    );

    // we want to mark that parent folders are created
    if (this.foldersCreatedBefore !== undefined) {
      const dirs = getFolderLevels(origKey).map((x) =>
        getDropboxPath(x, this.remoteBaseDir)
      );
      for (const dir of dirs) {
        this.foldersCreatedBefore?.add(dir);
      }
    }
    return await this._statFromRoot(key);
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    await this._init();
    if (key.endsWith("/")) {
      throw new Error(`you should not call readFile on folder ${key}`);
    }
    const downloadFile = getDropboxPath(key, this.remoteBaseDir);
    return await this._readFileFromRoot(downloadFile);
  }

  async _readFileFromRoot(key: string): Promise<ArrayBuffer> {
    const rsp = await retryReq(
      () =>
        this.dropbox.filesDownload({
          path: key,
        }),
      `downloadFromRemoteRaw=${key}`
    );
    if (rsp === undefined) {
      throw Error(`unknown rsp from dropbox download: ${rsp}`);
    }
    if ((rsp.result as any).fileBlob !== undefined) {
      // we get a Blob
      const content = (rsp.result as any).fileBlob as Blob;
      return await content.arrayBuffer();
    } else if ((rsp.result as any).fileBinary !== undefined) {
      // we get a Buffer
      const content = (rsp.result as any).fileBinary as Buffer;
      return bufferToArrayBuffer(content) as ArrayBuffer;
    } else {
      throw Error(`unknown rsp from dropbox download: ${rsp}`);
    }
  }

  async rename(key1: string, key2: string): Promise<void> {
    const remoteFileName1 = getDropboxPath(key1, this.remoteBaseDir);
    const remoteFileName2 = getDropboxPath(key2, this.remoteBaseDir);
    await this._init();
    try {
      await retryReq(
        () =>
          this.dropbox.filesMoveV2({
            from_path: remoteFileName1,
            to_path: remoteFileName2,
          }),
        `${key1}=>${key2}` // just a hint here
      );
    } catch (err) {
      console.error("some error while moving");
      console.error(err);
    }
  }

  supportsRename(): boolean { return true; }

  async rm(key: string): Promise<void> {
    if (key === "/") {
      return;
    }
    const remoteFileName = getDropboxPath(key, this.remoteBaseDir);

    await this._init();
    try {
      await retryReq(
        () =>
          this.dropbox.filesDeleteV2({
            path: remoteFileName,
          }),
        key // just a hint here
      );
    } catch (err) {
      console.error("some error while deleting");
      console.error(err);
    }
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    try {
      await this._init();
      const results = await this._statFromRoot(`/${this.remoteBaseDir}`);
      if (results === undefined) {
        throw Error(`cannot check root vault folder!`);
      }
    } catch (err) {
      console.debug(err);
      callbackFunc?.(err);
      return false;
    }

    return await this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName() {
    await this._init();
    const acct = await this.dropbox.usersGetCurrentAccount();
    return acct.result.name.display_name;
  }

  async revokeAuth(): Promise<void> {
    try {
      await this._init();
      await this.dropbox.authTokenRevoke();
    } catch (e) {
      console.warn("dropbox revokeAuth failed:", e);
    }
  }

  allowEmptyFile(): boolean {
    return true;
  }
}

/**
 * BYOC — Provider Factory
 * Resolves the active cloud provider from settings.
 * No imports from pro/ — all providers are local.
 */

import type { BYOCPluginSettings } from "./baseTypes";
import type { FakeFs } from "./fsAll";
import { FakeFsDropbox } from "./fsDropbox";
import { FakeFsOnedrive } from "./fsOnedrive";
import { FakeFsS3 } from "./fsS3";
import { FakeFsWebdav } from "./fsWebdav";
import { FakeFsWebdis } from "./fsWebdis";
import { FakeFsGoogleDrive } from "./fsGoogleDrive";
import { FakeFsPCloud } from "./fsPCloud";
import { FakeFsBox } from "./fsBox";
import { FakeFsYandexDisk } from "./fsYandexDisk";
import { FakeFsKoofr } from "./fsKoofr";
import { FakeFsAzureBlobStorage } from "./fsAzureBlobStorage";
import { FakeFsOnedriveFull } from "./fsOnedriveFull";

/**
 * Returns the appropriate FakeFs implementation for the configured provider.
 * To avoid circular dependency, this lives in a dedicated file.
 */
export function getClient(
  settings: BYOCPluginSettings,
  vaultName: string,
  saveUpdatedConfigFunc: () => Promise<void>
): FakeFs {
  switch (settings.serviceType) {
    case "s3":
      return new FakeFsS3(settings.s3);
    case "webdav":
      return new FakeFsWebdav(
        settings.webdav,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "dropbox":
      return new FakeFsDropbox(
        settings.dropbox,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "onedrive":
      return new FakeFsOnedrive(
        settings.onedrive,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "onedrivefull":
      return new FakeFsOnedriveFull(
        settings.onedrivefull,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "webdis":
      return new FakeFsWebdis(
        settings.webdis,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "googledrive":
      return new FakeFsGoogleDrive(
        settings.googledrive,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "box":
      return new FakeFsBox(settings.box, vaultName, saveUpdatedConfigFunc);
    case "pcloud":
      return new FakeFsPCloud(
        settings.pcloud,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "yandexdisk":
      return new FakeFsYandexDisk(
        settings.yandexdisk,
        vaultName,
        saveUpdatedConfigFunc
      );
    case "koofr":
      return new FakeFsKoofr(settings.koofr, vaultName, saveUpdatedConfigFunc);
    case "azureblobstorage":
      return new FakeFsAzureBlobStorage(settings.azureblobstorage, vaultName);
    default:
      throw new Error(
        `[BYOC] Cannot init client for unknown serviceType: ${(settings as any).serviceType}`
      );
  }
}

/**
 * BYOC — Google Drive Filesystem Adapter
 * Clean-room implementation using Google Drive API v3.
 *
 * Google does NOT support custom URI schemes (obsidian://) as redirect URIs.
 * This adapter uses a manual code-paste flow:
 *   1. User visits the auth URL in their browser
 *   2. Google redirects to localhost (or shows a code page)
 *   3. User copies the authorization code
 *   4. User pastes the code into BYOC settings
 *   5. BYOC exchanges the code for tokens
 *
 * The scope is drive.file — only files created by this app are accessible.
 */

import { request, requestUrl } from "obsidian";
import {
  GOOGLEDRIVE_CLIENT_ID,
  GOOGLEDRIVE_CLIENT_SECRET,
  type Entity,
  type GoogleDriveConfig,
} from "./baseTypes";
import { FakeFs } from "./fsAll";
import { retryFetch } from "./misc";

const DRIVE_API = "https://www.googleapis.com/drive/v3";
const DRIVE_UPLOAD_API = "https://www.googleapis.com/upload/drive/v3";
const GOOGLE_AUTH_URL = "https://accounts.google.com/o/oauth2/v2/auth";
const GOOGLE_TOKEN_URL = "https://oauth2.googleapis.com/token";
const SCOPES = "https://www.googleapis.com/auth/drive.file";
// Bridge page catches Google's redirect and bounces the auth code into
// Obsidian's protocol handler (obsidian://bring-your-own-cloud-cb-googledrive).
const REDIRECT_URI = "https://bringyourowncloud.xyz/auth/googledrive/callback";

export const DEFAULT_GOOGLEDRIVE_CONFIG: GoogleDriveConfig = {
  accessToken: "",
  accessTokenExpiresInMs: 0,
  accessTokenExpiresAtTimeMs: 0,
  refreshToken: "",
  remoteBaseDir: "",
  credentialsShouldBeDeletedAtTimeMs: 0,
  scope: SCOPES,
  kind: "googledrive",
};

////////////////////////////////////////////////////////////////////////////////
// OAuth2 Helpers
////////////////////////////////////////////////////////////////////////////////

export function generateAuthUrl(): string {
  const params = new URLSearchParams({
    response_type: "code",
    client_id: GOOGLEDRIVE_CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    scope: SCOPES,
    access_type: "offline",
    prompt: "consent",
  });
  return `${GOOGLE_AUTH_URL}?${params.toString()}`;
}

export async function sendAuthReq(
  code: string,
  errorCallBack: (e: unknown) => Promise<void>
): Promise<any> {
  try {
    const rsp = await request({
      url: GOOGLE_TOKEN_URL,
      method: "POST",
      contentType: "application/x-www-form-urlencoded",
      body: new URLSearchParams({
        grant_type: "authorization_code",
        code: code,
        client_id: GOOGLEDRIVE_CLIENT_ID,
        client_secret: GOOGLEDRIVE_CLIENT_SECRET,
        redirect_uri: REDIRECT_URI,
      }).toString(),
    });
    return JSON.parse(rsp);
  } catch (e) {
    console.error(e);
    await errorCallBack(e);
  }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any -- external OAuth response shape
async function refreshAccessToken(refreshToken: string): Promise<any> {
  const rsp = await request({
    url: GOOGLE_TOKEN_URL,
    method: "POST",
    contentType: "application/x-www-form-urlencoded",
    body: new URLSearchParams({
      grant_type: "refresh_token",
      refresh_token: refreshToken,
      client_id: GOOGLEDRIVE_CLIENT_ID,
      client_secret: GOOGLEDRIVE_CLIENT_SECRET,
    }).toString(),
  });
  return JSON.parse(rsp);
}

export async function setConfigBySuccessfullAuthInplace(
  config: GoogleDriveConfig,
  authRes: Record<string, unknown>,
  saveFunc: () => Promise<void>
): Promise<void> {
  const r = authRes as unknown as { access_token: string; refresh_token?: string; expires_in?: number };
  config.accessToken = r.access_token;
  config.refreshToken = r.refresh_token || config.refreshToken;
  config.accessTokenExpiresInMs = (r.expires_in ?? 3600) * 1000;
  config.accessTokenExpiresAtTimeMs =
    Date.now() + (r.expires_in ?? 3600) * 1000 - 300_000;
  config.credentialsShouldBeDeletedAtTimeMs = 0;
  await saveFunc();
}

////////////////////////////////////////////////////////////////////////////////
// Google Drive Specifics
////////////////////////////////////////////////////////////////////////////////

/**
 * Google Drive allows multiple files with the same name in the same folder.
 * We must use file IDs for all operations and search by name + parent.
 */

interface GDriveFile {
  id: string;
  name: string;
  mimeType: string;
  size?: string;
  modifiedTime?: string;
  createdTime?: string;
  parents?: string[];
  trashed?: boolean;
}

const FOLDER_MIME = "application/vnd.google-apps.folder";

////////////////////////////////////////////////////////////////////////////////
// The Client
////////////////////////////////////////////////////////////////////////////////

export class FakeFsGoogleDrive extends FakeFs {
  kind = "googledrive";
  private config: GoogleDriveConfig;
  private vaultName: string;
  private saveFunc: () => Promise<void>;
  private remoteBaseDir: string;
  private baseFolderId: string | null = null;
  // Cache folder name -> id mappings
  private folderCache: Map<string, string> = new Map();

  constructor(
    config: GoogleDriveConfig,
    vaultName: string,
    saveFunc: () => Promise<void>
  ) {
    super();
    this.config = config;
    this.vaultName = vaultName;
    this.saveFunc = saveFunc;
    this.remoteBaseDir = config.remoteBaseDir || vaultName || "";
  }

  private async ensureToken(): Promise<string> {
    if (!this.config.accessToken) {
      throw Error("[BYOC] Google Drive: not authorized.");
    }

    if (
      this.config.refreshToken &&
      this.config.accessTokenExpiresAtTimeMs > 0 &&
      this.config.accessTokenExpiresAtTimeMs < Date.now()
    ) {
      const res = await refreshAccessToken(this.config.refreshToken);
      if (res.error) {
        throw Error(`[BYOC] Google Drive refresh error: ${res.error_description}`);
      }
      this.config.accessToken = res.access_token;
      if (res.refresh_token) this.config.refreshToken = res.refresh_token;
      this.config.accessTokenExpiresAtTimeMs =
        Date.now() + (res.expires_in ?? 3600) * 1000 - 300_000;
      await this.saveFunc();
    }

    return this.config.accessToken;
  }




  private async _getJson(url: string): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${DRIVE_API}${url}`;
    return JSON.parse(
      await request({
        url: fullUrl,
        method: "GET",
        headers: { Authorization: `Bearer ${token}` },
      })
    );
  }




  private async _postJson(url: string, body: any): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${DRIVE_API}${url}`;
    return JSON.parse(
      await request({
        url: fullUrl,
        method: "POST",
        contentType: "application/json",
        body: JSON.stringify(body),
        headers: { Authorization: `Bearer ${token}` },
      })
    );
  }




  private async _patchJson(url: string, body: any): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${DRIVE_API}${url}`;
    return JSON.parse(
      await request({
        url: fullUrl,
        method: "PATCH",
        contentType: "application/json",
        body: JSON.stringify(body),
        headers: { Authorization: `Bearer ${token}` },
      })
    );
  }

  private async _delete(url: string): Promise<void> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${DRIVE_API}${url}`;
    await retryFetch(fullUrl, {
      method: "DELETE",
      headers: { Authorization: `Bearer ${token}` },
    });
  }

  /**
   * Find or create a folder by name under a parent.
   */
  private async findOrCreateFolder(
    name: string,
    parentId: string
  ): Promise<string> {
    const cacheKey = `${parentId}/${name}`;
    if (this.folderCache.has(cacheKey)) {
      return this.folderCache.get(cacheKey)!;
    }

    // Search for existing
    const q = `name='${name.replace(/'/g, "\\'")}' and '${parentId}' in parents and mimeType='${FOLDER_MIME}' and trashed=false`;
    const res = await this._getJson(
      `/files?q=${encodeURIComponent(q)}&fields=files(id,name)&pageSize=1`
    );

    if (res.files && res.files.length > 0) {
      const id = res.files[0].id;
      this.folderCache.set(cacheKey, id);
      return id;
    }

    // Create
    const created = await this._postJson("/files", {
      name: name,
      mimeType: FOLDER_MIME,
      parents: [parentId],
    });
    this.folderCache.set(cacheKey, created.id);
    return created.id;
  }

  /**
   * Get or create the base vault folder in Drive root.
   */
  private async getBaseFolderId(): Promise<string> {
    if (this.baseFolderId) return this.baseFolderId;

    // Walk through the path segments
    const segments = this.remoteBaseDir.split("/").filter(Boolean);
    let parentId = "root";
    for (const seg of segments) {
      parentId = await this.findOrCreateFolder(seg, parentId);
    }

    this.baseFolderId = parentId;
    return parentId;
  }

  /**
   * Resolve a key like "subfolder/file.md" to a folder ID for its parent
   * and return both parent ID and filename.
   */
  private async resolveParent(
    key: string
  ): Promise<{ parentId: string; name: string }> {
    const baseFolderId = await this.getBaseFolderId();
    const parts = key.replace(/\/+$/, "").split("/").filter(Boolean);

    if (parts.length === 0) {
      return { parentId: baseFolderId, name: "" };
    }

    const name = parts.pop()!;
    let parentId = baseFolderId;

    for (const seg of parts) {
      parentId = await this.findOrCreateFolder(seg, parentId);
    }

    return { parentId, name };
  }

  /**
   * Find a file by name in a folder.
   */
  private async findFile(
    name: string,
    parentId: string,
    mimeType?: string
  ): Promise<GDriveFile | null> {
    let q = `name='${name.replace(/'/g, "\\'")}' and '${parentId}' in parents and trashed=false`;
    if (mimeType) q += ` and mimeType='${mimeType}'`;

    const res = await this._getJson(
      `/files?q=${encodeURIComponent(q)}&fields=files(id,name,mimeType,size,modifiedTime,createdTime,parents)&pageSize=1`
    );

    return res.files && res.files.length > 0 ? res.files[0] : null;
  }

  /**
   * Recursively list all files under a folder.
   */
  private async listRecursive(
    folderId: string,
    pathPrefix: string,
    entities: Entity[]
  ): Promise<void> {
    let pageToken = "";

    do {
      let url = `/files?q='${folderId}'+in+parents+and+trashed%3Dfalse&fields=nextPageToken,files(id,name,mimeType,size,modifiedTime,createdTime)&pageSize=1000`;
      if (pageToken) url += `&pageToken=${pageToken}`;

      const res = await this._getJson(url);
      const files: GDriveFile[] = res.files || [];

      for (const f of files) {
        const isFolder = f.mimeType === FOLDER_MIME;
        const key = isFolder
          ? `${pathPrefix}${f.name}/`
          : `${pathPrefix}${f.name}`;

        const mtime = f.modifiedTime
          ? new Date(f.modifiedTime).getTime()
          : 0;
        const ctime = f.createdTime
          ? new Date(f.createdTime).getTime()
          : mtime;
        const size = f.size ? parseInt(f.size, 10) : 0;

        entities.push({
          key, keyRaw: key,
          mtimeSvr: mtime, mtimeCli: mtime, ctimeCli: ctime,
          size: isFolder ? 0 : size,
          sizeRaw: isFolder ? 0 : size,
        });

        if (isFolder) {
          await this.listRecursive(f.id, `${pathPrefix}${f.name}/`, entities);
        }
      }

      pageToken = res.nextPageToken || "";
    } while (pageToken);
  }

  async listFoldersAtRoot(): Promise<string[]> {
    const q = `'root' in parents and mimeType='${FOLDER_MIME}' and trashed=false`;
    const res = await this._getJson(
      `/files?q=${encodeURIComponent(q)}&fields=files(id,name)&pageSize=1000`
    );
    return (res.files || [])
      .map((f: GDriveFile) => f.name)
      .sort((a: string, b: string) => a.localeCompare(b));
  }

  async createFolderAtRoot(name: string): Promise<void> {
    await this._postJson("/files", {
      name,
      mimeType: FOLDER_MIME,
      parents: ["root"],
    });
  }

  async walk(): Promise<Entity[]> {
    const baseFolderId = await this.getBaseFolderId();
    const entities: Entity[] = [];
    await this.listRecursive(baseFolderId, "", entities);
    return entities;
  }

  async walkPartial(): Promise<Entity[]> {
    return this.walk();
  }

  async stat(key: string): Promise<Entity> {
    const isFolder = key.endsWith("/");
    const { parentId, name } = await this.resolveParent(key);

    if (!name) {
      // Stat on root
      return { key, keyRaw: key, size: 0, sizeRaw: 0 };
    }

    const file = await this.findFile(
      name,
      parentId,
      isFolder ? FOLDER_MIME : undefined
    );

    if (!file) {
      throw Error(`[BYOC] Google Drive: '${key}' not found`);
    }

    const mtime = file.modifiedTime
      ? new Date(file.modifiedTime).getTime()
      : 0;
    const ctime = file.createdTime
      ? new Date(file.createdTime).getTime()
      : mtime;
    const size = file.size ? parseInt(file.size, 10) : 0;

    return {
      key, keyRaw: key,
      mtimeSvr: mtime, mtimeCli: mtime, ctimeCli: ctime,
      size: isFolder ? 0 : size,
      sizeRaw: isFolder ? 0 : size,
    };
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    const { parentId, name } = await this.resolveParent(key);
    if (name) {
      await this.findOrCreateFolder(name, parentId);
    }
    return { key, keyRaw: key, size: 0, sizeRaw: 0 };
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    const { parentId, name } = await this.resolveParent(key);
    const token = await this.ensureToken();

    // Check if file already exists
    const existing = await this.findFile(name, parentId);

    const metadata: any = {
      modifiedTime: new Date(mtime).toISOString(),
    };

    if (existing) {
      // Update existing file
      const resp = await retryFetch(
        `${DRIVE_UPLOAD_API}/files/${existing.id}?uploadType=multipart&fields=id,name,size,modifiedTime`,
        {
          method: "PATCH",
          headers: { Authorization: `Bearer ${token}` },
          body: createMultipartBody(metadata, content, name),
        }
      );
      if (!resp.ok) {
        throw Error(
          `[BYOC] Google Drive: update failed for '${key}': ${resp.status}`
        );
      }
    } else {
      // Create new file
      metadata.name = name;
      metadata.parents = [parentId];

      const resp = await retryFetch(
        `${DRIVE_UPLOAD_API}/files?uploadType=multipart&fields=id,name,size,modifiedTime`,
        {
          method: "POST",
          headers: { Authorization: `Bearer ${token}` },
          body: createMultipartBody(metadata, content, name),
        }
      );
      if (!resp.ok) {
        throw Error(
          `[BYOC] Google Drive: create failed for '${key}': ${resp.status}`
        );
      }
    }

    return {
      key, keyRaw: key,
      mtimeCli: mtime, ctimeCli: ctime,
      size: content.byteLength,
      sizeRaw: content.byteLength,
    };
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    const { parentId, name } = await this.resolveParent(key);
    const file = await this.findFile(name, parentId);

    if (!file) {
      throw Error(`[BYOC] Google Drive: '${key}' not found for read`);
    }

    const token = await this.ensureToken();
    const resp = await retryFetch(
      `${DRIVE_API}/files/${file.id}?alt=media`,
      {
        headers: { Authorization: `Bearer ${token}` },
      }
    );

    if (!resp.ok) {
      throw Error(
        `[BYOC] Google Drive: download failed for '${key}': ${resp.status}`
      );
    }

    return resp.arrayBuffer();
  }

  async rename(key1: string, key2: string): Promise<void> {
    // Google Drive rename = move + rename in one PATCH call
    const { parentId: parent1, name: name1 } = await this.resolveParent(key1);
    const { parentId: parent2, name: name2 } = await this.resolveParent(key2);

    const isFolder = key1.endsWith("/");
    const file = await this.findFile(
      name1,
      parent1,
      isFolder ? FOLDER_MIME : undefined
    );

    if (!file) {
      throw Error(`[BYOC] Google Drive: '${key1}' not found for rename`);
    }

    await this._patchJson(
      `/files/${file.id}?addParents=${parent2}&removeParents=${parent1}`,
      { name: name2 }
    );
  }

  async rm(key: string): Promise<void> {
    const isFolder = key.endsWith("/");
    const { parentId, name } = await this.resolveParent(key);

    const file = await this.findFile(
      name,
      parentId,
      isFolder ? FOLDER_MIME : undefined
    );

    if (!file) return; // Already gone

    // Permanently delete (not trash)
    await this._delete(`/files/${file.id}`);
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    return this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    try {
      const res = await this._getJson("/about?fields=user");
      return res.user?.displayName || res.user?.emailAddress || "Google Drive User";
    } catch {
      return "Google Drive (not configured)";
    }
  }

  async revokeAuth(): Promise<void> {
    // Optionally revoke the token at Google
    if (this.config.accessToken) {
      try {
        await requestUrl({
          url: `https://oauth2.googleapis.com/revoke?token=${this.config.accessToken}`,
          method: "POST",
          throw: false,
        });
      } catch {
        // Best effort
      }
    }
    this.config.accessToken = "";
    this.config.refreshToken = "";
    await this.saveFunc();
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return true;
  }
}

////////////////////////////////////////////////////////////////////////////////
// Multipart Upload Helper
////////////////////////////////////////////////////////////////////////////////

/**
 * Create a multipart/related body for Google Drive API uploads.
 * This combines JSON metadata and file content in one request.
 */
function createMultipartBody(
  metadata: any,
  content: ArrayBuffer,
  filename: string
): Blob {
  const boundary = "byoc_boundary_" + Date.now();
  const delimiter = `\r\n--${boundary}\r\n`;
  const closeDelimiter = `\r\n--${boundary}--`;

  const metadataStr =
    delimiter +
    'Content-Type: application/json; charset=UTF-8\r\n\r\n' +
    JSON.stringify(metadata) +
    delimiter +
    'Content-Type: application/octet-stream\r\n\r\n';

  const metadataBlob = new Blob([metadataStr]);
  const contentBlob = new Blob([content]);
  const closeBlob = new Blob([closeDelimiter]);

  return new Blob([metadataBlob, contentBlob, closeBlob], {
    type: `multipart/related; boundary=${boundary}`,
  });
}

/**
 * BYOC — Koofr Filesystem Adapter
 * Clean-room implementation using Koofr REST API v2.
 * OAuth2 authorization code flow with silent token refresh.
 */

import { request } from "obsidian";
import {
  COMMAND_CALLBACK_KOOFR,
  KOOFR_CLIENT_ID,
  KOOFR_CLIENT_SECRET,
  type Entity,
  type KoofrConfig,
} from "./baseTypes";
import { FakeFs } from "./fsAll";
import { retryFetch } from "./misc";

const KOOFR_AUTH_URL = "https://app.koofr.net/oauth2/auth";
const KOOFR_TOKEN_URL = "https://app.koofr.net/oauth2/token";
const REDIRECT_URI = `obsidian://${COMMAND_CALLBACK_KOOFR}`;

export const DEFAULT_KOOFR_CONFIG: KoofrConfig = {
  accessToken: "",
  accessTokenExpiresInMs: 0,
  accessTokenExpiresAtTimeMs: 0,
  refreshToken: "",
  remoteBaseDir: "",
  credentialsShouldBeDeletedAtTimeMs: 0,
  scope: "",
  api: "https://app.koofr.net",
  mountID: "",
  kind: "koofr",
};

////////////////////////////////////////////////////////////////////////////////
// OAuth2 Helpers
////////////////////////////////////////////////////////////////////////////////

export function generateAuthUrl(): string {
  const params = new URLSearchParams({
    response_type: "code",
    client_id: KOOFR_CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    scope: "",
  });
  return `${KOOFR_AUTH_URL}?${params.toString()}`;
}

export async function sendAuthReq(
  code: string,
  errorCallBack: (e: unknown) => Promise<void>
): Promise<any> {
  try {
    const rsp = await request({
      url: KOOFR_TOKEN_URL,
      method: "POST",
      contentType: "application/x-www-form-urlencoded",
      body: new URLSearchParams({
        grant_type: "authorization_code",
        code: code,
        client_id: KOOFR_CLIENT_ID,
        client_secret: KOOFR_CLIENT_SECRET,
        redirect_uri: REDIRECT_URI,
      }).toString(),
    });
    return JSON.parse(rsp);
  } catch (e) {
    console.error(e);
    await errorCallBack(e);
  }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any -- external OAuth response shape
async function refreshAccessToken(refreshToken: string): Promise<any> {
  const rsp = await request({
    url: KOOFR_TOKEN_URL,
    method: "POST",
    contentType: "application/x-www-form-urlencoded",
    body: new URLSearchParams({
      grant_type: "refresh_token",
      refresh_token: refreshToken,
      client_id: KOOFR_CLIENT_ID,
      client_secret: KOOFR_CLIENT_SECRET,
    }).toString(),
  });
  return JSON.parse(rsp);
}

export async function setConfigBySuccessfullAuthInplace(
  config: KoofrConfig,
  authRes: Record<string, unknown>,
  saveFunc: () => Promise<void>
): Promise<void> {
  const r = authRes as unknown as { access_token: string; refresh_token?: string; expires_in?: number };
  config.accessToken = r.access_token;
  config.refreshToken = r.refresh_token || config.refreshToken;
  config.accessTokenExpiresInMs = (r.expires_in ?? 3600) * 1000;
  config.accessTokenExpiresAtTimeMs =
    Date.now() + (r.expires_in ?? 3600) * 1000 - 300_000;
  config.credentialsShouldBeDeletedAtTimeMs = 0;
  await saveFunc();
}

////////////////////////////////////////////////////////////////////////////////
// Path Helpers
////////////////////////////////////////////////////////////////////////////////

function getRemotePath(key: string, remoteBaseDir: string): string {
  if (!key || key === "/") return `/${remoteBaseDir}`;
  const clean = key.endsWith("/") ? key.slice(0, -1) : key;
  return `/${remoteBaseDir}/${clean}`;
}

////////////////////////////////////////////////////////////////////////////////
// The Client
////////////////////////////////////////////////////////////////////////////////

export class FakeFsKoofr extends FakeFs {
  kind = "koofr";
  private config: KoofrConfig;
  private vaultName: string;
  private saveFunc: () => Promise<void>;
  private remoteBaseDir: string;
  private apiBase: string;

  constructor(
    config: KoofrConfig,
    vaultName: string,
    saveFunc: () => Promise<void>
  ) {
    super();
    this.config = config;
    this.vaultName = vaultName;
    this.saveFunc = saveFunc;
    this.remoteBaseDir = config.remoteBaseDir || vaultName || "";
    this.apiBase = config.api || "https://app.koofr.net";
  }

  private async ensureToken(): Promise<string> {
    if (!this.config.accessToken) {
      throw Error("[BYOC] Koofr: not authorized.");
    }

    if (
      this.config.refreshToken &&
      this.config.accessTokenExpiresAtTimeMs > 0 &&
      this.config.accessTokenExpiresAtTimeMs < Date.now()
    ) {
      const res = await refreshAccessToken(this.config.refreshToken);
      if (res.error) {
        throw Error(`[BYOC] Koofr refresh error: ${res.error_description}`);
      }
      this.config.accessToken = res.access_token;
      if (res.refresh_token) this.config.refreshToken = res.refresh_token;
      this.config.accessTokenExpiresAtTimeMs =
        Date.now() + (res.expires_in ?? 3600) * 1000 - 300_000;
      await this.saveFunc();
    }

    return this.config.accessToken;
  }

  private async ensureMountID(): Promise<string> {
    if (this.config.mountID) return this.config.mountID;

    // Get the primary mount (default storage)
    const mounts = await this._getJson("/api/v2/mounts");
    if (mounts && mounts.mounts && mounts.mounts.length > 0) {
      // Find the primary mount
      const primary =
        mounts.mounts.find((m: any) => m.isPrimary) || mounts.mounts[0];
      this.config.mountID = primary.id;
      await this.saveFunc();
      return this.config.mountID;
    }
    throw Error("[BYOC] Koofr: no mounts found");
  }




  private async _getJson(path: string): Promise<any> {
    const token = await this.ensureToken();
    const url = path.startsWith("http") ? path : `${this.apiBase}${path}`;
    return JSON.parse(
      await request({
        url,
        method: "GET",
        headers: {
          Authorization: `Bearer ${token}`,
          Accept: "application/json",
        },
      })
    );
  }




  private async _postJson(path: string, body?: any): Promise<any> {
    const token = await this.ensureToken();
    const url = path.startsWith("http") ? path : `${this.apiBase}${path}`;
    const opts: any = {
      url,
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/json",
      },
    };
    if (body) {
      opts.contentType = "application/json";
      opts.body = JSON.stringify(body);
    }
    const rsp = await request(opts);
    return rsp ? JSON.parse(rsp) : {};
  }

  private async _delete(path: string): Promise<void> {
    const token = await this.ensureToken();
    const url = path.startsWith("http") ? path : `${this.apiBase}${path}`;
    await retryFetch(url, {
      method: "DELETE",
      headers: { Authorization: `Bearer ${token}` },
    });
  }

  private async ensureBaseDir(): Promise<void> {
    const mountID = await this.ensureMountID();
    const remotePath = `/${this.remoteBaseDir}`;

    try {
      await this._getJson(
        `/api/v2/mounts/${mountID}/files/info?path=${encodeURIComponent(remotePath)}`
      );
    } catch {
      // Create the base directory
      await this._postJson(
        `/api/v2/mounts/${mountID}/files/folder?path=${encodeURIComponent("/")}`,
        { name: this.remoteBaseDir }
      );
    }
  }

  /**
   * Recursively list all files in the Koofr mount under remoteBaseDir.
   */
  private async listRecursive(
    mountID: string,
    remotePath: string,
    entities: Entity[]
  ): Promise<void> {
    const res = await this._getJson(
      `/api/v2/mounts/${mountID}/files/list?path=${encodeURIComponent(remotePath)}`
    );
    const files = res.files || [];

    for (const item of files) {
      const itemPath = `${remotePath === "/" ? "" : remotePath}/${item.name}`;
      const basePrefix = `/${this.remoteBaseDir}/`;
      let key = "";

      if (itemPath.startsWith(basePrefix)) {
        key = itemPath.slice(basePrefix.length);
      } else if (itemPath === `/${this.remoteBaseDir}`) {
        continue;
      } else {
        key = item.name;
      }

      const isFolder = item.type === "dir";
      if (isFolder) {
        if (!key.endsWith("/")) key = `${key}/`;
        entities.push({
          key, keyRaw: key,
          mtimeSvr: item.modified ?? 0,
          size: 0, sizeRaw: 0,
        });
        // Recurse
        await this.listRecursive(mountID, itemPath, entities);
      } else {
        entities.push({
          key, keyRaw: key,
          mtimeSvr: item.modified ?? 0,
          mtimeCli: item.modified ?? 0,
          size: item.size ?? 0,
          sizeRaw: item.size ?? 0,
          hash: item.hash,
        });
      }
    }
  }

  async listFoldersAtRoot(): Promise<string[]> {
    const mountID = await this.ensureMountID();
    const res = await this._getJson(
      `/api/v2/mounts/${mountID}/files/list?path=${encodeURIComponent("/")}`
    );
    return (res.files || [])
      .filter((item: any) => item.type === "dir")
      .map((item: any) => item.name as string)
      .sort((a: string, b: string) => a.localeCompare(b));
  }

  async createFolderAtRoot(name: string): Promise<void> {
    const mountID = await this.ensureMountID();
    await this._postJson(
      `/api/v2/mounts/${mountID}/files/folder?path=${encodeURIComponent("/")}`,
      { name }
    );
  }

  async walk(): Promise<Entity[]> {
    await this.ensureBaseDir();
    const mountID = await this.ensureMountID();
    const entities: Entity[] = [];
    await this.listRecursive(mountID, `/${this.remoteBaseDir}`, entities);
    return entities;
  }

  async walkPartial(): Promise<Entity[]> {
    return this.walk();
  }

  async stat(key: string): Promise<Entity> {
    const mountID = await this.ensureMountID();
    const remotePath = getRemotePath(key, this.remoteBaseDir);
    const res = await this._getJson(
      `/api/v2/mounts/${mountID}/files/info?path=${encodeURIComponent(remotePath)}`
    );

    const isFolder = res.type === "dir";
    return {
      key, keyRaw: key,
      mtimeSvr: res.modified ?? 0,
      mtimeCli: res.modified ?? 0,
      size: isFolder ? 0 : (res.size ?? 0),
      sizeRaw: isFolder ? 0 : (res.size ?? 0),
      hash: res.hash,
    };
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    const mountID = await this.ensureMountID();
    const folderName = key.replace(/\/+$/, "").split("/").pop()!;
    const parentKey = key.replace(/\/+$/, "");
    const parentPath = parentKey.includes("/")
      ? `/${this.remoteBaseDir}/${parentKey.slice(0, parentKey.lastIndexOf("/"))}`
      : `/${this.remoteBaseDir}`;

    try {
      await this._postJson(
        `/api/v2/mounts/${mountID}/files/folder?path=${encodeURIComponent(parentPath)}`,
        { name: folderName }
      );
    } catch (e: unknown) {
      // Already exists is fine
      if (!String(e).includes("409") && !String(e).includes("AlreadyExists")) {
        throw e;
      }
    }

    return { key, keyRaw: key, size: 0, sizeRaw: 0 };
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    const mountID = await this.ensureMountID();
    const remotePath = getRemotePath(key, this.remoteBaseDir);
    const fileName = key.split("/").pop()!;
    const parentPath = remotePath.slice(0, remotePath.lastIndexOf("/")) || "/";

    const token = await this.ensureToken();

    // Koofr file upload uses multipart form with PUT
    const formData = new FormData();
    formData.append("file", new Blob([content]), fileName);

    const resp = await retryFetch(
      `${this.apiBase}/api/v2/mounts/${mountID}/files/put?path=${encodeURIComponent(parentPath)}&filename=${encodeURIComponent(fileName)}&autorename=false&overwrite=true`,
      {
        method: "POST",
        headers: { Authorization: `Bearer ${token}` },
        body: formData,
      }
    );

    if (!resp.ok) {
      throw Error(`[BYOC] Koofr: upload failed for '${key}': ${resp.status}`);
    }

    return {
      key, keyRaw: key,
      mtimeCli: mtime, ctimeCli: ctime,
      size: content.byteLength,
      sizeRaw: content.byteLength,
    };
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    const mountID = await this.ensureMountID();
    const remotePath = getRemotePath(key, this.remoteBaseDir);
    const token = await this.ensureToken();

    const resp = await retryFetch(
      `${this.apiBase}/api/v2/mounts/${mountID}/files/get?path=${encodeURIComponent(remotePath)}`,
      {
        headers: { Authorization: `Bearer ${token}` },
      }
    );

    if (!resp.ok) {
      throw Error(`[BYOC] Koofr: download failed for '${key}': ${resp.status}`);
    }
    return resp.arrayBuffer();
  }

  async rename(key1: string, key2: string): Promise<void> {
    const mountID = await this.ensureMountID();
    const from = getRemotePath(key1, this.remoteBaseDir);
    const to = getRemotePath(key2, this.remoteBaseDir);
    const toName = key2.split("/").pop()!;
    const toParent = to.slice(0, to.lastIndexOf("/")) || "/";

    await this._postJson(
      `/api/v2/mounts/${mountID}/files/move?path=${encodeURIComponent(from)}`,
      {
        toMountId: mountID,
        toPath: toParent,
        toName: toName,
      }
    );
  }

  async rm(key: string): Promise<void> {
    const mountID = await this.ensureMountID();
    const remotePath = getRemotePath(key, this.remoteBaseDir);

    try {
      await this._delete(
        `${this.apiBase}/api/v2/mounts/${mountID}/files/remove?path=${encodeURIComponent(remotePath)}`
      );
    } catch (e: unknown) {
      // 404 = already gone
      if (!String(e).includes("404") && !String(e).includes("NotFound")) throw e;
    }
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    return this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    const res = await this._getJson("/api/v2/user");
    return `${res.firstName ?? ""} ${res.lastName ?? ""}`.trim() || "Koofr User";
  }

  async revokeAuth(): Promise<void> {
    this.config.accessToken = "";
    this.config.refreshToken = "";
    this.config.mountID = "";
    await this.saveFunc();
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return true;
  }
}

import { DEFAULT_DEBUG_FOLDER, type Entity } from "./baseTypes";
import { FakeFs } from "./fsAll";

import { TFile, TFolder, type Vault } from "obsidian";
import { mkdirpInVault, statFix, unixTimeToStr } from "./misc";
import { listFilesInObsFolder } from "./obsFolderLister";
import type { Profiler } from "./profiler";

export class FakeFsLocal extends FakeFs {
  vault: Vault;
  syncConfigDir: boolean;
  syncBookmarks: boolean;
  configDir: string;
  pluginID: string;
  profiler: Profiler | undefined;
  deleteToWhere: "obsidian" | "system";
  kind: "local";
  constructor(
    vault: Vault,
    syncConfigDir: boolean,
    syncBookmarks: boolean,
    configDir: string,
    pluginID: string,
    profiler: Profiler | undefined,
    deleteToWhere: "obsidian" | "system"
  ) {
    super();

    this.vault = vault;
    this.syncConfigDir = syncConfigDir;
    this.syncBookmarks = syncBookmarks;
    this.configDir = configDir;
    this.pluginID = pluginID;
    this.profiler = profiler;
    this.deleteToWhere = deleteToWhere;
    this.kind = "local";
  }

  async walk(): Promise<Entity[]> {
    this.profiler?.addIndent();
    this.profiler?.insert("enter walk for local");
    const local: Entity[] = [];

    const localTAbstractFiles = this.vault.getAllLoadedFiles();
    this.profiler?.insert("finish getting walk for local");
    for (const entry of localTAbstractFiles) {
      let r: Entity | undefined = undefined;
      let key = entry.path;
      if (key.startsWith("/")) {
        // why?
        // just remove leading slash /
        key = key.slice(1);
      }

      if (entry.path === "/" || entry.path === "") {
        // ignore
        continue;
      } else if (entry instanceof TFile) {
        let mtimeLocal: number | undefined = entry.stat.mtime;
        if (mtimeLocal <= 0) {
          mtimeLocal = entry.stat.ctime;
        }
        if (mtimeLocal === 0) {
          mtimeLocal = undefined;
        }
        if (mtimeLocal === undefined) {
          throw Error(
            `Your file has last modified time 0: ${key}, don't know how to deal with it`
          );
        }
        r = {
          key: key, // local always unencrypted
          keyRaw: key,
          mtimeCli: mtimeLocal,
          mtimeSvr: mtimeLocal,
          size: entry.stat.size, // local always unencrypted
          sizeRaw: entry.stat.size,
        };
      } else if (entry instanceof TFolder) {
        key = `${key}/`;
        r = {
          key: key,
          keyRaw: key,
          size: 0,
          sizeRaw: 0,
        };
      } else {
        throw Error(`unexpected ${entry}`);
      }

      if (r.keyRaw.startsWith(DEFAULT_DEBUG_FOLDER)) {
        // skip listing the debug folder,
        // which should always not involved in sync
        // continue;
      } else {
        local.push(r);
      }
    }

    this.profiler?.insert("finish transforming walk for local");

    if (this.syncConfigDir || this.syncBookmarks) {
      this.profiler?.insert("into syncConfigDir or syncBookmarks");
      const bookmarksOnly = !this.syncConfigDir;
      const syncFiles = await listFilesInObsFolder(
        this.configDir,
        this.vault,
        this.pluginID,
        bookmarksOnly
      );
      // console.debug(`syncFiles in obs: ${JSON.stringify(syncFiles, null, 2)}`);
      for (const f of syncFiles) {
        local.push(f);
      }
      this.profiler?.insert("finish syncConfigDir");
    }

    this.profiler?.insert("finish walk for local");
    this.profiler?.removeIndent();
    return local;
  }

  async walkPartial(): Promise<Entity[]> {
    return await this.walk();
  }

  async stat(key: string): Promise<Entity> {
    const statRes = await statFix(this.vault, key);
    if (statRes === undefined || statRes === null) {
      throw Error(`${key} does not exist! cannot stat for local`);
    }
    const isFolder = statRes.type === "folder";
    return {
      key: isFolder ? `${key}/` : key, // local always unencrypted
      keyRaw: isFolder ? `${key}/` : key,
      ctimeCli: statRes.ctime,
      mtimeCli: statRes.mtime,
      mtimeSvr: statRes.mtime,
      ctimeCliFmt: unixTimeToStr(statRes.ctime),
      mtimeCliFmt: unixTimeToStr(statRes.mtime),
      mtimeSvrFmt: unixTimeToStr(statRes.mtime),
      size: statRes.size, // local always unencrypted
      sizeRaw: statRes.size,
    };
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    // console.debug(`mkdir: ${key}`);
    await mkdirpInVault(key, this.vault);
    return await this.stat(key);
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    await this.vault.adapter.writeBinary(key, content, {
      mtime: mtime,
      ctime: ctime,
    });
    return await this.stat(key);
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    return await this.vault.adapter.readBinary(key);
  }

  async rename(key1: string, key2: string): Promise<void> {
    return await this.vault.adapter.rename(key1, key2);
  }

  async rm(key: string): Promise<void> {
    if (this.deleteToWhere === "obsidian") {
      await this.vault.adapter.trashLocal(key);
    } else {
      // "system"
      if (!(await this.vault.adapter.trashSystem(key))) {
        await this.vault.adapter.trashLocal(key);
      }
    }
  }
  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    return true;
  }

  async getUserDisplayName(): Promise<string> {
    throw new Error("Method not implemented.");
  }

  async revokeAuth(): Promise<void> {
    throw new Error("Method not implemented.");
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return true;
  }
}

