// The Client
////////////////////////////////////////////////////////////////////////////////

export class FakeFsOnedriveFull extends FakeFs {
  kind: "onedrivefull";
  config: OnedriveFullConfig;
  remoteBaseDir: string;
  vaultFolderExists: boolean;
  auth: OneDriveFullAuthProvider;
  saveFunc: () => Promise<void>;
  foldersCreated: Set<string>;

  constructor(
    config: OnedriveFullConfig,
    vaultName: string,
    saveFunc: () => Promise<void>
  ) {
    super();
    this.kind = "onedrivefull";
    this.config = config;
    this.remoteBaseDir = config.remoteBaseDir || vaultName || "";
    this.vaultFolderExists = false;
    this.saveFunc = saveFunc;
    this.auth = new OneDriveFullAuthProvider(config, saveFunc);
    this.foldersCreated = new Set();
  }

  private _buildUrl(pathFrag: string): string {
    const API = "https://graph.microsoft.com/v1.0";
    let url = pathFrag.startsWith("http") ? pathFrag : `${API}${encodeURI(pathFrag)}`;
    url = url.replace(/#/g, "%23");
    return url;
  }

   


  private async _getJson(path: string): Promise<any> {
    return JSON.parse(
      await request({
        url: this._buildUrl(path),
        method: "GET",
        contentType: "application/json",
        headers: {
          Authorization: `Bearer ${await this.auth.getAccessToken()}`,
          "Cache-Control": "no-cache",
        },
      })
    );
  }

   


  private async _postJson(path: string, payload: any): Promise<any> {
    return JSON.parse(
      await request({
        url: this._buildUrl(path),
        method: "POST",
        contentType: "application/json",
        body: JSON.stringify(payload),
        headers: {
          Authorization: `Bearer ${await this.auth.getAccessToken()}`,
        },
      })
    );
  }

   


  private async _patchJson(path: string, payload: any): Promise<any> {
    return JSON.parse(
      await request({
        url: this._buildUrl(path),
        method: "PATCH",
        contentType: "application/json",
        body: JSON.stringify(payload),
        headers: {
          Authorization: `Bearer ${await this.auth.getAccessToken()}`,
        },
      })
    );
  }

  private async _deleteJson(path: string): Promise<void> {
    const url = this._buildUrl(path);
    if (VALID_REQURL) {
      await requestUrl({
        url,
        method: "DELETE",
        headers: { Authorization: `Bearer ${await this.auth.getAccessToken()}` },
      });
    } else {
      await retryFetch(url, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${await this.auth.getAccessToken()}` },
      });
    }
  }

  private async _putArrayBuffer(
    path: string,
    payload: ArrayBuffer
  ): Promise<DriveItem | UploadSession> {
    const url = this._buildUrl(path);
    const token = await this.auth.getAccessToken();
    const res = await retryFetch(url, {
      method: "PUT",
      body: payload,
      headers: {
        "Content-Type": DEFAULT_CONTENT_TYPE,
        Authorization: `Bearer ${token}`,
      },
    });
    return (await res.json()) as DriveItem | UploadSession;
  }

  private async _putByRange(
    url: string,
    data: Uint8Array,
    start: number,
    end: number,
    total: number
  ): Promise<DriveItem | UploadSession> {
    // Upload session ranges — NO auth header
    const res = await retryFetch(url, {
      method: "PUT",
      body: data.slice(start, end).buffer,
      headers: {
        "Content-Length": `${end - start}`,
        "Content-Range": `bytes ${start}-${end - 1}/${total}`,
        "Content-Type": DEFAULT_CONTENT_TYPE,
      },
    });
    return (await res.json()) as DriveItem | UploadSession;
  }

  async _init(): Promise<void> {
    if (!this.config.accessToken || !this.config.refreshToken) {
      throw Error("OneDrive Full: user has not authorized yet.");
    }

    if (!this.vaultFolderExists) {
      // Check if the base dir exists at the drive root
      try {
        await this._getJson(`/drive/root:/${this.remoteBaseDir}`);
        this.vaultFolderExists = true;
      } catch {
        // Create it
        console.debug(`OneDrive Full: creating /${this.remoteBaseDir}`);
        await this._postJson("/drive/root/children", {
          name: this.remoteBaseDir,
          folder: {},
          "@microsoft.graph.conflictBehavior": "replace",
        });
        this.vaultFolderExists = true;
      }
    }
  }

  async listFoldersAtRoot(): Promise<string[]> {
    const k = await this._getJson("/drive/root/children");
    return (k.value as DriveItem[])
      .filter((x: DriveItem) => "folder" in x)
      .map((x: DriveItem) => x.name!)
      .sort((a, b) => a.localeCompare(b));
  }

  async createFolderAtRoot(name: string): Promise<void> {
    await this._postJson("/drive/root/children", {
      name,
      folder: {},
      "@microsoft.graph.conflictBehavior": "fail",
    });
  }

  async walk(): Promise<Entity[]> {
    await this._init();

    const NEXT_KEY = "@odata.nextLink";
    const DELTA_KEY = "@odata.deltaLink";

    let res = await this._getJson(
      `/drive/root:/${this.remoteBaseDir}:/delta`
    );
    const items = res.value as DriveItem[];

    while (NEXT_KEY in res) {
      res = await this._getJson(res[NEXT_KEY]);
      items.push(...cloneDeep(res.value as DriveItem[]));
    }

    if (DELTA_KEY in res) {
      this.config.deltaLink = res[DELTA_KEY];
      await this.saveFunc();
    }

    return items
      .map((x) => fromDriveItemToEntity(x, this.remoteBaseDir))
      .filter((x) => x.key !== "/" && x.key !== "");
  }

  async walkPartial(): Promise<Entity[]> {
    await this._init();

    const DELTA_KEY = "@odata.deltaLink";
    const res = await this._getJson(
      `/drive/root:/${this.remoteBaseDir}:/delta`
    );
    const items = res.value as DriveItem[];

    if (DELTA_KEY in res) {
      this.config.deltaLink = res[DELTA_KEY];
      await this.saveFunc();
    }

    return items
      .map((x) => fromDriveItemToEntity(x, this.remoteBaseDir))
      .filter((x) => x.key !== "/" && x.key !== "");
  }

  async stat(key: string): Promise<Entity> {
    await this._init();
    const path = getOnedrivePath(key, this.remoteBaseDir);
    const rsp = await this._getJson(
      `${path}?$select=cTag,eTag,fileSystemInfo,folder,file,name,parentReference,size`
    );
    return fromDriveItemToEntity(rsp as DriveItem, this.remoteBaseDir);
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    if (!key.endsWith("/")) throw Error(`mkdir called on non-folder: ${key}`);
    await this._init();

    const uploadFolder = getOnedrivePath(key, this.remoteBaseDir);
    if (!this.foldersCreated.has(uploadFolder)) {
      const payload: any = {
        folder: {},
        "@microsoft.graph.conflictBehavior": "replace",
      };
      const fsi: Record<string, string> = {};
      if (mtime && mtime !== 0) fsi.lastModifiedDateTime = new Date(mtime).toISOString();
      if (ctime && ctime !== 0) fsi.createdDateTime = new Date(ctime).toISOString();
      if (Object.keys(fsi).length > 0) payload.fileSystemInfo = fsi;
      await this._patchJson(uploadFolder, payload);
      this.foldersCreated.add(uploadFolder);
    }
    return this.stat(key);
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    if (key.endsWith("/")) throw Error(`writeFile called on folder: ${key}`);
    await this._init();

    if (content.byteLength === 0) {
      if (this.config.emptyFile === "error") {
        throw Error(
          `${key}: Empty files not allowed in OneDrive. Please add content.`
        );
      }
      return {
        key, keyRaw: key,
        mtimeSvr: mtime, mtimeCli: mtime, ctimeCli: ctime,
        size: 0, sizeRaw: 0, synthesizedFile: true,
      };
    }

    const remotePath = getOnedrivePath(key, this.remoteBaseDir);
    const mtimeStr = new Date(mtime).toISOString();
    const ctimeStr = new Date(ctime).toISOString();

    const DIRECT_MAX = 4_000_000; // 4 MB
    const RANGE_SIZE = 327680 * 20; // ~6.5 MB chunks

    if (content.byteLength < DIRECT_MAX) {
      await this._putArrayBuffer(
        `${remotePath}:/content?${new URLSearchParams({
          "@microsoft.graph.conflictBehavior": "replace",
        })}`,
        content
      );
      if (mtime !== 0 && ctime !== 0) {
        await this._patchJson(remotePath, {
          fileSystemInfo: {
            lastModifiedDateTime: mtimeStr,
            createdDateTime: ctimeStr,
          },
        });
      }
    } else {
      // Large file upload session
      const session: UploadSession = await this._postJson(
        `${remotePath}:/createUploadSession`,
        {
          item: {
            "@microsoft.graph.conflictBehavior": "replace",
            fileSystemInfo: {
              lastModifiedDateTime: mtimeStr,
              createdDateTime: ctimeStr,
            },
          },
        }
      );
      const uploadUrl = session.uploadUrl!;
      const uint8 = new Uint8Array(content);
      let start = 0;
      while (start < uint8.byteLength) {
        await this._putByRange(
          uploadUrl,
          uint8,
          start,
          Math.min(start + RANGE_SIZE, uint8.byteLength),
          uint8.byteLength
        );
        start += RANGE_SIZE;
      }
    }

    return this.stat(key);
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    await this._init();
    if (key.endsWith("/")) throw Error(`readFile called on folder: ${key}`);

    const remotePath = getOnedrivePath(key, this.remoteBaseDir);
    const rsp = await this._getJson(
      `${remotePath}?$select=@microsoft.graph.downloadUrl`
    );
    const downloadUrl: string = rsp["@microsoft.graph.downloadUrl"];

    try {
      return await (await retryFetch(downloadUrl, { cache: "no-store" })).arrayBuffer();
    } catch {
      // Fallback for CORS issues
      return (await requestUrl({ url: downloadUrl, headers: { "Cache-Control": "no-cache" } })).arrayBuffer;
    }
  }

  async rename(key1: string, key2: string): Promise<void> {
    if (!key1 || key1 === "/" || !key2 || key2 === "/") return;
    await this._init();
    const remote1 = getOnedrivePath(key1, this.remoteBaseDir);
    const remote2 = getOnedrivePath(key2, this.remoteBaseDir);
    await this._patchJson(remote1, { name: remote2 });
  }

  async rm(key: string): Promise<void> {
    if (!key || key === "/") return;
    await this._init();
    await this._deleteJson(getOnedrivePath(key, this.remoteBaseDir));
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    try {
      const name = await this.getUserDisplayName();
      if (name === "<unknown>") throw Error("unknown display name");
    } catch (err) {
      callbackFunc?.(err);
      return false;
    }
    return this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    await this._init();
    const res: User = await this._getJson("/me?$select=displayName");
    return res.displayName || "<unknown>";
  }

  async revokeAuth(): Promise<void> {
    throw new Error("Visit https://account.live.com/consent/Manage to revoke.");
  }

  async getRevokeAddr(): Promise<string> {
    return "https://account.live.com/consent/Manage";
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return false;
  }
}

export const getShrinkedSettings = (config: OnedriveFullConfig) => {
  const c = cloneDeep(config);
  c.accessToken = "x";
  c.accessTokenExpiresInSeconds = 1;
  c.accessTokenExpiresAtTime = 1;
  return c;
};

import { nanoid } from "nanoid";
import { requestUrl } from "obsidian";
import pcloudSdk from "pcloud-sdk-js";
import {
  type Entity,
  PCLOUD_CLIENT_ID,
  PCLOUD_CLIENT_SECRET,
  type PCloudConfig,
  COMMAND_URI,
  COMMAND_CALLBACK_PCLOUD,
} from "./baseTypes";
import { FakeFs } from "./fsAll";
import { getFolderLevels, retryFetch } from "./misc";

export const DEFAULT_PCLOUD_CONFIG: PCloudConfig = {
  accessToken: "",
  hostname: "eapi.pcloud.com",
  locationid: 2,
  credentialsShouldBeDeletedAtTimeMs: 0,
  emptyFile: "skip",
  kind: "pcloud",
};

export interface AuthAllowFirstRes {
  code: string;
  state?: string;
  locationid: 1 | 2;
  hostname: "api.pcloud.com" | "eapi.pcloud.com";
}

/**
 * https://docs.pcloud.com/methods/oauth_2.0/authorize.html
 */
export const generateAuthUrl = async (hasCallback: boolean) => {
  const clientID = PCLOUD_CLIENT_ID;
  const state = nanoid();
  let authUrl = `https://my.pcloud.com/oauth2/authorize?response_type=code&client_id=${clientID}&state=${state}`;
  if (hasCallback) {
    authUrl += `&redirect_uri=obsidian://${COMMAND_CALLBACK_PCLOUD}`;
  }
  return {
    authUrl,
    state,
  };
};

interface AuthResSucc {
  result: number;
  access_token: string;
  token_type: "bearer";
  uid: number;
  locationid: number;
}

/**
 * https://docs.pcloud.com/methods/oauth_2.0/oauth2_token.html
 */
export const sendAuthReq = async (
  hostname: string,
  authCode: string,
  errorCallBack: (e: unknown) => void | Promise<void>
) => {
  const clientID = PCLOUD_CLIENT_ID ?? "";
  const clientSecret = PCLOUD_CLIENT_SECRET ?? "";
  try {
    const k = {
      code: authCode,
      client_id: clientID,
      client_secret: clientSecret,
    };
    // console.debug(k);
    const resp1 = await requestUrl({
      url: `https://${hostname}/oauth2_token`,
      method: "POST",
      contentType: "application/x-www-form-urlencoded",
      body: new URLSearchParams(k).toString(),
      throw: false,
    });
    const resp2: AuthResSucc = resp1.json as AuthResSucc;
    // console.debug(resp2);
    if (resp2?.result !== 0) {
      throw Error(`result is not 0 (success) in the end`);
    }
    if (!("access_token" in resp2)) {
      throw Error(`no access_token in the end`);
    }
    return resp2;
  } catch (e) {
    console.error(e);
    if (errorCallBack !== undefined) {
      await errorCallBack(e);
    }
  }
};

export const setConfigBySuccessfullAuthInplace = async (
  config: PCloudConfig,
  authAllowFirstRes: AuthAllowFirstRes,
  authRes: AuthResSucc | undefined,
  saveUpdatedConfigFunc: () => Promise<void> | undefined
) => {
  if (authRes === undefined) {
    throw Error(
      `BYOC pCloud auth failed â€” no token received. Please try authenticating again.`
    );
  }

  config.accessToken = authRes.access_token;
  config.hostname = authAllowFirstRes.hostname;
  config.locationid = authAllowFirstRes.locationid;

  // BYOC: No credential expiry â€” tokens persist until manually revoked.
  config.credentialsShouldBeDeletedAtTimeMs = 0;

  await saveUpdatedConfigFunc?.();

  console.debug("finish updating local info of pCloud token");
};

interface PCloudEntity extends Entity {
  id: number;
  parentID: number | undefined;
  parentIDPath: string | undefined;
  isFolder: boolean;
  hashPCloud: number | undefined;
}

interface File {
  contenttype: string;
  created: string;
  fileid: number;
  hash: number;
  id: string; // "f" + fileid
  isfolder: false;
  modified: string;
  name: string;
  parentfolderid: number;
  size: number;
}

interface Folder {
  contents: (Folder | File)[] | undefined;
  id: string; // "d"+folderid
  folderid: number;
  isfolder: true;
  created: string;
  modified: string;
  name: string;
  parentfolderid: number;
}

interface StatRawResponse {
  result: number;
  fileids: number[];
  metadata: (File | Folder)[];
  checksums: { sha1: string; sha256?: string; md5?: string }[] | undefined;
}

const fromRawResponseToEntity = (
  item: Folder | File,
  parentFolderPath: string | undefined /* for bfs */
): PCloudEntity => {
  if (item.parentfolderid === undefined || item.parentfolderid === 0) {
    throw Error(
      `parentfolderid=${item.parentfolderid} should not be in fromRawResponseToEntity`
    );
  }

  let keyRaw = item.name;
  let size = 0;
  let hashPCloud: number | undefined = undefined;
  let hash: string | undefined = undefined;
  let id: number | undefined = undefined;
  if (
    parentFolderPath !== undefined &&
    parentFolderPath !== "" &&
    parentFolderPath !== "/"
  ) {
    if (!parentFolderPath.endsWith("/")) {
      throw Error(
        `parentFolderPath=${parentFolderPath} should not be in fromRawResponseToEntity`
      );
    }
    keyRaw = `${parentFolderPath}${item.name}`;
  }

  if (item.isfolder) {
    keyRaw = `${keyRaw}/`;
    id = item.folderid;
  } else {
    size = item.size;
    hashPCloud = item.hash;
    hash = `${item.hash}`;
    id = item.fileid;
  }

  const mtime = new Date(item.modified).valueOf();

  return {
    key: keyRaw,
    keyRaw: keyRaw,
    mtimeCli: mtime,
    mtimeSvr: mtime,
    id: id,
    parentID: item.parentfolderid,
    isFolder: item.isfolder,
    size: size,
    sizeRaw: size,
    hash: hash,
    hashPCloud: hashPCloud,
    parentIDPath: parentFolderPath,
  };
};

const fromNestedFolderToEntityListAndCache = (
  root: Folder
): { entities: PCloudEntity[]; key2Entity: Record<string, PCloudEntity> } => {
  // console.debug("root:");
  // console.debug(root);

  const entities: PCloudEntity[] = [];
  const key2Entity: Record<string, PCloudEntity> = {};

  if (root.contents === undefined || root.contents.length === 0) {
    // console.debug(`early return`);
    return {
      entities,
      key2Entity,
    };
  }

  let parents: {
    folderPath: string;
    itself: Folder | File;
  }[] = [];
  for (const f of root.contents ?? []) {
    parents.push({
      folderPath: "",
      itself: f,
    });
  }

  while (parents.length !== 0) {
    const children: typeof parents = [];
    for (const { folderPath, itself } of parents) {
      if (itself.isfolder && itself.folderid === root.folderid) {
        // special, ignore root folder itself
      } else {
        const entity = fromRawResponseToEntity(itself, folderPath);
        entities.push(entity);
        key2Entity[entity.keyRaw] = entity;
      }

      if (
        itself.isfolder &&
        itself.contents !== undefined &&
        itself.contents.length > 0
      ) {
        for (const f of itself.contents) {
          if (folderPath === "" || folderPath === "/") {
            const child = {
              itself: f,
              folderPath: `${itself.name}/`,
            };
            children.push(child);
          } else {
            const child = {
              itself: f,
              folderPath: `${folderPath}${itself.name}/`,
            };
            children.push(child);
          }
        }
      }
    }
    parents = children;
  }

  // console.debug("entities:");
  // console.debug(entities);
  // console.debug("key2Entity:");
  // console.debug(key2Entity);

  return {
    entities,
    key2Entity,
  };
};

const getPCloudPath = (fileOrFolderPath: string, remoteBaseDir: string) => {
  return `/${remoteBaseDir}/${fileOrFolderPath}`;
};

export class FakeFsPCloud extends FakeFs {
  kind: string;

  pCloudConfig: PCloudConfig;
  remoteBaseDir: string;
  vaultFolderExists: boolean;
  saveUpdatedConfigFunc: () => Promise<void>;

  keyToPCloudEntity: Record<string, PCloudEntity>;
  baseDirID: number;

  client: pcloudSdk.Client | null;

  constructor(
    pCloudConfig: PCloudConfig,
    vaultName: string,
    saveUpdatedConfigFunc: () => Promise<void>
  ) {
    super();
    this.kind = "pcloud";
    this.pCloudConfig = pCloudConfig;
    this.remoteBaseDir = this.pCloudConfig.remoteBaseDir || vaultName || "";
    this.vaultFolderExists = false;
    this.saveUpdatedConfigFunc = saveUpdatedConfigFunc;
    this.keyToPCloudEntity = {};
    this.baseDirID = 0;

    // Lazy: delay SDK client creation until _init().
    // The constructor runs when the settings panel renders, at which point
    // accessToken may still be empty string. createClient() throws if token absent.
    this.client = null;
  }

  /**
   * Lazy-create the SDK client. Pulled out of _init so that operations
   * targeting the cloud root (folder picker, listFoldersAtRoot, etc.) can
   * skip the remoteBaseDir resolution that _init also performs.
   */
  private _initClient() {
    if (this.client) return;
    const token = this.pCloudConfig.accessToken;
    if (!token) {
      throw Error("pCloud: no access token — please authenticate first.");
    }
    // pCloud SDK reads locationid from global scope; coerce string→number
    // because URL callback params always arrive as strings.
    // eslint-disable-next-line obsidianmd/prefer-active-doc
    (globalThis as { locationid?: number }).locationid =
      typeof this.pCloudConfig.locationid === "string"
        ? parseInt(this.pCloudConfig.locationid, 10)
        : (this.pCloudConfig.locationid ?? 1);
    this.client = pcloudSdk.createClient(token);
  }

  async _init() {
    this._initClient();

    if (this.vaultFolderExists) {
      return;
    } else {
      const root = (await this._sdk.listfolder(0, {
        recursive: false,
      })) as Folder;

      // find?
      if (root.contents === undefined) {
        throw Error(`cannot listfolder of root!`);
      }
      const found = root.contents.filter(
        (x) => x.isfolder && x.name === this.remoteBaseDir
      );
      if (found.length > 0) {
        // we find it!
        const f = found[0] as Folder;
        this.baseDirID = f.folderid;
        this.vaultFolderExists = true;
      } else {
        // not found, let's create it!
        const f: Folder = await this._sdk.createfolder(this.remoteBaseDir, 0);
        // console.debug(f);
        this.baseDirID = f.folderid;
        this.vaultFolderExists = true;
      }
    }
  }

  /** Non-null accessor â€” only call after _init() has resolved. */
  private get _sdk(): pcloudSdk.Client {
    return this.client!;
  }

async _getAccessToken() {
    if (this.pCloudConfig.accessToken === "") {
      throw Error("The user has not manually auth yet.");
    }

    return this.pCloudConfig.accessToken;

    // TODO: no expire date?
    // https://docs.pcloud.com/methods/intro/authentication.html
  }

  async listFoldersAtRoot(): Promise<string[]> {
    this._initClient();
    const root = (await this._sdk.listfolder(0, {
      recursive: false,
    })) as Folder;
    if (!root.contents) return [];
    return root.contents
      .filter((x) => x.isfolder)
      .map((x) => x.name)
      .sort((a, b) => a.localeCompare(b));
  }

  async createFolderAtRoot(name: string): Promise<void> {
    this._initClient();
    await this._sdk.createfolder(name, 0);
  }

  async walk(): Promise<Entity[]> {
    await this._init();
    const rsp = (await this._sdk.listfolder(this.baseDirID, {
      recursive: true,
    })) as Folder;

    const { entities, key2Entity } = fromNestedFolderToEntityListAndCache(rsp);

    this.keyToPCloudEntity = Object.assign(this.keyToPCloudEntity, key2Entity);

    return entities;
  }

  async walkPartial(): Promise<Entity[]> {
    await this._init();
    const rsp = (await this._sdk.listfolder(this.baseDirID, {
      recursive: false,
    })) as Folder;
    const { entities, key2Entity } = fromNestedFolderToEntityListAndCache(rsp);

    this.keyToPCloudEntity = Object.assign(this.keyToPCloudEntity, key2Entity);

    return entities;
  }

  async stat(key: string): Promise<Entity> {
    await this._init();

    // TODO: we already have a cache, should we call again?
    const cachedEntity = this.keyToPCloudEntity[key];
    const fileID = cachedEntity?.id;
    if (cachedEntity === undefined || fileID === undefined) {
      throw Error(`no fileID found for key=${key}`);
    }

    // why? pcloud doesn't have stat api??
    return cachedEntity;
  }

  async mkdir(
    key: string,
    mtime?: number  ,
    ctime?: number  
  ): Promise<Entity> {
    if (!key.endsWith("/")) {
      throw Error(`you should not mkdir on key=${key}`);
    }

    await this._init();

    const cachedEntity = this.keyToPCloudEntity[key];
    const fileID = cachedEntity?.id;
    if (cachedEntity !== undefined && fileID !== undefined) {
      return cachedEntity;
    }

    // xxx/ => ["xxx"]
    // xxx/yyy/zzz/ => ["xxx", "xxx/yyy", "xxx/yyy/zzz"]
    const folderLevels = getFolderLevels(key);
    let parentFolderPath: string | undefined = undefined;
    let parentID: number | undefined = undefined;
    if (folderLevels.length === 0) {
      throw Error(`cannot getFolderLevels of ${key}`);
    } else if (folderLevels.length === 1) {
      parentID = this.baseDirID;
      parentFolderPath = ""; // ignore base dir
    } else {
      // length > 1
      parentFolderPath = `${folderLevels[folderLevels.length - 2]}/`;
      if (!(parentFolderPath in this.keyToPCloudEntity)) {
        throw Error(
          `parent of ${key}: ${parentFolderPath} is not created before??`
        );
      }
      parentID = this.keyToPCloudEntity[parentFolderPath].id;
    }

    // xxx/yyy/zzz/ => ["xxx", "xxx/yyy", "xxx/yyy/zzz"] => "xxx/yyy/zzz" => "zzz"
    let folderItselfWithoutSlash = folderLevels[folderLevels.length - 1];
    folderItselfWithoutSlash = folderItselfWithoutSlash.split("/").pop()!;

    const f = await this._sdk.createfolder(
      folderItselfWithoutSlash,
      parentID
    );

    const entity = fromRawResponseToEntity(f, parentFolderPath);
    // insert into cache
    this.keyToPCloudEntity[key] = entity;
    return entity;
  }

  /**
   * https://docs.pcloud.com/methods/file/uploadfile.html
   */
  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    if (key.endsWith("/")) {
      throw Error(`should not call writeFile on ${key}`);
    }

    await this._init();

    const prevCachedEntity: PCloudEntity | undefined =
      this.keyToPCloudEntity[key];
    const prevFileID: number | undefined = prevCachedEntity?.id;

    let parentID: number | undefined = undefined;
    let parentFolderPath: string | undefined = undefined;

    // "xxx" => []
    // "xxx/yyy/zzz.md" => ["xxx", "xxx/yyy"]
    const folderLevels = getFolderLevels(key);
    if (folderLevels.length === 0) {
      // root
      parentID = this.baseDirID;
      parentFolderPath = "";
    } else {
      parentFolderPath = `${folderLevels[folderLevels.length - 1]}/`;
      if (!(parentFolderPath in this.keyToPCloudEntity)) {
        throw Error(
          `parent of ${key}: ${parentFolderPath} is not created before??`
        );
      }
      parentID = this.keyToPCloudEntity[parentFolderPath].id;
    }

    const fileItself = key.split("/").pop()!;

    // no idea how to use the sdk, let's use https here
    // https://docs.pcloud.com/methods/file/uploadfile.html
    const params = new URLSearchParams({
      access_token: await this._getAccessToken(),
      folderid: `${parentID}`,
      filename: fileItself,
      nopartial: `1`,
      renameifexists: `0`,
      mtime: `${Math.floor(mtime / 1000.0)}`,
      ctime: `${Math.floor(ctime / 1000.0)}`,
    });
    const apiUrl = `https://${this.pCloudConfig.hostname}/uploadfile?${params}`;

    if (content.byteLength > 0) {
      const rsp = await retryFetch(apiUrl, {
        method: "PUT",
        body: content,
      });
      const f: StatRawResponse = await rsp.json();
      const entity = fromRawResponseToEntity(f.metadata[0], parentFolderPath);
      // console.debug(entity);
      this.keyToPCloudEntity[key] = entity;
      return entity;
    } else {
      // no idea why pcloud doesn't work for empty files
      // it can be uploaded successfully but the call doesn't end
      // we abort it and stat it manually.
      // console.warn(`uploading empty file ${key}`);
      const controller = new AbortController();
      const timeoutMs = 300; // just a random reasonable number
      const id = activeWindow.setTimeout(() => controller.abort(), timeoutMs);
      try {
        // requestUrl has no abort signal support; we deliberately use fetch
        // here so we can abort the hung empty-file request after 300ms.
         
        const rsp = await fetch(apiUrl, {
          method: "PUT",
          body: content,
          signal: controller.signal,
        });
      } catch (e) {
        // console.warn(`we abort the request of uploading empty file ${key}:`);
        // console.warn(e);
      } finally {
        activeWindow.clearTimeout(id);
      }

      // raw stat here
      // https://docs.pcloud.com/methods/file/stat.html
      const params = new URLSearchParams({
        access_token: await this._getAccessToken(),
        path: getPCloudPath(key, this.remoteBaseDir),
      });
      const apiUrlStat = `https://${this.pCloudConfig.hostname}/stat?${params}`;
      const rsp2 = await retryFetch(apiUrlStat);
      const f = await rsp2.json();
      const entity = fromRawResponseToEntity(f.metadata, parentFolderPath);
      // console.warn(entity);
      this.keyToPCloudEntity[key] = entity;
      return entity;
    }
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    await this._init();
    const cachedEntity = this.keyToPCloudEntity[key];
    const fileID = cachedEntity?.id;
    if (cachedEntity === undefined || fileID === undefined) {
      throw Error(`no fileID found for key=${key}`);
    }

    const params = new URLSearchParams({
      access_token: await this._getAccessToken(),
      forcedownload: `1`,
      fileid: `${fileID}`,
    });
    const urlMeta = `https://${this.pCloudConfig.hostname}/getfilelink?${params}`;

    // Referrer is restricted to pcloud.com.
    // we need to bypass it
    const meta = (await requestUrl(urlMeta)).json;
    // console.debug(meta);
    const link: string = `https://${meta.hosts[0]}${meta.path}`;
    const rsp = await requestUrl(link);
    const content = rsp.arrayBuffer;
    return content;
  }

  async rename(key1: string, key2: string): Promise<void> {
    await this._init();
    throw new Error("Method not implemented.");
  }

  async rm(key: string): Promise<void> {
    await this._init();

    const cachedEntity = this.keyToPCloudEntity[key];
    const fileID = cachedEntity?.id;
    if (cachedEntity === undefined || fileID === undefined) {
      throw Error(`no fileID found for key=${key}`);
    }

    if (key.endsWith("/")) {
      await this._sdk.deletefolder(fileID);
    } else {
      await this._sdk.deletefile(fileID);
    }
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    // if we can init, we can connect
    try {
      await this._init();
    } catch (err) {
      console.debug(err);
      callbackFunc?.(err);
      return false;
    }
    return await this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    await this._init();
    // https://docs.pcloud.com/methods/general/userinfo.html
    const params = new URLSearchParams({
      access_token: await this._getAccessToken(),
    });
    const url = `https://${this.pCloudConfig.hostname}/userinfo?${params}`;
    const rsp = await retryFetch(url);
    const info = await rsp.json();
    // pCloud returns `email` as the primary identifier
    return (info.email as string) ?? "pCloud user";
  }

  async revokeAuth(): Promise<void> {
    await this._init();
    throw new Error("Method not implemented.");
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return true;
  }
}

