export const simpleTransRemotePrefix = (x: string) => {
  if (x === undefined) {
    return "";
  }
  let y = path.posix.normalize(x.trim());
  if (y === undefined || y === "" || y === "/" || y === ".") {
    return "";
  }
  if (y.startsWith("/")) {
    y = y.slice(1);
  }
  if (!y.endsWith("/")) {
    y = `${y}/`;
  }
  return y;
};

export const DEFAULT_S3_CONFIG: S3Config = {
  s3Endpoint: "",
  s3Region: "",
  s3AccessKeyID: "",
  s3SecretAccessKey: "",
  s3BucketName: "",
  bypassCorsLocally: true,
  partsConcurrency: 20,
  forcePathStyle: false,
  remotePrefix: "",
  useAccurateMTime: false, // it causes money, disable by default
  reverseProxyNoSignUrl: "",
  generateFolderObject: false, // new version, by default not generate folders
};

/**
 * The Body of resp of aws GetObject has mix types
 * and we want to get ArrayBuffer here.
 * See https://github.com/aws/aws-sdk-js-v3/issues/1877
 * @param b The Body of GetObject
 * @returns Promise<ArrayBuffer>
 */
const getObjectBodyToArrayBuffer = async (
  b: Readable | ReadableStream | Blob | undefined
) => {
  if (b === undefined) {
    throw Error(`ObjectBody is undefined and don't know how to deal with it`);
  }
  if (b instanceof Readable) {
    return await new Promise<ArrayBuffer>((resolve, reject) => {
      const chunks: Uint8Array[] = [];
      b.on("data", (chunk) => chunks.push(chunk));
      b.on("error", reject);
      b.on("end", () => resolve(bufferToArrayBuffer(Buffer.concat(chunks)) as ArrayBuffer));
    });
  } else if (b instanceof ReadableStream) {
    return await new Response(b, {}).arrayBuffer();
  } else if (b instanceof Blob) {
    return await b.arrayBuffer();
  } else {
    throw TypeError(`The type of ${b} is not one of the supported types`);
  }
};

const getS3Client = (s3Config: S3Config) => {
  let endpoint = s3Config.s3Endpoint;
  if (!(endpoint.startsWith("http://") || endpoint.startsWith("https://"))) {
    endpoint = `https://${endpoint}`;
  }

  let s3Client: S3Client;
  if (VALID_REQURL && s3Config.bypassCorsLocally) {
    s3Client = new S3Client({
      region: s3Config.s3Region,
      endpoint: endpoint,
      forcePathStyle: s3Config.forcePathStyle,
      credentials: {
        accessKeyId: s3Config.s3AccessKeyID,
        secretAccessKey: s3Config.s3SecretAccessKey,
      },
      requestHandler: new ObsHttpHandler(
        undefined,
        s3Config.reverseProxyNoSignUrl
      ),
    });
  } else {
    s3Client = new S3Client({
      region: s3Config.s3Region,
      endpoint: endpoint,
      forcePathStyle: s3Config.forcePathStyle,
      credentials: {
        accessKeyId: s3Config.s3AccessKeyID,
        secretAccessKey: s3Config.s3SecretAccessKey,
      },
    });
  }

  s3Client.middlewareStack.add(
    (next, context) => (args) => {
      (args.request as any).headers["cache-control"] = "no-cache";
      return next(args);
    },
    {
      step: "build",
    }
  );

  return s3Client;
};

const getLocalNoPrefixPath = (
  fileOrFolderPathWithRemotePrefix: string,
  remotePrefix: string
) => {
  if (
    !(
      fileOrFolderPathWithRemotePrefix === `${remotePrefix}` ||
      fileOrFolderPathWithRemotePrefix.startsWith(`${remotePrefix}`)
    )
  ) {
    throw Error(
      `"${fileOrFolderPathWithRemotePrefix}" doesn't starts with "${remotePrefix}"`
    );
  }
  return fileOrFolderPathWithRemotePrefix.slice(`${remotePrefix}`.length);
};

const getRemoteWithPrefixPath = (
  fileOrFolderPath: string,
  remotePrefix: string
) => {
  if (remotePrefix === undefined || remotePrefix === "") {
    return fileOrFolderPath;
  }
  let key = fileOrFolderPath;
  if (fileOrFolderPath === "/" || fileOrFolderPath === "") {
    // special
    key = remotePrefix;
  }
  if (!fileOrFolderPath.startsWith("/")) {
    key = `${remotePrefix}${fileOrFolderPath}`;
  }
  return key;
};

const fromS3ObjectToEntity = (
  x: _Object,
  remotePrefix: string,
  mtimeRecords: Record<string, number>,
  ctimeRecords: Record<string, number>
) => {
  // console.debug(`fromS3ObjectToEntity: ${x.Key!}, ${JSON.stringify(x,null,2)}`);
  // S3 officially only supports seconds precision!!!!!
  if (x.LastModified === undefined) {
    throw Error(
      `s3 object ${x.Key!} doesn't have LastModified value: ${JSON.stringify(
        x
      )}`
    );
  }
  const mtimeSvr = Math.floor(x.LastModified.valueOf() / 1000.0) * 1000;
  let mtimeCli = mtimeSvr;
  if (x.Key! in mtimeRecords) {
    const m2 = mtimeRecords[x.Key!];
    if (m2 !== 0) {
      // to be compatible with RClone, we read and store the time in seconds in new version!
      if (m2 >= 1000000000000) {
        // it's a millsecond, uploaded by old codes..
        mtimeCli = m2;
      } else {
        // it's a second, uploaded by new codes of the plugin from March 24, 2024
        mtimeCli = m2 * 1000;
      }
    }
  }
  const key = getLocalNoPrefixPath(x.Key!, remotePrefix); // we remove prefix here
  const r: Entity = {
    key: key, // from s3's repsective, the keyRaw is the key, we will change it in decyption
    keyRaw: key,
    mtimeSvr: mtimeSvr,
    mtimeCli: mtimeCli,
    sizeRaw: x.Size!,
    size: x.Size!, // from s3's repsective, the sizeRaw is the size, we will change it in decyption
    etag: x.ETag,
    synthesizedFolder: false,
  };
  return r;
};

const fromS3HeadObjectToEntity = (
  fileOrFolderPathWithRemotePrefix: string,
  x: HeadObjectCommandOutput,
  remotePrefix: string,
  useAccurateMTime: boolean
) => {
  // console.debug(`fromS3HeadObjectToEntity: ${fileOrFolderPathWithRemotePrefix}: ${JSON.stringify(x,null,2)}`);
  // S3 officially only supports seconds precision!!!!!
  if (x.LastModified === undefined) {
    throw Error(
      `s3 object ${fileOrFolderPathWithRemotePrefix} doesn't have LastModified value: ${JSON.stringify(
        x
      )}`
    );
  }
  const mtimeSvr = Math.floor(x.LastModified.valueOf() / 1000.0) * 1000;
  let mtimeCli = mtimeSvr;
  if (useAccurateMTime && x.Metadata !== undefined) {
    const m2 = Math.floor(
      Number.parseFloat(x.Metadata.mtime || x.Metadata.MTime || "0")
    );
    if (m2 !== 0) {
      // to be compatible with RClone, we read and store the time in seconds in new version!
      if (m2 >= 1000000000000) {
        // it's a millsecond, uploaded by old codes..
        mtimeCli = m2;
      } else {
        // it's a second, uploaded by new codes of the plugin from March 24, 2024
        mtimeCli = m2 * 1000;
      }
    }
  }
  // console.debug(
  //   `fromS3HeadObjectToEntity, fileOrFolderPathWithRemotePrefix=${fileOrFolderPathWithRemotePrefix}, remotePrefix=${remotePrefix}, x=${JSON.stringify(
  //     x
  //   )} `
  // );
  const key = getLocalNoPrefixPath(
    fileOrFolderPathWithRemotePrefix,
    remotePrefix
  );
  // console.debug(`fromS3HeadObjectToEntity, key=${key} after removing prefix`);
  return {
    key: key,
    keyRaw: key,
    mtimeSvr: mtimeSvr,
    mtimeCli: mtimeCli,
    sizeRaw: x.ContentLength,
    size: x.ContentLength,
    etag: x.ETag,
    synthesizedFolder: false,
  } as Entity;
};

export class FakeFsS3 extends FakeFs {
  s3Config: S3Config;
  s3Client: S3Client;
  kind: "s3";
  synthFoldersCache: Record<string, Entity>;
  constructor(s3Config: S3Config) {
    super();
    this.s3Config = s3Config;
    this.s3Client = getS3Client(s3Config);
    this.kind = "s3";
    this.synthFoldersCache = {};
  }

  async walk(): Promise<Entity[]> {
    const res = (
      await this._walkFromRoot(this.s3Config.remotePrefix, false)
    ).filter((x) => x.key !== "" && x.key !== "/");
    return res;
  }

  async walkPartial(): Promise<Entity[]> {
    const res = (
      await this._walkFromRoot(this.s3Config.remotePrefix, true)
    ).filter((x) => x.key !== "" && x.key !== "/");
    return res;
  }

  /**
   * the input key contains basedir (prefix),
   * but the result doesn't contain it.
   */
  async _walkFromRoot(prefixOfRawKeys: string | undefined, partial: boolean) {
    const confCmd = {
      Bucket: this.s3Config.s3BucketName,
    } as ListObjectsV2CommandInput;
    if (prefixOfRawKeys !== undefined && prefixOfRawKeys !== "") {
      confCmd.Prefix = prefixOfRawKeys;
    }
    if (partial) {
      confCmd.MaxKeys = 10; // no need to list more!
    }

    const contents = [] as _Object[];
    const mtimeRecords: Record<string, number> = {};
    const ctimeRecords: Record<string, number> = {};
    const partsConcurrency = partial ? 1 : this.s3Config.partsConcurrency;
    const queueHead = new PQueue({
      concurrency: partsConcurrency,
      autoStart: true,
    });
    queueHead.on("error", (error) => {
      queueHead.pause();
      queueHead.clear();
      throw error;
    });

    let isTruncated = true;
    do {
      const rsp = await this.s3Client.send(new ListObjectsV2Command(confCmd));

      if (rsp.$metadata.httpStatusCode !== 200) {
        throw Error("some thing bad while listing remote!");
      }
      if (rsp.Contents === undefined) {
        break;
      }
      contents.push(...rsp.Contents);

      if (this.s3Config.useAccurateMTime) {
        // head requests of all objects, love it
        for (const content of rsp.Contents) {
          queueHead.add(async () => {
            const rspHead = await this.s3Client.send(
              new HeadObjectCommand({
                Bucket: this.s3Config.s3BucketName,
                Key: content.Key,
              })
            );
            if (rspHead.$metadata.httpStatusCode !== 200) {
              throw Error("some thing bad while heading single object!");
            }
            if (rspHead.Metadata === undefined) {
              // pass
            } else {
              mtimeRecords[content.Key!] = Math.floor(
                Number.parseFloat(
                  rspHead.Metadata.mtime || rspHead.Metadata.MTime || "0"
                )
              );
              ctimeRecords[content.Key!] = Math.floor(
                Number.parseFloat(
                  rspHead.Metadata.ctime || rspHead.Metadata.CTime || "0"
                )
              );
            }
          });
        }
      }

      if (partial) {
        // do not loop over
        isTruncated = false;
      } else {
        // loop over
        isTruncated = rsp.IsTruncated ?? false;
        confCmd.ContinuationToken = rsp.NextContinuationToken;
        if (
          isTruncated &&
          (confCmd.ContinuationToken === undefined ||
            confCmd.ContinuationToken === "")
        ) {
          throw Error("isTruncated is true but no continuationToken provided");
        }
      }
    } while (isTruncated);

    // wait for any head requests
    await queueHead.onIdle();

    // ensemble fake rsp
    // in the end, we need to transform the response list
    // back to the local contents-alike list
    const res: Entity[] = [];
    const realEnrities = new Set<string>();
    for (const remoteObj of contents) {
      const remoteEntity = fromS3ObjectToEntity(
        remoteObj,
        this.s3Config.remotePrefix ?? "",
        mtimeRecords,
        ctimeRecords
      );
      realEnrities.add(remoteEntity.key!);
      res.push(remoteEntity);

      for (const f of getFolderLevels(remoteEntity.key!, true)) {
        if (realEnrities.has(f)) {
          delete this.synthFoldersCache[f];
          continue;
        }
        if (
          !Object.prototype.hasOwnProperty.call(this.synthFoldersCache, f) ||
          remoteEntity.mtimeSvr! >= this.synthFoldersCache[f].mtimeSvr!
        ) {
          this.synthFoldersCache[f] = {
            key: f,
            keyRaw: f,
            size: 0,
            sizeRaw: 0,
            sizeEnc: 0,
            mtimeSvr: remoteEntity.mtimeSvr,
            mtimeSvrFmt: remoteEntity.mtimeSvrFmt,
            mtimeCli: remoteEntity.mtimeCli,
            mtimeCliFmt: remoteEntity.mtimeCliFmt,
            synthesizedFolder: true,
          };
        }
      }
    }
    for (const key of Object.keys(this.synthFoldersCache)) {
      res.push(this.synthFoldersCache[key]);
    }
    return res;
  }

  async stat(key: string): Promise<Entity> {
    if (Object.prototype.hasOwnProperty.call(this.synthFoldersCache, key)) {
      return this.synthFoldersCache[key];
    }
    let keyFullPath = key;
    keyFullPath = getRemoteWithPrefixPath(
      keyFullPath,
      this.s3Config.remotePrefix ?? ""
    );
    return await this._statFromRoot(keyFullPath);
  }

  /**
   * the input key contains basedir (prefix),
   * but the result doesn't contain it.
   */
  async _statFromRoot(key: string): Promise<Entity> {
    if (
      this.s3Config.remotePrefix !== undefined &&
      this.s3Config.remotePrefix !== "" &&
      !key.startsWith(this.s3Config.remotePrefix)
    ) {
      throw Error(`_statFromRoot should only accept prefix-ed path`);
    }
    const res = await this.s3Client.send(
      new HeadObjectCommand({
        Bucket: this.s3Config.s3BucketName,
        Key: key,
      })
    );

    return fromS3HeadObjectToEntity(
      key,
      res,
      this.s3Config.remotePrefix ?? "",
      this.s3Config.useAccurateMTime ?? false
    );
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    if (!key.endsWith("/")) {
      throw new Error(`You should not call mkdir on ${key}!`);
    }

    const generateFolderObject = this.s3Config.generateFolderObject ?? false;
    if (!generateFolderObject) {
      const synth = {
        key: key,
        keyRaw: key,
        size: 0,
        sizeRaw: 0,
        sizeEnc: 0,
        mtimeSvr: mtime,
        mtimeCli: mtime,
        synthesizedFolder: true,
      };
      this.synthFoldersCache[key] = synth;
      return synth;
    }

    const uploadFile = getRemoteWithPrefixPath(
      key,
      this.s3Config.remotePrefix ?? ""
    );
    return await this._mkdirFromRoot(uploadFile, mtime, ctime);
  }

  async _mkdirFromRoot(key: string, mtime?: number, ctime?: number) {
    if (
      this.s3Config.remotePrefix !== undefined &&
      this.s3Config.remotePrefix !== "" &&
      !key.startsWith(this.s3Config.remotePrefix)
    ) {
      throw Error(`_mkdirFromRoot should only accept prefix-ed path`);
    }

    const contentType = DEFAULT_CONTENT_TYPE;
    const p: PutObjectCommandInput = {
      Bucket: this.s3Config.s3BucketName,
      Key: key,
      Body: "",
      ContentType: contentType,
      ContentLength: 0, // interesting we need to set this to avoid the warning
    };
    const metadata: Record<string, string> = {};
    if (mtime !== undefined && mtime !== 0) {
      metadata["MTime"] = `${mtime / 1000.0}`;
    }
    if (ctime !== undefined && ctime !== 0) {
      metadata["CTime"] = `${ctime / 1000.0}`;
    }
    if (Object.keys(metadata).length > 0) {
      p["Metadata"] = metadata;
    }
    await this.s3Client.send(new PutObjectCommand(p));
    return await this._statFromRoot(key);
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    const uploadFile = getRemoteWithPrefixPath(
      key,
      this.s3Config.remotePrefix ?? ""
    );
    const res = await this._writeFileFromRoot(
      uploadFile,
      content,
      mtime,
      ctime
    );
    return res;
  }

  /**
   * the input key contains basedir (prefix),
   * but the result doesn't contain it.
   */
  async _writeFileFromRoot(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    if (
      this.s3Config.remotePrefix !== undefined &&
      this.s3Config.remotePrefix !== "" &&
      !key.startsWith(this.s3Config.remotePrefix)
    ) {
      throw Error(`_writeFileFromRoot should only accept prefix-ed path`);
    }

    const bytesIn5MB = 5242880;
    const body = new Uint8Array(content);

    let contentType = DEFAULT_CONTENT_TYPE;
    contentType =
      mime.contentType(mime.lookup(key) || DEFAULT_CONTENT_TYPE) ||
      DEFAULT_CONTENT_TYPE;

    const upload = new Upload({
      client: this.s3Client,
      queueSize: this.s3Config.partsConcurrency, // concurrency
      partSize: bytesIn5MB, // minimal 5MB by default
      leavePartsOnError: false,
      params: {
        Bucket: this.s3Config.s3BucketName,
        Key: key,
        Body: body,
        ContentType: contentType,
        Metadata: {
          MTime: `${mtime / 1000.0}`,
          CTime: `${ctime / 1000.0}`,
        },
      },
    });
    upload.on("httpUploadProgress", (progress) => {
      // console.debug(progress);
    });
    await upload.done();

    return await this._statFromRoot(key);
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    if (key.endsWith("/")) {
      throw new Error(`you should not call readFile on folder ${key}`);
    }
    const downloadFile = getRemoteWithPrefixPath(
      key,
      this.s3Config.remotePrefix ?? ""
    );

    return await this._readFileFromRoot(downloadFile);
  }

  async _readFileFromRoot(key: string): Promise<ArrayBuffer> {
    if (
      this.s3Config.remotePrefix !== undefined &&
      this.s3Config.remotePrefix !== "" &&
      !key.startsWith(this.s3Config.remotePrefix)
    ) {
      throw Error(`_readFileFromRoot should only accept prefix-ed path`);
    }
    const data = await this.s3Client.send(
      new GetObjectCommand({
        Bucket: this.s3Config.s3BucketName,
        Key: key,
      })
    );
    const bodyContents = await getObjectBodyToArrayBuffer(data.Body);
    return bodyContents;
  }

  async rename(key1: string, key2: string): Promise<void> {
    throw Error(`rename not implemented for s3`);
  }

  supportsRename(): boolean { return false; }

  async rm(key: string): Promise<void> {
    if (key === "/") {
      return;
    }

    if (key.endsWith("/")) {
      if (Object.prototype.hasOwnProperty.call(this.synthFoldersCache, key)) {
        delete this.synthFoldersCache[key];
        return;
      }

      // in s3 the folder may not exist, so we make our best effort.
      // do NOT read this.s3Config.generateFolderObject
      // because the folder might be generated by previous setting
      try {
        const remoteFileName = getRemoteWithPrefixPath(
          key,
          this.s3Config.remotePrefix ?? ""
        );

        await this.s3Client.send(
          new DeleteObjectCommand({
            Bucket: this.s3Config.s3BucketName,
            Key: remoteFileName,
          })
        );
      } catch (e) {
        // pass
      }
    } else {
      const remoteFileName = getRemoteWithPrefixPath(
        key,
        this.s3Config.remotePrefix ?? ""
      );

      await this.s3Client.send(
        new DeleteObjectCommand({
          Bucket: this.s3Config.s3BucketName,
          Key: remoteFileName,
        })
      );
    }

    // TODO: do we need to delete folder recursively?
    // maybe we should not
    // because the outer sync algorithm should do that
    // (await this._walkFromRoot(remoteFileName)).map(...)
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    try {
      // const results = await this.s3Client.send(
      //   new HeadBucketCommand({ Bucket: this.s3Config.s3BucketName })
      // );
      // very simplified version of listing objects
      const confCmd = {
        Bucket: this.s3Config.s3BucketName,
      } as ListObjectsV2CommandInput;
      const results = await this.s3Client.send(
        new ListObjectsV2Command(confCmd)
      );

      if (
        results === undefined ||
        results.$metadata === undefined ||
        results.$metadata.httpStatusCode === undefined
      ) {
        throw Error("results or $metadata or httStatusCode is undefined");
      }
      if (results.$metadata.httpStatusCode !== 200) {
        throw Error(`not 200 httpStatusCode`);
      }
    } catch (err: unknown) {
      console.debug(err);
      if (callbackFunc !== undefined) {
        if (this.s3Config.s3Endpoint.contains(this.s3Config.s3BucketName)) {
          const wrapped = err instanceof Error ? err : new Error(String(err));
          const err2 = new AggregateError([
            wrapped,
            new Error(
              "Maybe you've included the bucket name inside the endpoint setting. Please remove the bucket name and try again."
            ),
          ]);
          callbackFunc(err2);
        } else {
          callbackFunc(err);
        }
      }
      return false;
    }

    return await this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    throw new Error("Method not implemented.");
  }

  async revokeAuth() {
    throw new Error("Method not implemented.");
  }

  allowEmptyFile(): boolean {
    return true;
  }
}

import { Buffer } from "buffer";
import { Queue } from "@fyears/tsqueue";
import { getReasonPhrase } from "http-status-codes/build/cjs/utils-functions";
import chunk from "lodash/chunk";
import cloneDeep from "lodash/cloneDeep";
import flatten from "lodash/flatten";
import { Platform, type RequestUrlParam, requestUrl } from "obsidian";
import type {
  FileStat,
  RequestOptionsWithState,
  WebDAVClient,
  // Response,
  // ResponseDataDetailed,
} from "webdav";
import type { Entity, WebdavConfig } from "./baseTypes";
import { VALID_REQURL } from "./baseTypesObs";
import { FakeFs } from "./fsAll";
import { bufferToArrayBuffer, splitFileSizeToChunkRanges } from "./misc";

/**
 * https://stackoverflow.com/questions/32850898/how-to-check-if-a-string-has-any-non-iso-8859-1-characters-with-javascript
 * @param str
 * @returns true if all are iso 8859 1 chars
 */
function onlyAscii(str: string) {
  return !/[^\u0000-\u00ff]/g.test(str);
}

/**
 * https://stackoverflow.com/questions/12539574/
 * @param obj
 * @returns
 */
function objKeyToLower(obj: Record<string, string>) {
  return Object.fromEntries(
    Object.entries(obj).map(([k, v]) => [k.toLowerCase(), v])
  );
}

// @ts-ignore
import { getPatcher } from "webdav/dist/web/index.js";
if (VALID_REQURL) {
  getPatcher().patch(
    "request",
    async (options: RequestOptionsWithState): Promise<Response> => {
      const transformedHeaders = objKeyToLower({ ...options.headers });
      delete transformedHeaders["host"];
      delete transformedHeaders["content-length"];

      const reqContentType =
        transformedHeaders["accept"] ?? transformedHeaders["content-type"];

      const retractedHeaders = { ...transformedHeaders };
      if (Object.prototype.hasOwnProperty.call(retractedHeaders, "authorization")) {
        retractedHeaders["authorization"] = "<retracted>";
      }

      // console.debug(`before request:`);
      // console.debug(`url: ${options.url}`);
      // console.debug(`method: ${options.method}`);
      // console.debug(`headers: ${JSON.stringify(retractedHeaders, null, 2)}`);
      // console.debug(`reqContentType: ${reqContentType}`);

      const p: RequestUrlParam = {
        url: options.url,
        method: options.method,
        body: options.data as string | ArrayBuffer,
        headers: transformedHeaders,
        contentType: reqContentType,
        throw: false,
      };

      let r = await requestUrl(p);

      if (
        r.status === 401 &&
        Platform.isIosApp &&
        !options.url.endsWith("/") &&
        !options.url.endsWith(".md") &&
        options.method.toUpperCase() === "PROPFIND"
      ) {
        // don't ask me why,
        // some webdav servers have some mysterious behaviours,
        // if a folder doesn't exist without slash, the servers return 401 instead of 404
        // here is a dirty hack that works
        console.debug(`so we have 401, try appending request url with slash`);
        p.url = `${options.url}/`;
        r = await requestUrl(p);
      }

      // console.debug(`after request:`);
      const rspHeaders = objKeyToLower({ ...r.headers });
      // console.debug(`rspHeaders: ${JSON.stringify(rspHeaders, null, 2)}`);
      for (const key in rspHeaders) {
        if (Object.prototype.hasOwnProperty.call(rspHeaders, key)) {
          // avoid the error:
          // Failed to read the 'headers' property from 'ResponseInit': String contains non ISO-8859-1 code point.
          // const possibleNonAscii = [
          //   "Content-Disposition",
          //   "X-Accel-Redirect",
          //   "X-Outfilename",
          //   "X-Sendfile"
          // ];
          // for (const p of possibleNonAscii) {
          //   if (key === p || key === p.toLowerCase()) {
          //     rspHeaders[key] = encodeURIComponent(rspHeaders[key]);
          //   }
          // }
          if (!onlyAscii(rspHeaders[key])) {
            // console.debug(`rspHeaders[key] needs encode: ${key}`);
            rspHeaders[key] = encodeURIComponent(rspHeaders[key]);
          }
        }
      }

      let r2: Response | undefined = undefined;
      const statusText = getReasonPhrase(r.status);
      // console.debug(`statusText: ${statusText}`);
      if ([101, 103, 204, 205, 304].includes(r.status)) {
        // A null body status is a status that is 101, 103, 204, 205, or 304.
        // https://fetch.spec.whatwg.org/#statuses
        // fix this: Failed to construct 'Response': Response with null body status cannot have body
        r2 = new Response(null, {
          status: r.status,
          statusText: statusText,
          headers: rspHeaders,
        });
      } else {
        r2 = new Response(r.arrayBuffer, {
          status: r.status,
          statusText: statusText,
          headers: rspHeaders,
        });
      }

      return r2;
    }
  );
}

// @ts-ignore
// biome-ignore lint: we want to ts-ignore the next line
import { AuthType, BufferLike, createClient } from "webdav/dist/web/index.js";

export const DEFAULT_WEBDAV_CONFIG = {
  address: "",
  username: "",
  password: "",
  authType: "basic",
  manualRecursive: true,
  depth: "manual_1",
  remoteBaseDir: "",
} as WebdavConfig;

const getWebdavPath = (fileOrFolderPath: string, remoteBaseDir: string) => {
  let key = fileOrFolderPath;
  if (fileOrFolderPath === "/" || fileOrFolderPath === "") {
    // special
    key = `/${remoteBaseDir}/`;
  } else if (fileOrFolderPath.startsWith("/")) {
    console.warn(
      `why the path ${fileOrFolderPath} starts with '/'? but we just go on.`
    );
    key = `/${remoteBaseDir}${fileOrFolderPath}`;
  } else {
    key = `/${remoteBaseDir}/${fileOrFolderPath}`;
  }
  return key;
};

/**
 * sometimes the path startswith /../../......
 * we want to make sure the path is compatible
 */
const stripLeadingPath = (x: string) => {
  let y = x;
  while (y.startsWith("/..")) {
    y = y.slice("/..".length);
  }
  return y;
};

const getNormPath = (fileOrFolderPath: string, remoteBaseDir: string) => {
  const strippedFileOrFolderPath = stripLeadingPath(fileOrFolderPath);
  if (
    !(
      strippedFileOrFolderPath === `/${remoteBaseDir}` ||
      strippedFileOrFolderPath.startsWith(`/${remoteBaseDir}/`)
    )
  ) {
    throw Error(
      `"${fileOrFolderPath}" after stripping doesn't starts with "/${remoteBaseDir}/"`
    );
  }
  const result = strippedFileOrFolderPath.slice(`/${remoteBaseDir}/`.length);
  return result;
};

const fromWebdavItemToEntity = (x: FileStat, remoteBaseDir: string): Entity => {
  let key = getNormPath(x.filename, remoteBaseDir);

  if (x.type === "directory" && !key.endsWith("/")) {
    key = `${key}/`;
  }
  const mtimeSvr = Date.parse(x.lastmod).valueOf();
  return {
    key: key,
    keyRaw: key,
    mtimeSvr: mtimeSvr,
    mtimeCli: mtimeSvr, // TODO: no universal way to set mtime in webdav
    size: x.size,
    sizeRaw: x.size,
  };
};

const tryEncodeURI = (x: string) => {
  if (x.includes("%")) {
    // likely encoded before!
    return x;
  }
  return encodeURI(x);
};

const tryEncodeUsernamePassword = (x: string) => {
  if (onlyAscii(x)) {
    return x;
  }
  return unescape(encodeURIComponent(x));
};

const parseCustomHeaders = (x: string): Record<string, string> => {
  const y = x.trim();
  if (y === "") {
    return {};
  }
  const z = y.split("\n");

  const res: Record<string, string> = {};

  for (const kv of z) {
    if (!kv.includes(":")) {
      continue;
    }

    const [keyRaw, ...valueArr] = kv.split(":");
    const key = keyRaw.trim();
    const value = valueArr.join(":").trim();
    res[key] = value;
  }

  return res;
};

export class FakeFsWebdav extends FakeFs {
  kind: "webdav";

  webdavConfig: WebdavConfig;
  remoteBaseDir: string;
  client!: WebDAVClient;
  vaultFolderExists: boolean;
  saveUpdatedConfigFunc: () => Promise<void>;

  supportApachePartial: boolean;
  supportSabrePartial: boolean;
  isNextcloud: boolean;
  nextcloudUploadServerAddress: string;

  constructor(
    webdavConfig: WebdavConfig,
    vaultName: string,
    saveUpdatedConfigFunc: () => Promise<void>
  ) {
    super();
    this.kind = "webdav";
    this.webdavConfig = cloneDeep(webdavConfig);
    this.webdavConfig.address = tryEncodeURI(this.webdavConfig.address);
    this.remoteBaseDir = this.webdavConfig.remoteBaseDir || vaultName || "";
    this.vaultFolderExists = false;
    this.saveUpdatedConfigFunc = saveUpdatedConfigFunc;

    this.supportApachePartial = false;
    this.supportSabrePartial = false;
    this.isNextcloud = false;
    this.nextcloudUploadServerAddress = "";
  }

  async _init() {
    // init client if not inited
    if (this.client !== undefined) {
      return;
    }

    const cacheHeader = {
      "Cache-Control": "no-cache",
    };
    const customHeaders = parseCustomHeaders(
      this.webdavConfig.customHeaders ?? ""
    );
    const headers = { ...cacheHeader, ...customHeaders };

    if (
      this.webdavConfig.username !== "" &&
      this.webdavConfig.password !== ""
    ) {
      this.client = createClient(this.webdavConfig.address, {
        username: tryEncodeUsernamePassword(this.webdavConfig.username),
        password: tryEncodeUsernamePassword(this.webdavConfig.password),
        headers: headers,
        authType:
          this.webdavConfig.authType === "digest"
            ? AuthType.Digest
            : AuthType.Password,
      });
    } else {
      console.debug("no password");
      this.client = createClient(this.webdavConfig.address, {
        headers: headers,
      });
    }

    // check vault folder
    if (this.vaultFolderExists) {
      // pass
    } else {
      const res = await this.client.exists(`/${this.remoteBaseDir}/`);
      if (res) {
        // console.debug("remote vault folder exits!");
        this.vaultFolderExists = true;
      } else {
        console.debug("remote vault folder not exists, creating");
        await this.client.createDirectory(`/${this.remoteBaseDir}/`);
        console.debug("remote vault folder created!");
        this.vaultFolderExists = true;
      }
    }

    // adjust depth parameter
    if (
      this.webdavConfig.depth === "auto" ||
      this.webdavConfig.depth === "auto_1" ||
      this.webdavConfig.depth === "auto_infinity" ||
      this.webdavConfig.depth === "auto_unknown"
    ) {
      this.webdavConfig.depth = "manual_1";
      this.webdavConfig.manualRecursive = true;
      if (this.saveUpdatedConfigFunc !== undefined) {
        await this.saveUpdatedConfigFunc();
        console.debug(
          `webdav depth="auto_???" is changed to ${this.webdavConfig.depth}`
        );
      }
    }

    await this._checkPartialSupport();
  }

  /**
   * <server>/remote.php/dav/files/<userid>
   * => <server>/remote.php/dav/uploads/<userid>
   */
  _getnextcloudUploadServerAddress = () => {
    let k = this.webdavConfig.address;
    if (k.endsWith("/")) {
      // no tailing slash
      k = k.substring(0, k.length - 1);
    }
    const s = k.split("/");
    if (
      s.length > 3 &&
      s[s.length - 3] === "dav" &&
      s[s.length - 2] === "files" &&
      s[s.length - 1] !== ""
    ) {
      s[s.length - 2] = "uploads";
      return s.join("/");
    }
    throw Error(`cannot construct upload address for ${s}`);
  };

  async _checkPartialSupport() {
    const compliance = await this.client.getDAVCompliance(
      `/${this.remoteBaseDir}/`
    );

    for (const c of compliance.compliance) {
      // nextcloud AND with an account
      if (
        c.toLocaleLowerCase().includes("nextcloud") &&
        this.webdavConfig.username !== "" &&
        this.webdavConfig.password !== ""
      ) {
        // the address is parsable
        const s = this.webdavConfig.address.split("/");
        if (
          s.length > 3 &&
          s[s.length - 3] === "dav" &&
          s[s.length - 2] === "files" &&
          s[s.length - 1] !== ""
        ) {
          this.isNextcloud = true;
          this.nextcloudUploadServerAddress =
            this._getnextcloudUploadServerAddress();
          console.debug(
            `isNextcloud=${this.isNextcloud}, uploadFolder=${this.nextcloudUploadServerAddress}`
          );
          return true;
        } else {
          return false;
        }
      }
    }

    // taken from https://github.com/perry-mitchell/webdav-client/blob/master/source/operations/partialUpdateFileContents.ts
    // which is under MIT license
    if (
      compliance.server.includes("Apache") &&
      compliance.compliance.includes("<http://apache.org/dav/propset/fs/1>")
    ) {
      this.supportApachePartial = true;
      console.debug(
        `supportApachePartial=true, compliance=${JSON.stringify(compliance)}`
      );
      return true;
    }

    if (compliance.compliance.includes("sabredav-partialupdate")) {
      this.supportSabrePartial = true;
      console.debug(
        `supportSabrePartial=true, compliance=${JSON.stringify(compliance)}`
      );
      return true;
    }

    return false;
  }

  async walk(): Promise<Entity[]> {
    await this._init();

    let contents = [] as FileStat[];
    if (
      this.webdavConfig.depth === "auto" ||
      this.webdavConfig.depth === "auto_unknown" ||
      this.webdavConfig.depth === "auto_1" ||
      this.webdavConfig.depth === "auto_infinity" /* don't trust auto now */ ||
      this.webdavConfig.depth === "manual_1" ||
      this.webdavConfig.address.includes("jianguoyun.com") ||
      this.webdavConfig.address.includes("teracloud.jp")
    ) {
      // the remote doesn't support infinity propfind,
      // we need to do a bfs here
      const q = new Queue([`/${this.remoteBaseDir}`]);
      const CHUNK_SIZE = 10;
      while (q.length > 0) {
        const itemsToFetch: string[] = [];
        while (q.length > 0) {
          itemsToFetch.push(q.pop()!);
        }
        const itemsToFetchChunks = chunk(itemsToFetch, CHUNK_SIZE);
        // console.debug(itemsToFetchChunks);
        const subContents = [] as FileStat[];
        for (const singleChunk of itemsToFetchChunks) {
          const r = singleChunk.map(async (x) => {
            let k = (await this.client.getDirectoryContents(x, {
              deep: false,
              details: false /* no need for verbose details here */,
              // TODO: to support .obsidian,
              // we need to load all files including dot,
              // anyway to reduce the resources?
              // glob: "/**" /* avoid dot files by using glob */,
            }));
            k = k.filter((sub) => stripLeadingPath(sub.filename) !== x);
            return k;
          });
          const r3 = await Promise.all(r);
          for (const r4 of r3) {
            if (
              this.webdavConfig.address.includes("jianguoyun.com") &&
              r4.length >= 749
            ) {
              // https://help.jianguoyun.com/?p=2064
              // no more than 750 per request
              throw Error(
                `出错：坚果云 api 有限制，文件列表加载不全。终止同步！`
              );
            }
          }
          const r2 = flatten(r3);
          subContents.push(...r2);
        }
        for (let i = 0; i < subContents.length; ++i) {
          const f = subContents[i];
          contents.push(f);
          if (f.type === "directory") {
            q.push(stripLeadingPath(f.filename));
          }
        }
      }
    } else {
      // the remote supports infinity propfind
      contents = (await this.client.getDirectoryContents(
        `/${this.remoteBaseDir}`,
        {
          deep: true,
          details: false /* no need for verbose details here */,
          // TODO: to support .obsidian,
          // we need to load all files including dot,
          // anyway to reduce the resources?
          // glob: "/**" /* avoid dot files by using glob */,
        }
      ));
    }

    const result = contents
      .map((x) => fromWebdavItemToEntity(x, this.remoteBaseDir))
      .filter((x) => x.keyRaw !== "/");
    return result;
  }

  async walkPartial(): Promise<Entity[]> {
    await this._init();

    const contents = (await this.client.getDirectoryContents(
      `/${this.remoteBaseDir}`,
      {
        deep: false, // partial, no need to recursive here
        details: false /* no need for verbose details here */,
      }
    ));
    return contents
      .map((x) => fromWebdavItemToEntity(x, this.remoteBaseDir))
      .filter((x) => x.keyRaw !== "/");
  }

  async stat(key: string): Promise<Entity> {
    await this._init();
    const fullPath = getWebdavPath(key, this.remoteBaseDir);
    return await this._statFromRoot(fullPath);
  }

  async _statFromRoot(key: string): Promise<Entity> {
    const res = (await this.client.stat(key, {
      details: false,
    })) as FileStat;
    return fromWebdavItemToEntity(res, this.remoteBaseDir);
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    if (!key.endsWith("/")) {
      throw Error(`you should not call mkdir on ${key}`);
    }
    await this._init();
    const uploadFile = getWebdavPath(key, this.remoteBaseDir);
    return await this._mkdirFromRoot(uploadFile, mtime, ctime);
  }

  async _mkdirFromRoot(
    key: string,
    mtime?: number,
    ctime?: number
  ): Promise<Entity> {
    // the sync algorithm should do recursive manually already.
    // if we set recursive: true here, Digest auth will return some error inside the PROPFIND
    await this.client.createDirectory(key, {
      recursive: false,
    });
    return await this._statFromRoot(key);
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    if (key.endsWith("/")) {
      throw Error(`you should not call writeFile on ${key}`);
    }
    await this._init();
    const uploadFile = getWebdavPath(key, this.remoteBaseDir);
    return await this._writeFileFromRoot(
      uploadFile,
      content,
      mtime,
      ctime,
      key
    );
  }

  async _writeFileFromRoot(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number,
    origKey: string
  ): Promise<Entity> {
    // less than 10 MB
    if (content.byteLength <= 10 * 1024 * 1024) {
      return await this._writeFileFromRootFull(
        key,
        content,
        mtime,
        ctime,
        origKey
      );
    }

    // larger than 10 MB
    if (
      !this.isNextcloud &&
      !this.supportApachePartial &&
      !this.supportSabrePartial
    ) {
      // give up and upload by whole, and directly return
      return await this._writeFileFromRootFull(
        key,
        content,
        mtime,
        ctime,
        origKey
      );
    }

    // try to upload by chunks
    try {
      if (this.isNextcloud) {
        return await this._writeFileFromRootNextcloud(
          key,
          content,
          mtime,
          ctime,
          origKey
        );
      } else if (this.supportApachePartial) {
        return await this._writeFileFromRootApachePartial(
          key,
          content,
          mtime,
          ctime,
          origKey
        );
      } else if (this.supportSabrePartial) {
        return await this._writeFileFromRootSabrePartial(
          key,
          content,
          mtime,
          ctime,
          origKey
        );
      }
      throw Error(`Error: partial upload / update method is not implemented??`);
    } catch (e) {
      console.error(
        `we fail to write file partially for nextcloud or apache or sabre/dav, stop!`
      );
      console.error(e);
      throw e;
      // this.isNextcloud = false;
      // this.supportApachePartial = false;
      // return await this._writeFileFromRootFull(
      //   key,
      //   content,
      //   mtime,
      //   ctime,
      //   origKey
      // );
    }
  }

  async _writeFileFromRootFull(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number,
    origKey: string
  ): Promise<Entity> {
    // console.debug(`start _writeFileFromRootFull`);
    await this.client.putFileContents(key, content, {
      overwrite: true,
      onUploadProgress: (progress: any) => {
        console.debug(`Uploaded ${progress.loaded} bytes of ${progress.total}`);
      },
    });
    const k = await this._statFromRoot(key);
    // console.debug(`end _writeFileFromRootFull`);
    return k;
  }

  /**
   * https://docs.nextcloud.com/server/latest/developer_manual/client_apis/WebDAV/chunking.html
   * @param key
   * @param content
   * @param mtime
   * @param ctime
   * @returns
   */
  async _writeFileFromRootNextcloud(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number,
    origKey: string
  ): Promise<Entity> {
    if (key.endsWith("/")) {
      throw Error(
        `key=${key} should not have tailing slash in _writeFileFromRootNextcloud`
      );
    }
    const destUrl = `${this.webdavConfig.address}/${encodeURI(key)}`;
    console.debug(`destUrl=${destUrl}`);

    const getTmpFolder = (x: string) => {
      if (x.endsWith("/")) {
        throw Error(`file to upload by chunk should not ends with /`);
      }
      const y = x.split("/");
      const z = encodeURI(`${y[y.length - 1]}`);
      return z;
    };

    const uploadServerAddress = this.nextcloudUploadServerAddress;
    console.debug(`uploadServerAddress=${uploadServerAddress}`);
    const tmpFolderName = getTmpFolder(key);
    console.debug(`tmpFolderName=${tmpFolderName}`);

    const clientForUpload = createClient(uploadServerAddress, {
      username: tryEncodeUsernamePassword(this.webdavConfig.username),
      password: tryEncodeUsernamePassword(this.webdavConfig.password),
      headers: {
        "Cache-Control": "no-cache",
      },
      authType:
        this.webdavConfig.authType === "digest"
          ? AuthType.Digest
          : AuthType.Password,
    });

    // create folder
    await clientForUpload.createDirectory(tmpFolderName, {
      method: "MKCOL",
      headers: {
        Destination: destUrl,
      },
    });
    console.debug(`finish creating folder`);

    // upload by chunks
    const sizePerChunk = 5 * 1024 * 1024; // 5 mb
    const chunkRanges = splitFileSizeToChunkRanges(
      content.byteLength,
      sizePerChunk
    );
    for (let i = 0; i < chunkRanges.length; ++i) {
      const { start, end } = chunkRanges[i];
      const tmpFileName = `${i + 1}`.padStart(5, "0");
      const tmpFileNameWithFolder = `${tmpFolderName}/${tmpFileName}`;
      console.debug(
        `start to upload chunk ${
          i + 1
        } to ${tmpFileNameWithFolder} with startInclusive=${start}, endInclusive=${end}`
      );
      await clientForUpload.putFileContents(
        tmpFileNameWithFolder,
        content.slice(start, end + 1),
        {
          headers: {
            Destination: destUrl,
            "OC-Total-Length": `${content.byteLength}`,
          },
        }
      );
    }
    console.debug(`finish upload all chunks`);

    // move to assemble
    const fakeFileToMoveUrl = `${tmpFolderName}/.file`;
    console.debug(`fakeFileToMoveUrl=${fakeFileToMoveUrl}`);
    await clientForUpload.customRequest(fakeFileToMoveUrl, {
      method: "MOVE",
      headers: {
        Destination: destUrl,
        "OC-Total-Length": `${content.byteLength}`,
      },
    });
    console.debug(`finish moving file`);
    // TODO: setting X-OC-Mtime

    // stat
    console.debug(`before stat origKey=${origKey}`);
    const k = await this.stat(origKey);
    console.debug(`after stat`);
    if (k.sizeRaw !== content.byteLength) {
      // we failed!
      this.isNextcloud = false; // give up next time!
      const err = `unable to upload file ${key} by chunks to nextcloud`;
      console.error(err);
      throw Error(err);
    }
    console.debug(`after stat, k=${JSON.stringify(k, null, 2)}`);

    return k;
  }

  async _writeFileFromRootApachePartial(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number,
    origKey: string
  ): Promise<Entity> {
    // firstly upload a 0-byte data
    await this._writeFileFromRootFull(
      key,
      new ArrayBuffer(0),
      mtime,
      ctime,
      origKey
    );

    // then "update" by chunks
    const sizePerChunk = 5 * 1024 * 1024; // 5 mb
    const chunkRanges = splitFileSizeToChunkRanges(
      content.byteLength,
      sizePerChunk
    );

    // TODO: parallel
    for (let i = 0; i < chunkRanges.length; ++i) {
      const { start, end } = chunkRanges[i];
      await this.client.partialUpdateFileContents(
        key,
        start,
        end,
        content.slice(start, end + 1)
      );
    }

    // lastly return
    return await this.stat(origKey);
  }

  async _writeFileFromRootSabrePartial(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number,
    origKey: string
  ): Promise<Entity> {
    // firstly upload a 0-byte data
    await this._writeFileFromRootFull(
      key,
      new ArrayBuffer(0),
      mtime,
      ctime,
      origKey
    );

    // then "update" by chunks
    const sizePerChunk = 5 * 1024 * 1024; // 5 mb
    const chunkRanges = splitFileSizeToChunkRanges(
      content.byteLength,
      sizePerChunk
    );

    // diff from apachePartial: we use "append" header here for dufs...
    // we cannot parallel here
    for (let i = 0; i < chunkRanges.length; ++i) {
      const { start, end } = chunkRanges[i];
      await this.client.customRequest(key, {
        method: "PATCH",
        headers: {
          "X-Update-Range": "append",
          "Content-Type": "application/x-sabredav-partialupdate",
        },
        data: content.slice(start, end + 1),
      });
    }

    // lastly return
    return await this.stat(origKey);
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    if (key.endsWith("/")) {
      throw Error(`you should not call readFile on ${key}`);
    }
    await this._init();
    const downloadFile = getWebdavPath(key, this.remoteBaseDir);
    return await this._readFileFromRoot(downloadFile);
  }

  async _readFileFromRoot(key: string): Promise<ArrayBuffer> {
    const buff = (await this.client.getFileContents(key)) as BufferLike;
    if (buff instanceof ArrayBuffer) {
      return buff;
    } else if (buff instanceof Buffer) {
      return bufferToArrayBuffer(buff) as ArrayBuffer;
    }
    throw Error(`unexpected file content result with type ${typeof buff}`);
  }

  async rename(key1: string, key2: string): Promise<void> {
    if (key1 === "/" || key2 === "/") {
      return;
    }
    const remoteFileName1 = getWebdavPath(key1, this.remoteBaseDir);
    const remoteFileName2 = getWebdavPath(key2, this.remoteBaseDir);
    await this._init();
    await this.client.moveFile(remoteFileName1, remoteFileName2);
  }

  supportsRename(): boolean { return true; }

  async rm(key: string): Promise<void> {
    if (key === "/") {
      return;
    }
    await this._init();
    try {
      const remoteFileName = getWebdavPath(key, this.remoteBaseDir);
      await this.client.deleteFile(remoteFileName);
      // console.debug(`delete ${remoteFileName} succeeded`);
    } catch (err) {
      console.error("some error while deleting");
      console.error(err);
    }
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    if (
      !(
        this.webdavConfig.address.startsWith("http://") ||
        this.webdavConfig.address.startsWith("https://")
      )
    ) {
      const err =
        "Error: the url should start with http(s):// but it does not!";
      console.error(err);
      if (callbackFunc !== undefined) {
        callbackFunc(err);
      }
      return false;
    }

    try {
      await this._init();
      const results = await this._statFromRoot(`/${this.remoteBaseDir}/`);
      if (results === undefined) {
        throw Error("cannot stat root vault folder!");
      }
    } catch (err) {
      console.error(err);
      callbackFunc?.(err);
      return false;
    }

    return await this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    throw new Error("Method not implemented.");
  }

  async revokeAuth() {
    throw new Error("Method not implemented.");
  }

  allowEmptyFile(): boolean {
    return true;
  }
}

import { isEqual } from "lodash";
import { requestUrl } from "obsidian";
import {
  DEFAULT_CONTENT_TYPE,
  type Entity,
  type WebdisConfig,
} from "./baseTypes";
import { FakeFs } from "./fsAll";

export const DEFAULT_WEBDIS_CONFIG: WebdisConfig = {
  address: "",
  username: "",
  password: "",
  remoteBaseDir: "",
};

const getWebdisPath = (fileOrFolderPath: string, remoteBaseDir: string) => {
  let key = fileOrFolderPath;
  if (fileOrFolderPath === "/" || fileOrFolderPath === "") {
    // special
    key = `${remoteBaseDir}`;
  } else if (fileOrFolderPath.startsWith("/")) {
    console.warn(
      `why the path ${fileOrFolderPath} starts with '/'? but we just go on.`
    );
    key = `${remoteBaseDir}${fileOrFolderPath}`;
  } else {
    key = `${remoteBaseDir}/${fileOrFolderPath}`;
  }
  return `rs:fs:v1:${encodeURIComponent(key)}`; // we should encode them!!!!
};

export const getOrigPath = (fullKey: string, remoteBaseDir: string) => {
  const fullKeyDecoded = decodeURIComponent(fullKey);
  const prefix = `rs:fs:v1:${remoteBaseDir}/`;
  // console.debug(`prefix=${prefix}`);
  const suffix1 = ":meta";
  const suffix2 = ":content";
  if (!fullKeyDecoded.startsWith(prefix)) {
    throw Error(`you should not call getOrigEntity on ${fullKey}`);
  }
  let realKey = fullKeyDecoded.slice(prefix.length);
  // console.debug(`realKey=${realKey}`);
  if (realKey.endsWith(suffix1)) {
    realKey = realKey.slice(0, -suffix1.length);
    // console.debug(`realKey=${realKey}`);
  } else if (realKey.endsWith(suffix2)) {
    realKey = realKey.slice(0, -suffix2.length);
    // console.debug(`realKey=${realKey}`);
  }
  // console.debug(`fullKey=${fullKey}, realKey=${realKey}`);
  return realKey;
};

export class FakeFsWebdis extends FakeFs {
  kind: "webdis";
  webdisConfig: WebdisConfig;
  remoteBaseDir: string;
  saveUpdatedConfigFunc: () => Promise<void>;

  constructor(
    webdisConfig: WebdisConfig,
    vaultName: string,
    saveUpdatedConfigFunc: () => Promise<void>
  ) {
    super();
    this.kind = "webdis";
    this.webdisConfig = webdisConfig;
    this.remoteBaseDir = this.webdisConfig.remoteBaseDir || vaultName || "";
    this.saveUpdatedConfigFunc = saveUpdatedConfigFunc;
  }

  async _fetchCommand(
    method: "GET" | "POST" | "PUT",
    urlPath: string,
    content?: ArrayBuffer
  ) {
    const address = this.webdisConfig.address;
    if (!address.startsWith(`https://`) && !address.startsWith(`http://`)) {
      throw Error(
        `your webdis server address should start with https:// or http://`
      );
    }
    if (address.endsWith("/")) {
      throw Error(`your webdis server should not ends with /`);
    }

    if (content !== undefined && method !== "PUT") {
      throw Error(`you can only "POST" ArrayBuffer, not using other methods`);
    }

    const fullUrl = `${address}/${urlPath}`;
    // console.debug(`fullUrl=${fullUrl}`)

    const username = this.webdisConfig.username ?? "";
    const password = this.webdisConfig.password ?? "";
    if (username !== "" && password !== "") {
      return await requestUrl({
        url: fullUrl,
        method,
        headers: {
          Authorization: "Basic " + btoa(username + ":" + password),
        },
        body: content,
        throw: false,
      });
    } else if (username === "" && password === "") {
      return await requestUrl({
        url: fullUrl,
        method,
        body: content,
        throw: false,
      });
    } else {
      throw Error(
        `your username and password should both be empty or not empty!`
      );
    }
  }

  async walk(): Promise<Entity[]> {
    let cursor = "0";
    const res: Entity[] = [];
    do {
      const command = `SCAN/${cursor}/MATCH/rs:fs:v1:${encodeURIComponent(this.remoteBaseDir + "/")}*:meta/COUNT/1000`;
      const rsp = (await (await this._fetchCommand("GET", command)).json)[
        "SCAN"
      ];
      // console.debug(rsp);
      cursor = rsp[0];
      for (const fullKeyWithMeta of rsp[1]) {
        const realKey = getOrigPath(fullKeyWithMeta, this.remoteBaseDir);
        res.push(await this.stat(realKey));
      }
    } while (cursor !== "0");
    // console.debug(`walk res:`);
    // console.debug(res);
    return res;
  }

  async walkPartial(): Promise<Entity[]> {
    let cursor = "0";
    const res: Entity[] = [];
    const command = `SCAN/${cursor}/MATCH/rs:fs:v1:${encodeURIComponent(this.remoteBaseDir + "/")}*:meta/COUNT/10`; // fewer keys
    const rsp = (await (await this._fetchCommand("GET", command)).json)[
      "SCAN"
    ];
    // console.debug(rsp);
    cursor = rsp[0];
    for (const fullKeyWithMeta of rsp[1]) {
      const realKey = getOrigPath(fullKeyWithMeta, this.remoteBaseDir);
      res.push(await this.stat(realKey));
    }
    // no need to loop over cursor
    // console.debug(`walk res:`);
    // console.debug(res);
    return res;
  }

  async stat(key: string): Promise<Entity> {
    const fullKey = getWebdisPath(key, this.remoteBaseDir);
    return await this._statFromRaw(fullKey);
  }

  async _statFromRaw(key: string): Promise<Entity> {
    // console.debug(`_statFromRaw on ${key}`);
    const command = `HGETALL/${key}:meta`;
    const rsp = (await (await this._fetchCommand("GET", command)).json)[
      "HGETALL"
    ];
    // console.debug(`rsp: ${JSON.stringify(rsp, null, 2)}`);
    if (isEqual(rsp, {})) {
      // empty!
      throw Error(`key ${key} doesn't exist!`);
    }
    const realKey = getOrigPath(key, this.remoteBaseDir);
    return {
      key: realKey,
      keyRaw: realKey,
      mtimeCli: Number.parseInt(rsp["mtime"]),
      mtimeSvr: Number.parseInt(rsp["mtime"]),
      size: Number.parseInt(rsp["size"]),
      sizeRaw: Number.parseInt(rsp["size"]),
    };
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    let command = `HSET/${getWebdisPath(key, this.remoteBaseDir)}:meta/size/0`;
    if (mtime !== undefined && mtime !== 0) {
      command = `${command}/mtime/${mtime}`;
    }
    if (ctime !== undefined && ctime !== 0) {
      command = `${command}/ctime/${ctime}`;
    }
    const rsp = (await (await this._fetchCommand("GET", command)).json)[
      "HSET"
    ];
    return await this.stat(key);
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    const fullKey = getWebdisPath(key, this.remoteBaseDir);

    // meta
    let command1 = `HSET/${fullKey}:meta/size/${content.byteLength}`;
    if (mtime !== undefined && mtime !== 0) {
      command1 = `${command1}/mtime/${mtime}`;
    }
    if (ctime !== undefined && ctime !== 0) {
      command1 = `${command1}/ctime/${ctime}`;
    }
    const rsp1 = (await (await this._fetchCommand("GET", command1)).json)[
      "HSET"
    ];

    // content
    const command2 = `SET/${fullKey}:content`;
    const rsp2 = (
      await (await this._fetchCommand("PUT", command2, content)).json
    )["SET"];

    // fetch meta
    return await this.stat(key);
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    const fullKey = getWebdisPath(key, this.remoteBaseDir);
    const command = `GET/${fullKey}:content?type=${DEFAULT_CONTENT_TYPE}`;
    const rsp = await (await this._fetchCommand("GET", command)).arrayBuffer;
    return rsp;
  }

  async rename(key1: string, key2: string): Promise<void> {
    const fullKey1 = getWebdisPath(key1, this.remoteBaseDir);
    const fullKey2 = getWebdisPath(key2, this.remoteBaseDir);
    const commandContent = `RENAME/${fullKey1}:content/${fullKey2}:content`;
    await this._fetchCommand("POST", commandContent);
    const commandMeta = `RENAME/${fullKey1}:meta/${fullKey2}:meta`;
    await this._fetchCommand("POST", commandMeta);
  }

  async rm(key: string): Promise<void> {
    const fullKey = getWebdisPath(key, this.remoteBaseDir);
    const command = `DEL/${fullKey}:meta/${fullKey}:content`;
    const rsp = (await (await this._fetchCommand("PUT", command)).json)[
      "DEL"
    ];
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    try {
      const k = (
        await this._fetchCommand("GET", "PING/helloworld")
      ).json;
      if (!isEqual(k, { PING: "helloworld" })) {
        throw Error(`no correct ping response`);
      }
    } catch (err: unknown) {
      console.error(err);
      callbackFunc?.(err);
      return false;
    }
    return await this.checkConnectCommonOps(callbackFunc);
    // return true;
  }

  async getUserDisplayName(): Promise<string> {
    return this.webdisConfig.username || "<no usernme>";
  }

  async revokeAuth(): Promise<void> {
    throw new Error("Method not implemented.");
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return true;
  }
}

/**
 * BYOC — Yandex Disk Filesystem Adapter
 * Clean-room implementation using Yandex Disk REST API v1.
 * OAuth2 authorization code flow with silent token refresh.
 */

import { request } from "obsidian";
import {
  COMMAND_CALLBACK_YANDEXDISK,
  YANDEXDISK_CLIENT_ID,
  YANDEXDISK_CLIENT_SECRET,
  type Entity,
  type YandexDiskConfig,
} from "./baseTypes";
import { FakeFs } from "./fsAll";
import { retryFetch } from "./misc";

const YANDEX_API = "https://cloud-api.yandex.net/v1/disk";
const YANDEX_AUTH_URL = "https://oauth.yandex.com/authorize";
const YANDEX_TOKEN_URL = "https://oauth.yandex.com/token";
const REDIRECT_URI = `obsidian://${COMMAND_CALLBACK_YANDEXDISK}`;

export const DEFAULT_YANDEXDISK_CONFIG: YandexDiskConfig = {
  accessToken: "",
  accessTokenExpiresInMs: 0,
  accessTokenExpiresAtTimeMs: 0,
  refreshToken: "",
  remoteBaseDir: "",
  credentialsShouldBeDeletedAtTimeMs: 0,
  scope: "cloud_api:disk.app_folder cloud_api:disk.read cloud_api:disk.write",
  kind: "yandexdisk",
};

////////////////////////////////////////////////////////////////////////////////
// OAuth2 Helpers
////////////////////////////////////////////////////////////////////////////////

export function generateAuthUrl(): string {
  const params = new URLSearchParams({
    response_type: "code",
    client_id: YANDEXDISK_CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    force_confirm: "yes",
  });
  return `${YANDEX_AUTH_URL}?${params.toString()}`;
}

export async function sendAuthReq(
  code: string,
  errorCallBack: (e: unknown) => Promise<void>
): Promise<any> {
  try {
    const rsp = await request({
      url: YANDEX_TOKEN_URL,
      method: "POST",
      contentType: "application/x-www-form-urlencoded",
      body: new URLSearchParams({
        grant_type: "authorization_code",
        code: code,
        client_id: YANDEXDISK_CLIENT_ID,
        client_secret: YANDEXDISK_CLIENT_SECRET,
        redirect_uri: REDIRECT_URI,
      }).toString(),
    });
    return JSON.parse(rsp);
  } catch (e) {
    console.error(e);
    await errorCallBack(e);
  }
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any -- external OAuth response shape
async function refreshAccessToken(refreshToken: string): Promise<any> {
  const rsp = await request({
    url: YANDEX_TOKEN_URL,
    method: "POST",
    contentType: "application/x-www-form-urlencoded",
    body: new URLSearchParams({
      grant_type: "refresh_token",
      refresh_token: refreshToken,
      client_id: YANDEXDISK_CLIENT_ID,
      client_secret: YANDEXDISK_CLIENT_SECRET,
    }).toString(),
  });
  return JSON.parse(rsp);
}

export async function setConfigBySuccessfullAuthInplace(
  config: YandexDiskConfig,
  authRes: Record<string, unknown>,
  saveFunc: () => Promise<void>
): Promise<void> {
  const r = authRes as unknown as { access_token: string; refresh_token?: string; expires_in?: number };
  config.accessToken = r.access_token;
  config.refreshToken = r.refresh_token || config.refreshToken;
  config.accessTokenExpiresInMs = (r.expires_in ?? 31536000) * 1000;
  config.accessTokenExpiresAtTimeMs =
    Date.now() + (r.expires_in ?? 31536000) * 1000 - 300_000;
  config.credentialsShouldBeDeletedAtTimeMs = 0;
  await saveFunc();
}

////////////////////////////////////////////////////////////////////////////////
// Path Helpers
////////////////////////////////////////////////////////////////////////////////

function getRemotePath(key: string, remoteBaseDir: string): string {
  if (!key || key === "/") return `disk:/${remoteBaseDir}`;
  const clean = key.endsWith("/") ? key.slice(0, -1) : key;
  return `disk:/${remoteBaseDir}/${clean}`;
}

function normalizeKey(path: string, remoteBaseDir: string): string {
  const prefix = `disk:/${remoteBaseDir}/`;
  if (path.startsWith(prefix)) {
    return path.slice(prefix.length);
  }
  const prefix2 = `disk:/${remoteBaseDir}`;
  if (path === prefix2) return "";
  return path;
}

////////////////////////////////////////////////////////////////////////////////
// The Client
////////////////////////////////////////////////////////////////////////////////

export class FakeFsYandexDisk extends FakeFs {
  kind = "yandexdisk";
  private config: YandexDiskConfig;
  private vaultName: string;
  private saveFunc: () => Promise<void>;
  private remoteBaseDir: string;

  constructor(
    config: YandexDiskConfig,
    vaultName: string,
    saveFunc: () => Promise<void>
  ) {
    super();
    this.config = config;
    this.vaultName = vaultName;
    this.saveFunc = saveFunc;
    this.remoteBaseDir = config.remoteBaseDir || vaultName || "";
  }

  private async ensureToken(): Promise<string> {
    if (!this.config.accessToken) {
      throw Error("[BYOC] Yandex Disk: not authorized.");
    }

    // Yandex tokens last a very long time (up to 1 year)
    // but we still refresh if we have a refresh token and it's expiring
    if (
      this.config.refreshToken &&
      this.config.accessTokenExpiresAtTimeMs > 0 &&
      this.config.accessTokenExpiresAtTimeMs < Date.now()
    ) {
      const res = await refreshAccessToken(this.config.refreshToken);
      if (res.error) {
        throw Error(`[BYOC] Yandex refresh error: ${res.error_description}`);
      }
      this.config.accessToken = res.access_token;
      if (res.refresh_token) this.config.refreshToken = res.refresh_token;
      this.config.accessTokenExpiresAtTimeMs =
        Date.now() + (res.expires_in ?? 31536000) * 1000 - 300_000;
      await this.saveFunc();
    }

    return this.config.accessToken;
  }




  private async _getJson(url: string): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${YANDEX_API}${url}`;
    return JSON.parse(
      await request({
        url: fullUrl,
        method: "GET",
        headers: { Authorization: `OAuth ${token}` },
      })
    );
  }




  private async _put(url: string, body?: any): Promise<any> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${YANDEX_API}${url}`;
    const opts: any = {
      url: fullUrl,
      method: "PUT",
      headers: { Authorization: `OAuth ${token}` },
    };
    if (body) {
      opts.contentType = "application/json";
      opts.body = JSON.stringify(body);
    }
    const rsp = await request(opts);
    return rsp ? JSON.parse(rsp) : {};
  }

  private async _delete(url: string): Promise<void> {
    const token = await this.ensureToken();
    const fullUrl = url.startsWith("http") ? url : `${YANDEX_API}${url}`;
    await request({
      url: fullUrl,
      method: "DELETE",
      headers: { Authorization: `OAuth ${token}` },
    });
  }

  private async ensureBaseDir(): Promise<void> {
    try {
      await this._getJson(
        `/resources?path=${encodeURIComponent(`disk:/${this.remoteBaseDir}`)}`
      );
    } catch {
      // Create base dir
      await this._put(
        `/resources?path=${encodeURIComponent(`disk:/${this.remoteBaseDir}`)}`
      );
    }
  }

  async listFoldersAtRoot(): Promise<string[]> {
    const res = await this._getJson(
      `/resources?path=${encodeURIComponent("disk:/")}&limit=1000&fields=_embedded.items.name,_embedded.items.type`
    );
    return (res._embedded?.items || [])
      .filter((item: any) => item.type === "dir")
      .map((item: any) => item.name as string)
      .sort((a: string, b: string) => a.localeCompare(b));
  }

  async createFolderAtRoot(name: string): Promise<void> {
    await this._put(
      `/resources?path=${encodeURIComponent(`disk:/${name}`)}`
    );
  }

  async walk(): Promise<Entity[]> {
    await this.ensureBaseDir();

    const entities: Entity[] = [];
    let offset = 0;
    const limit = 1000;

    while (true) {
      const path = encodeURIComponent(`disk:/${this.remoteBaseDir}`);
      const res = await this._getJson(
        `/resources?path=${path}&limit=${limit}&offset=${offset}&fields=_embedded.items.path,_embedded.items.type,_embedded.items.size,_embedded.items.modified,_embedded.items.created,_embedded.total`
      );

      // Yandex Disk /resources returns embedded items for folders
      // We need to use /resources/files for a flat listing
      break; // We'll use the flat files endpoint instead
    }

    // Use flat file listing — much more efficient
    let flatOffset = 0;
    while (true) {
      const res = await this._getJson(
        `/resources/files?limit=${limit}&offset=${flatOffset}&fields=items.path,items.type,items.size,items.modified,items.created`
      );
      const items = res.items || [];

      for (const item of items) {
        let key = normalizeKey(item.path, this.remoteBaseDir);
        if (!key) continue;
        // Filter out items not under our base dir
        if (
          !item.path.startsWith(`disk:/${this.remoteBaseDir}/`) &&
          item.path !== `disk:/${this.remoteBaseDir}`
        ) {
          continue;
        }

        const isFolder = item.type === "dir";
        if (isFolder && !key.endsWith("/")) key = `${key}/`;

        const mtime = item.modified ? new Date(item.modified).getTime() : 0;
        const ctime = item.created ? new Date(item.created).getTime() : mtime;

        entities.push({
          key, keyRaw: key,
          mtimeSvr: mtime, mtimeCli: mtime, ctimeCli: ctime,
          size: isFolder ? 0 : (item.size ?? 0),
          sizeRaw: isFolder ? 0 : (item.size ?? 0),
        });
      }

      flatOffset += items.length;
      if (items.length < limit) break;
    }

    // Also list folders recursively
    await this.walkFolders(
      `disk:/${this.remoteBaseDir}`,
      entities
    );

    return entities;
  }

  private async walkFolders(
    folderPath: string,
    entities: Entity[]
  ): Promise<void> {
    const res = await this._getJson(
      `/resources?path=${encodeURIComponent(folderPath)}&limit=1000&fields=_embedded.items.path,_embedded.items.type,_embedded.items.size,_embedded.items.modified,_embedded.items.created`
    );

    const items = res._embedded?.items || [];
    for (const item of items) {
      if (item.type === "dir") {
        let key = normalizeKey(item.path, this.remoteBaseDir);
        if (key && !key.endsWith("/")) key = `${key}/`;
        if (key) {
          const mtime = item.modified ? new Date(item.modified).getTime() : 0;
          entities.push({
            key, keyRaw: key,
            mtimeSvr: mtime, size: 0, sizeRaw: 0,
          });
        }
        // Recurse into subfolder
        await this.walkFolders(item.path, entities);
      }
    }
  }

  async walkPartial(): Promise<Entity[]> {
    return this.walk();
  }

  async stat(key: string): Promise<Entity> {
    const remotePath = getRemotePath(key, this.remoteBaseDir);
    const res = await this._getJson(
      `/resources?path=${encodeURIComponent(remotePath)}&fields=path,type,size,modified,created`
    );

    const isFolder = res.type === "dir";
    let normalKey = normalizeKey(res.path, this.remoteBaseDir);
    if (isFolder && !normalKey.endsWith("/")) normalKey = `${normalKey}/`;

    const mtime = res.modified ? new Date(res.modified).getTime() : 0;
    const ctime = res.created ? new Date(res.created).getTime() : mtime;

    return {
      key: normalKey, keyRaw: normalKey,
      mtimeSvr: mtime, mtimeCli: mtime, ctimeCli: ctime,
      size: isFolder ? 0 : (res.size ?? 0),
      sizeRaw: isFolder ? 0 : (res.size ?? 0),
    };
  }

  async mkdir(key: string, mtime?: number, ctime?: number): Promise<Entity> {
    const remotePath = getRemotePath(key, this.remoteBaseDir);
    try {
      await this._put(
        `/resources?path=${encodeURIComponent(remotePath)}`
      );
    } catch (e: unknown) {
      // 409 = already exists, that's fine
      if (!String(e).includes("409")) throw e;
    }
    return { key, keyRaw: key, size: 0, sizeRaw: 0 };
  }

  async writeFile(
    key: string,
    content: ArrayBuffer,
    mtime: number,
    ctime: number
  ): Promise<Entity> {
    const remotePath = getRemotePath(key, this.remoteBaseDir);

    // Step 1: Get upload URL from Yandex
    const uploadInfo = await this._getJson(
      `/resources/upload?path=${encodeURIComponent(remotePath)}&overwrite=true`
    );

    if (!uploadInfo.href) {
      throw Error(`[BYOC] Yandex: no upload URL returned for '${key}'`);
    }

    // Step 2: PUT the content to the upload URL (no auth header needed)
    const resp = await retryFetch(uploadInfo.href, {
      method: "PUT",
      body: content,
      headers: { "Content-Type": "application/octet-stream" },
    });

    if (!resp.ok) {
      throw Error(`[BYOC] Yandex: upload failed for '${key}': ${resp.status}`);
    }

    return {
      key, keyRaw: key,
      mtimeCli: mtime, ctimeCli: ctime,
      size: content.byteLength,
      sizeRaw: content.byteLength,
    };
  }

  async readFile(key: string): Promise<ArrayBuffer> {
    const remotePath = getRemotePath(key, this.remoteBaseDir);

    // Step 1: Get download URL
    const downloadInfo = await this._getJson(
      `/resources/download?path=${encodeURIComponent(remotePath)}`
    );

    if (!downloadInfo.href) {
      throw Error(`[BYOC] Yandex: no download URL returned for '${key}'`);
    }

    // Step 2: Download the content
    const resp = await retryFetch(downloadInfo.href);
    if (!resp.ok) {
      throw Error(`[BYOC] Yandex: download failed for '${key}': ${resp.status}`);
    }
    return resp.arrayBuffer();
  }

  async rename(key1: string, key2: string): Promise<void> {
    const from = getRemotePath(key1, this.remoteBaseDir);
    const to = getRemotePath(key2, this.remoteBaseDir);
    await this._postMove(from, to);
  }

  private async _postMove(from: string, to: string): Promise<void> {
    const token = await this.ensureToken();
    await request({
      url: `${YANDEX_API}/resources/move?from=${encodeURIComponent(from)}&path=${encodeURIComponent(to)}&overwrite=true`,
      method: "POST",
      headers: { Authorization: `OAuth ${token}` },
    });
  }

  async rm(key: string): Promise<void> {
    const remotePath = getRemotePath(key, this.remoteBaseDir);
    try {
      await this._delete(
        `/resources?path=${encodeURIComponent(remotePath)}&permanently=true`
      );
    } catch (e: unknown) {
      // 404 = already gone
      if (!String(e).includes("404")) throw e;
    }
  }

  async checkConnect(callbackFunc?: (err: unknown) => unknown): Promise<boolean> {
    return this.checkConnectCommonOps(callbackFunc);
  }

  async getUserDisplayName(): Promise<string> {
    const res = await this._getJson("");
    return res.user?.display_name || res.user?.login || "Yandex Disk User";
  }

  async revokeAuth(): Promise<void> {
    this.config.accessToken = "";
    this.config.refreshToken = "";
    await this.saveFunc();
  }

  supportsRename(): boolean { return true; }

  allowEmptyFile(): boolean {
    return true;
  }
}

import merge from "lodash/merge";
import Mustache from "mustache";
import { moment } from "obsidian";

import { LANGS as LANGS_BASIC } from "./langs";

// BYOC: No pro-specific i18n strings. Uses only base langs.
const LANGS = LANGS_BASIC;


export type LangType = keyof typeof LANGS;
export type LangTypeAndAuto = LangType | "auto";
export type TransItemType = keyof (typeof LANGS)["en"];

export class I18n {
  lang: LangTypeAndAuto;
  readonly saveSettingFunc: (tolang: LangTypeAndAuto) => Promise<void>;
  constructor(
    lang: LangTypeAndAuto,
    saveSettingFunc: (tolang: LangTypeAndAuto) => Promise<void>
  ) {
    this.lang = lang;
    this.saveSettingFunc = saveSettingFunc;
  }
  async changeTo(anotherLang: LangTypeAndAuto) {
    this.lang = anotherLang;
    await this.saveSettingFunc(anotherLang);
  }

  _get(key: TransItemType) {
    let realLang = this.lang;
    if (this.lang === "auto" && moment.locale().replace("-", "_") in LANGS) {
      realLang = moment.locale().replace("-", "_") as LangType;
    } else {
      realLang = "en";
    }

    const localVal = (LANGS[realLang] as (typeof LANGS)["en"])[key];
    const enVal = LANGS["en"][key];
    const res: string = localVal !== undefined ? localVal : (enVal !== undefined ? enVal : key);
    return res;
  }

  t(key: TransItemType, vars?: Record<string, string>) {
    if (vars === undefined) {
      return this._get(key);
    }
    return Mustache.render(this._get(key), vars);
  }
}

import cloneDeep from "lodash/cloneDeep";
import QRCode from "qrcode";
// BYOC: onedrivefull shrinker — stub until provider is implemented in Batch 3
const getShrinkedSettingsOnedriveFull = (config: any) => cloneDeep(config);
import {
  COMMAND_URI,
  COMMAND_URI_LEGACY,
  type QRExportType,
  type BYOCPluginSettings,
  type UriParams,
} from "./baseTypes";
import { getShrinkedSettings as getShrinkedSettingsOnedrive } from "./fsOnedrive";

export const exportQrCodeUri = async (
  settings: BYOCPluginSettings,
  currentVaultName: string,
  pluginVersion: string,
  exportFields: QRExportType
) => {
  let settings2: Partial<BYOCPluginSettings> = {};

  if (exportFields === "basic_and_advanced") {
    settings2 = cloneDeep(settings);
    delete settings2.s3;
    delete settings2.dropbox;
    delete settings2.onedrive;
    delete settings2.onedrivefull;
    delete settings2.webdav;
    delete settings2.webdis;
    delete settings2.googledrive;
    delete settings2.box;
    delete settings2.pcloud;
    delete settings2.yandexdisk;
    delete settings2.koofr;
    delete settings2.azureblobstorage;
    delete settings2.pro;
  } else if (exportFields === "s3") {
    settings2 = { s3: cloneDeep(settings.s3) };
  } else if (exportFields === "dropbox") {
    settings2 = { dropbox: cloneDeep(settings.dropbox) };
  } else if (exportFields === "onedrive") {
    settings2 = { onedrive: getShrinkedSettingsOnedrive(settings.onedrive) };
  } else if (exportFields === "onedrivefull") {
    settings2 = {
      onedrivefull: getShrinkedSettingsOnedriveFull(settings.onedrivefull),
    };
  } else if (exportFields === "webdav") {
    settings2 = { webdav: cloneDeep(settings.webdav) };
  } else if (exportFields === "webdis") {
    settings2 = { webdis: cloneDeep(settings.webdis) };
  } else if (exportFields === "googledrive") {
    settings2 = { googledrive: cloneDeep(settings.googledrive) };
  } else if (exportFields === "box") {
    settings2 = { box: cloneDeep(settings.box) };
  } else if (exportFields === "pcloud") {
    settings2 = { pcloud: cloneDeep(settings.pcloud) };
  } else if (exportFields === "yandexdisk") {
    settings2 = { yandexdisk: cloneDeep(settings.yandexdisk) };
  } else if (exportFields === "koofr") {
    settings2 = { koofr: cloneDeep(settings.koofr) };
  } else if (exportFields === "azureblobstorage") {
    settings2 = { azureblobstorage: cloneDeep(settings.azureblobstorage) };
  }

  delete settings2.vaultRandomID;
  const data = encodeURIComponent(JSON.stringify(settings2));
  const vault = encodeURIComponent(currentVaultName);
  const version = encodeURIComponent(pluginVersion);
  const rawUri = `obsidian://${COMMAND_URI}?func=settings&version=${version}&vault=${vault}&data=${data}`;
  // console.debug(uri)
  const imgUri = await QRCode.toDataURL(rawUri);
  return {
    rawUri,
    imgUri,
  };
};

export interface ProcessQrCodeResultType {
  status: "error" | "ok";
  message: string;
  result?: BYOCPluginSettings;
}

/**
 * we also support directly parse the uri, instead of relying on web browser
 * @param input
 */
export const parseUriByHand = (input: string) => {
  if (
    !input.startsWith(`obsidian://${COMMAND_URI}?func=settings&`) &&
    !input.startsWith(`obsidian://${COMMAND_URI_LEGACY}?func=settings&`)
  ) {
    throw Error(`not valid string`);
  }

  const k = new URL(input);
  const output = Object.fromEntries(k.searchParams);
  return output;
};

export const importQrCodeUri = (
  inputParams: any,
  currentVaultName: string
): ProcessQrCodeResultType => {
  const params = inputParams as UriParams;
  if (
    params.func === undefined ||
    params.func !== "settings" ||
    params.vault === undefined ||
    params.data === undefined
  ) {
    return {
      status: "error",
      message: `the uri is not for exporting/importing settings: ${JSON.stringify(
        inputParams
      )}`,
    };
  }

  if (params.vault !== currentVaultName) {
    return {
      status: "error",
      message: `the target vault is ${
        params.vault
      } but you are currently in ${currentVaultName}: ${JSON.stringify(
        inputParams
      )}`,
    };
  }

  let settings = {} as BYOCPluginSettings;
  try {
    settings = JSON.parse(params.data);
  } catch (e) {
    return {
      status: "error",
      message: `errors while parsing settings: ${JSON.stringify(inputParams)}`,
    };
  }
  return {
    status: "ok",
    message: "ok",
    result: settings,
  };
};

