  /**
   * Attempt to inject the sync button into Obsidian's mobile bottom navbar
   * (.mobile-navbar > .mobile-navbar-actions). Placed immediately BEFORE
   * the rightmost three-dot menu button so it lines up with the other
   * navbar actions (back, forward, quick-switcher, new-tab, tabs, menu).
   *
   * If the menu button isn't present yet (rare race where the row is
   * mid-render), we append to the actions row instead so the user still
   * gets a button this frame; a later mutation can re-anchor if needed.
   */
  private _tryInjectSyncButton(btn: HTMLElement): boolean {
    const actions = activeDocument.querySelector(".mobile-navbar-actions");
    if (!actions) return false;

    const menuBtn = actions.querySelector(".mobile-navbar-action-menu");
    if (menuBtn) {
      actions.insertBefore(btn, menuBtn);
    } else {
      actions.appendChild(btn);
    }
    console.debug("[BYOC] Mobile sync button: injected into mobile navbar");
    return true;
  }

  /**
   * Mobile resume sync — fires sync when the app returns from background.
   *
   * Covers two mobile lifecycle scenarios:
   *   1. Suspend → resume: `visibilitychange` fires (document was hidden, becomes visible).
   *   2. Kill → cold start: document is already visible at registration time.
   *      Handled by an onLayoutReady fallback, only if initRunAfterMilliseconds is off.
   *
   * Uses "manual" trigger so errors surface as notices (users opened the app intentionally).
   * 3s debounce absorbs iOS radio re-association and WebView focus flicker.
   */
  enableSyncOnMobileResume() {
    if (!Platform.isMobile) return;

    console.debug("[BYOC] Mobile resume sync: registering visibilitychange handler");

    const RESUME_DEBOUNCE_MS = 3000;
    let resumeTimer: number | undefined;

    const triggerSync = () => {
      activeWindow.clearTimeout(resumeTimer);
      resumeTimer = activeWindow.setTimeout(() => {
        if (!this.isSyncing) {
          console.debug("[BYOC] Mobile resume sync: triggering syncRun");
          this.syncRun("manual");
        }
      }, RESUME_DEBOUNCE_MS);
    };

    // Scenario 1: suspend → resume
    const handler = () => {
      if (activeDocument.visibilityState !== "visible") return;
      triggerSync();
    };
    activeDocument.addEventListener("visibilitychange", handler);

    // Scenario 2: kill → cold start (only if user hasn't configured initRunAfterMilliseconds)
    if ((this.settings.initRunAfterMilliseconds ?? 0) <= 0) {
      this.app.workspace.onLayoutReady(() => {
        if (!this.isSyncing) {
          console.debug("[BYOC] Mobile cold-start sync: triggering initial syncRun");
          activeWindow.setTimeout(() => this.syncRun("manual"), RESUME_DEBOUNCE_MS);
        }
      });
    }

    this.register(() => {
      activeDocument.removeEventListener("visibilitychange", handler);
      activeWindow.clearTimeout(resumeTimer);
    });
  }

  /**
   * Mobile Sync Button — injected into Obsidian's bottom toolbar, immediately
   * to the LEFT of the settings cog. Lives in the toolbar or not at all; if
   * the toolbar never renders, the user still has the command palette
   * "Sync now" entry — we don't fall back to a floating overlay.
   *
   * A MutationObserver on document.body survives both the cold-start race
   * (toolbar mounts after layout-ready) and any later re-render where
   * Obsidian replaces the toolbar element. The callback is cheap: once the
   * button is in the DOM, btn.isConnected short-circuits before the
   * querySelector runs.
   *
   * The isSyncing guard and CSS pointer-events:none both block concurrent
   * taps (belt-and-suspenders — either alone would suffice).
   */
  enableMobileSyncButton() {
    if (!Platform.isMobile) return;

    // Use Obsidian's native navbar-action styling (icon-only, transparent),
    // and add our own class so we can style the spinning state.
    const btn = activeDocument.createElement("div");
    btn.addClass("mobile-navbar-action");
    btn.addClass("byoc-mobile-sync");
    btn.setAttribute("aria-label", "Sync vault now");
    setIcon(btn, iconNameSyncWait);

    btn.addEventListener("click", async () => {
      if (this.isSyncing) return;
      btn.addClass("byoc-mobile-sync--syncing");
      setIcon(btn, iconNameSyncRunning);
      try {
        await this.syncRun("manual");
      } finally {
        btn.removeClass("byoc-mobile-sync--syncing");
        setIcon(btn, iconNameSyncWait);
      }
    });

    const tryInject = () => {
      if (btn.isConnected) return;
      this._tryInjectSyncButton(btn);
    };

    this.app.workspace.onLayoutReady(() => {
      tryInject();

      const observer = new MutationObserver(tryInject);
      observer.observe(activeDocument.body, { childList: true, subtree: true });
      this.register(() => observer.disconnect());
    });

    this.register(() => btn.remove());
  }

  async _checkCurrFileModified(caller: "SYNC" | "FILE_CHANGES") {
    const currentFile = this.app.workspace.getActiveFile();
    if (caller === "FILE_CHANGES") {
      // For vault events (create/delete/rename/modify), always trigger sync
      // regardless of active file state. Deletion events remove the active file,
      // so we can't rely on getActiveFile() here.
      if (this.isSyncing) { this.hasPendingSyncOnSave = true; return; }
      this.hasPendingSyncOnSave = false;
      await this.syncRun("auto_sync_on_save");
    } else if (caller === "SYNC" && currentFile) {
      // Post-sync check: only re-sync if the active file was modified after last sync.
      const lastModified = currentFile.stat.mtime;
      const lastSuccessSyncMillis = await getLastSuccessSyncTimeByVault(this.db, this.vaultRandomID);
      if (lastModified > (lastSuccessSyncMillis ?? 1)) {
        if (this.isSyncing) { this.hasPendingSyncOnSave = true; return; }
        if (this.hasPendingSyncOnSave) {
          this.hasPendingSyncOnSave = false;
          await this.syncRun("auto_sync_on_save");
        }
      }
    }
  }

  _syncOnSaveEvent1 = () => { this._checkCurrFileModified("SYNC"); };
  
  _debouncedSyncImpl?: ReturnType<typeof debounce>;
  _syncOnSaveRegistered = false;
  
  _syncOnSaveEvent2 = async (...args: any[]) => {
    this._debouncedSyncImpl?.(...args);
  };

  toggleSyncOnSaveIfSet() {
    this._debouncedSyncImpl?.cancel();

    if (this.settings.syncOnSaveAfterMilliseconds != null && this.settings.syncOnSaveAfterMilliseconds > 0) {
      this._debouncedSyncImpl = debounce(
        async () => { await this._checkCurrFileModified("FILE_CHANGES"); },
        this.settings.syncOnSaveAfterMilliseconds,
        { leading: false, trailing: true }
      );

      if (!this._syncOnSaveRegistered) {
        this._syncOnSaveRegistered = true;
        this.app.workspace.onLayoutReady(() => {
          this.registerEvent(this.syncEvent?.on("SYNC_DONE", this._syncOnSaveEvent1)!);
          this.registerEvent(this.app.vault.on("modify", this._syncOnSaveEvent2));
          this.registerEvent(this.app.vault.on("create", this._syncOnSaveEvent2));
          this.registerEvent(this.app.vault.on("delete", this._syncOnSaveEvent2));
          this.registerEvent(this.app.vault.on("rename", this._syncOnSaveEvent2));
        });
      }
    } else {
      this._debouncedSyncImpl = undefined;
      // We intentionally do not unregister events here.
      // They pipe into the undefined wrapper as a no-op.
    }
  }



  enableCheckingFileStat() {
    this.app.workspace.onLayoutReady(() => {
      const t = (x: TransItemType, vars?: Record<string, string>) => this.i18n.t(x, vars);
      this.registerEvent(
        this.app.workspace.on("file-menu", (menu, file) => {
          if (file instanceof TFolder) return;
          menu.addItem((item) => {
            item.setTitle(t("menu_check_file_stat")).setIcon("file-cog").onClick(async () => {
              const fsLocal = new FakeFsLocal(
                this.app.vault, this.settings.syncConfigDir ?? false, this.settings.syncBookmarks ?? false,
                this.app.vault.configDir, this.manifest.id, undefined, this.settings.deleteToWhere ?? "system"
              );
              const s = await fsLocal.stat(file.path);
              new Notice(JSON.stringify(s, null, 2), 10000);
            });
          });
        })
      );
    });
  }

  async saveAgreeToUseNewSyncAlgorithm() {
    this.settings.agreeToUseSyncV3 = true;
    await this.saveSettings();
  }

  setCurrSyncMsg(
    t: (x: TransItemType, vars?: Record<string, string>) => string,
    s: SyncTriggerSourceType,
    i: number,
    totalCount: number,
    pathName: string,
    decision: string,
    triggerSource: SyncTriggerSourceType
  ) {
    const shortMsg = `BYOC ⟳ ${i}/${totalCount}`;
    const longMsg = `Syncing ${i}/${totalCount}: ${pathName} (${decision})`;
    this.currSyncMsg = longMsg;
    if (this.statusBarElement !== undefined) {
      this.statusBarElement.setText(shortMsg);
      this.statusBarElement.setAttribute("aria-label", longMsg);
    }
  }

  updateLastSyncMsg(
    s: SyncTriggerSourceType | undefined,
    syncStatus: "not_syncing" | "syncing",
    lastSuccessSyncMillis: number | null | undefined,
    lastFailedSyncMillis: number | null | undefined
  ) {
    if (this.statusBarElement === undefined) return;
    const t = (x: TransItemType, vars?: Record<string, string>) => this.i18n.t(x, vars);

    if (syncStatus === "syncing") {
      this.statusBarElement.setText("BYOC ⟳");
      this.statusBarElement.setAttribute("aria-label", "Syncing now…");
      return;
    }

    const inputTs = Math.max(lastSuccessSyncMillis ?? -999, lastFailedSyncMillis ?? -999);
    const isSuccess = (lastSuccessSyncMillis ?? -999) >= (lastFailedSyncMillis ?? -999);

    if (inputTs <= 0) {
      this.statusBarElement.setText("BYOC —");
      this.statusBarElement.setAttribute("aria-label", "Never synced. Click to sync now.");
      return;
    }

    const icon = isSuccess ? "✓" : "✗";
    const delta = Date.now() - inputTs;
    const ago =
      delta < 60_000 ? "now" :
      delta < 3_600_000 ? `${Math.floor(delta / 60_000)}m` :
      delta < 86_400_000 ? `${Math.floor(delta / 3_600_000)}h` :
      `${Math.floor(delta / 86_400_000)}d`;

    const shortMsg = `BYOC ${icon} ${ago}`;
    const dateText = new Date(inputTs).toLocaleTimeString(navigator.language, {
      weekday: "long", year: "numeric", month: "long", day: "numeric"
    });
    const statusWord = isSuccess ? "Succeeded" : "Failed";
    // We use the language placeholder string for the date to preserve internationalization.
    const longMsg = `Last sync ${statusWord}: ` + t("statusbar_lastsync_label", { date: dateText }) + ". Click to sync now.";

    this.statusBarElement.setText(shortMsg);
    this.statusBarElement.setAttribute("aria-label", longMsg);
  }

  async tryToAddIgnoreFile() {
    const pluginConfigDir = this.manifest.dir || `${this.app.vault.configDir}/plugins/${this.manifest.id}`;
    const pluginConfigDirExists = await this.app.vault.adapter.exists(pluginConfigDir);
    if (!pluginConfigDirExists) return;
    const ignoreFile = `${pluginConfigDir}/.gitignore`;
    const ignoreFileExists = await this.app.vault.adapter.exists(ignoreFile);
    if (!ignoreFileExists) {
      try { this.app.vault.adapter.write(ignoreFile, "data.json\n"); } catch (_) {}
    }
  }

  enableAutoClearOutputToDBHistIfSet() {
    this.app.workspace.onLayoutReady(() => {
      activeWindow.setTimeout(() => clearAllLoggerOutputRecords(this.db), 1000 * 30);
    });
  }

  enableAutoClearSyncPlanHist() {
    this.app.workspace.onLayoutReady(() => {
      activeWindow.setTimeout(() => clearExpiredSyncPlanRecords(this.db), 1000 * 45);
      const intervalID = activeWindow.setInterval(() => clearExpiredSyncPlanRecords(this.db), 1000 * 60 * 5);
      this.registerInterval(intervalID);
    });
  }
}

import isEqual from "lodash/isEqual";
import { base64url } from "rfc4648";
import { reverseString } from "./misc";

const DEFAULT_README_FOR_METADATAONREMOTE =
  "Do NOT edit or delete the file manually. This file is for the plugin remotely-save to store some necessary meta data on the remote services. Its content is slightly obfuscated.";

const DEFAULT_VERSION_FOR_METADATAONREMOTE = "20220220";

export const DEFAULT_FILE_NAME_FOR_METADATAONREMOTE =
  "_remotely-save-metadata-on-remote.json";

export const DEFAULT_FILE_NAME_FOR_METADATAONREMOTE2 =
  "_remotely-save-metadata-on-remote.bin";

export interface DeletionOnRemote {
  key: string;
  actionWhen: number;
}

export interface MetadataOnRemote {
  version?: string;
  generatedWhen?: number;
  deletions?: DeletionOnRemote[];
}

export const isEqualMetadataOnRemote = (
  a: MetadataOnRemote | undefined,
  b: MetadataOnRemote | undefined
) => {
  const m1 = a === undefined ? { deletions: [] } : a;
  const m2 = b === undefined ? { deletions: [] } : b;

  // we only need to compare deletions
  const d1 = m1.deletions === undefined ? [] : m1.deletions;
  const d2 = m2.deletions === undefined ? [] : m2.deletions;
  return isEqual(d1, d2);
};

export const serializeMetadataOnRemote = (x: MetadataOnRemote) => {
  const y = x;

  if (y["version"] === undefined) {
    y["version"] === DEFAULT_VERSION_FOR_METADATAONREMOTE;
  }
  if (y["generatedWhen"] === undefined) {
    y["generatedWhen"] = Date.now();
  }
  if (y["deletions"] === undefined) {
    y["deletions"] = [];
  }

  const z = {
    readme: DEFAULT_README_FOR_METADATAONREMOTE,
    d: reverseString(
      base64url.stringify(Buffer.from(JSON.stringify(x), "utf-8"), {
        pad: false,
      })
    ),
  };

  return JSON.stringify(z, null, 2);
};

export const deserializeMetadataOnRemote = (x: string | ArrayBuffer) => {
  let y1 = "";
  if (typeof x === "string") {
    y1 = x;
  } else {
    y1 = new TextDecoder().decode(x);
  }

  let y2: any;
  try {
    y2 = JSON.parse(y1);
  } catch (e) {
    throw new Error(
      `invalid remote meta data file with first few chars: ${y1.slice(0, 5)}`
    );
  }

  if (!("readme" in y2 && "d" in y2)) {
    throw new Error(
      'invalid remote meta data file (no "readme" or "d" fields)!'
    );
  }

  let y3: string;
  try {
    y3 = (
      base64url.parse(reverseString(y2["d"]), {
        out: Buffer.allocUnsafe as any,
        loose: true,
      }) as Buffer
    ).toString("utf-8");
  } catch (e) {
    throw new Error('invalid remote meta data file (invalid "d" field)!');
  }

  let y4: MetadataOnRemote;
  try {
    y4 = JSON.parse(y3) as MetadataOnRemote;
  } catch (e) {
    throw new Error(
      `invalid remote meta data file with "d" field with first few chars: ${y3.slice(
        0,
        5
      )}`
    );
  }
  return y4;
};

/**
 * BYOC — Data Migration Module
 *
 * Handles seamless migration from `remotely-save` plugin configs
 * to the BYOC format. Runs once on first load, backs up original
 * data, and strips all credential expiry timers.
 *
 * Migration version history:
 *   0 → 1: Initial migration from remotely-save format
 */

import cloneDeep from "lodash/cloneDeep";
import { Notice, type Plugin } from "obsidian";
import type { BYOCPluginSettings } from "./baseTypes";
import { messyConfigToNormal } from "./configPersist";

/** Current migration version — bump when adding new migrations */
export const CURRENT_MIGRATION_VERSION = 1;

/** The old plugin's data directory name */
const LEGACY_PLUGIN_ID = "remotely-save";

/**
 * Checks if a legacy `remotely-save` plugin folder exists in the vault,
 * reads its data.json, decodes it, and returns the parsed settings.
 * Returns null if no legacy data found or if it can't be parsed.
 */
async function readLegacyConfig(
  plugin: Plugin
): Promise<Record<string, any> | null> {
  const legacyDataPath = `${plugin.app.vault.configDir}/plugins/${LEGACY_PLUGIN_ID}/data.json`;

  try {
    const exists = await plugin.app.vault.adapter.exists(legacyDataPath);
    if (!exists) {
      console.debug("[BYOC Migration] No legacy remotely-save data.json found.");
      return null;
    }

    const raw = await plugin.app.vault.adapter.read(legacyDataPath);
    const parsed = JSON.parse(raw);

    // The legacy plugin uses the same messy encoding (base64url reversed)
    const decoded = messyConfigToNormal(parsed);
    if (!decoded) {
      console.warn("[BYOC Migration] Legacy data.json decoded to null.");
      return null;
    }

    console.debug("[BYOC Migration] Successfully read legacy remotely-save config.");
    return decoded;
  } catch (err) {
    console.warn("[BYOC Migration] Failed to read legacy config:", err);
    return null;
  }
}

/**
 * Creates a backup of the current BYOC data.json before migration.
 * The backup is written to data.json.byoc-backup in the BYOC plugin dir.
 */
async function backupCurrentConfig(plugin: Plugin): Promise<void> {
  const pluginDir =
    plugin.manifest.dir ||
    `${plugin.app.vault.configDir}/plugins/${plugin.manifest.id}`;
  const dataPath = `${pluginDir}/data.json`;
  const backupPath = `${pluginDir}/data.json.byoc-backup`;

  try {
    const exists = await plugin.app.vault.adapter.exists(dataPath);
    if (exists) {
      const raw = await plugin.app.vault.adapter.read(dataPath);
      await plugin.app.vault.adapter.write(backupPath, raw);
      console.debug(`[BYOC Migration] Backed up data.json → ${backupPath}`);
    }
  } catch (err) {
    console.warn("[BYOC Migration] Failed to create backup:", err);
  }
}

/**
 * Strips all credential expiry timers from provider configs.
 * The old plugin had an 80-day nuke that force-deleted tokens.
 * BYOC keeps credentials indefinitely until manually revoked.
 */
function stripCredentialExpiry(settings: BYOCPluginSettings): void {
  // Dropbox
  if (settings.dropbox?.credentialsShouldBeDeletedAtTime) {
    delete settings.dropbox.credentialsShouldBeDeletedAtTime;
  }

  // OneDrive
  if (settings.onedrive?.credentialsShouldBeDeletedAtTime) {
    delete settings.onedrive.credentialsShouldBeDeletedAtTime;
  }

  // OneDrive Full
  if (settings.onedrivefull?.credentialsShouldBeDeletedAtTime) {
    delete settings.onedrivefull.credentialsShouldBeDeletedAtTime;
  }

  // Google Drive
  if (settings.googledrive?.credentialsShouldBeDeletedAtTimeMs) {
    delete settings.googledrive.credentialsShouldBeDeletedAtTimeMs;
  }

  // Box
  if (settings.box?.credentialsShouldBeDeletedAtTimeMs) {
    delete settings.box.credentialsShouldBeDeletedAtTimeMs;
  }

  // pCloud
  if (settings.pcloud?.credentialsShouldBeDeletedAtTimeMs) {
    delete settings.pcloud.credentialsShouldBeDeletedAtTimeMs;
  }

  // Yandex Disk
  if (settings.yandexdisk?.credentialsShouldBeDeletedAtTimeMs) {
    delete settings.yandexdisk.credentialsShouldBeDeletedAtTimeMs;
  }

  // Koofr
  if (settings.koofr?.credentialsShouldBeDeletedAtTimeMs) {
    delete settings.koofr.credentialsShouldBeDeletedAtTimeMs;
  }
}

/**
 * Extracts provider configs that lived under the `pro` key in the
 * legacy plugin and promotes them to top-level fields in BYOC settings.
 */
function extractProConfigs(
  legacyConfig: Record<string, unknown>,
  settings: BYOCPluginSettings
): void {
  const proRaw = legacyConfig.pro;
  if (!proRaw || typeof proRaw !== "object") return;
  const pro = proRaw as Record<string, unknown>;

  // The pro object could contain nested provider configs
  // Map known pro fields to their BYOC top-level equivalents
  const providerMap: Record<string, keyof BYOCPluginSettings> = {
    googledrive: "googledrive",
    box: "box",
    pcloud: "pcloud",
    yandexdisk: "yandexdisk",
    koofr: "koofr",
    azureblobstorage: "azureblobstorage",
    onedrivefull: "onedrivefull",
  };

  for (const [proKey, settingsKey] of Object.entries(providerMap)) {
    if (pro[proKey] && typeof pro[proKey] === "object") {
      // Only merge if the current config is empty/default
      const current = settings[settingsKey] as Record<string, any> | undefined;
      const incoming = pro[proKey] as Record<string, any>;

      // Check if incoming has real data (e.g., a non-empty accessToken)
      const hasRealData =
        incoming.accessToken ||
        incoming.refreshToken ||
        incoming.containerSasUrl;

      if (hasRealData) {
        (settings as any)[settingsKey] = {
          ...((current as any) || {}),
          ...cloneDeep(incoming),
        };
        console.debug(
          `[BYOC Migration] Promoted pro.${proKey} config to top-level.`
        );
      }
    }
  }

  // Also check if pro had feature flags we can learn from
  if (pro.enabledProFeatures && Array.isArray(pro.enabledProFeatures)) {
    console.debug(
      `[BYOC Migration] Legacy pro features detected: ${pro.enabledProFeatures.join(", ")}. All features enabled in BYOC by default.`
    );
  }
}

/**
 * Merges legacy remotely-save settings into the current BYOC settings.
 * Preserves existing BYOC values — only fills in fields that are
 * empty/default in BYOC but have real data in the legacy config.
 */
function mergeLegacyIntoSettings(
  legacyConfig: Record<string, unknown>,
  settings: BYOCPluginSettings
): void {
  // Core provider configs that exist at top level in both old and new
  const directProviders = [
    "s3",
    "webdav",
    "dropbox",
    "onedrive",
    "webdis",
  ] as const;

  for (const provider of directProviders) {
    const legacyRaw = legacyConfig[provider];
    if (!legacyRaw || typeof legacyRaw !== "object") continue;
    const legacy = legacyRaw as Record<string, unknown>;

    const current = settings[provider] as Record<string, any>;
    if (!current) continue;

    // Check if legacy has meaningful credentials
    const hasCredentials =
      legacy.accessToken ||
      legacy.refreshToken ||
      legacy.s3AccessKeyID ||
      legacy.address ||
      legacy.password;

    if (hasCredentials) {
      // Merge legacy into current, legacy values fill gaps
      for (const [key, value] of Object.entries(legacy)) {
        if (
          value !== undefined &&
          value !== null &&
          value !== "" &&
          (current[key] === undefined ||
            current[key] === null ||
            current[key] === "")
        ) {
          current[key] = cloneDeep(value);
        }
      }
      console.debug(
        `[BYOC Migration] Merged legacy ${provider} credentials.`
      );
    }
  }

  // Scalar settings — only copy if BYOC has the default value
  const scalarFields: Array<{
    key: keyof BYOCPluginSettings;
    defaultVal: any;
  }> = [
    { key: "serviceType", defaultVal: "s3" },
    { key: "password", defaultVal: "" },
    { key: "currLogLevel", defaultVal: "info" },
    { key: "autoRunEveryMilliseconds", defaultVal: -1 },
    { key: "initRunAfterMilliseconds", defaultVal: -1 },
    { key: "syncOnSaveAfterMilliseconds", defaultVal: -1 },
    { key: "concurrency", defaultVal: 5 },
    { key: "syncConfigDir", defaultVal: false },
    { key: "syncBookmarks", defaultVal: false },
    { key: "skipSizeLargerThan", defaultVal: -1 },
    { key: "ignorePaths", defaultVal: [] },
    { key: "onlyAllowPaths", defaultVal: [] },
    { key: "deleteToWhere", defaultVal: "system" },
    { key: "conflictAction", defaultVal: "keep_newer" },
    { key: "protectModifyPercentage", defaultVal: 50 },
    { key: "syncDirection", defaultVal: "bidirectional" },
    { key: "encryptionMethod", defaultVal: "unknown" },
  ];

  for (const { key, defaultVal } of scalarFields) {
    const legacyVal = legacyConfig[key];
    const currentVal = settings[key];

    if (legacyVal !== undefined && legacyVal !== null) {
      // Only overwrite if BYOC still has the default
      const isDefault =
        Array.isArray(defaultVal)
          ? Array.isArray(currentVal) && (currentVal as any[]).length === 0
          : currentVal === defaultVal;

      if (isDefault) {
        (settings as any)[key] = cloneDeep(legacyVal);
      }
    }
  }

  // Extract pro-gated provider configs
  extractProConfigs(legacyConfig, settings);
}

/**
 * Main migration entry point. Called from plugin.onload() AFTER
 * loadSettings() has already run. This means settings already has
 * defaults applied — we're layering legacy data on top.
 *
 * Returns true if migration was performed.
 */
export async function runMigration(
  plugin: Plugin,
  settings: BYOCPluginSettings
): Promise<boolean> {
  const currentVersion = settings.migrationVersion ?? 0;

  if (currentVersion >= CURRENT_MIGRATION_VERSION) {
    // Already migrated, nothing to do
    return false;
  }

  console.debug(
    `[BYOC Migration] Running migration v${currentVersion} → v${CURRENT_MIGRATION_VERSION}`
  );

  // Step 1: Backup existing BYOC data.json
  await backupCurrentConfig(plugin);

  // Step 2: Read legacy remotely-save config
  const legacyConfig = await readLegacyConfig(plugin);

  if (legacyConfig) {
    // Step 3: Merge legacy data into current settings
    mergeLegacyIntoSettings(legacyConfig, settings);

    // Step 4: Strip all credential expiry timers
    stripCredentialExpiry(settings);

    // Step 5: Clean up deprecated pro field
    if ("pro" in settings) {
      delete (settings as any).pro;
    }

    new Notice(
      "[BYOC] Migrated settings from Remotely Save. Your old config is backed up.",
      8000
    );
    console.debug("[BYOC Migration] Migration from remotely-save complete.");
  } else {
    // No legacy config found, but still strip expiry timers
    // in case user manually copied settings
    stripCredentialExpiry(settings);
    console.debug("[BYOC Migration] No legacy config found. Applied defaults.");
  }

  // Step 6: Stamp migration version
  settings.migrationVersion = CURRENT_MIGRATION_VERSION;

  return true;
}

import * as path from "path";
import type { Vault } from "obsidian";

import emojiRegex from "emoji-regex";
import { base32 } from "rfc4648";
import XRegExp from "xregexp";

declare global {
  interface Window {
    moment: (...data: any) => any;
  }
}

/**
 * If any part of the file starts with '.' or '_' then it's a hidden file.
 * @param item
 * @param dot
 * @param underscore
 * @returns
 */
export const isHiddenPath = (item: string, dot = true, underscore = true) => {
  if (!(dot || underscore)) {
    throw Error("parameter error for isHiddenPath");
  }
  const k = path.posix.normalize(item); // TODO: only unix path now
  const k2 = k.split("/"); // TODO: only unix path now
  // console.debug(k2)
  for (const singlePart of k2) {
    if (singlePart === "." || singlePart === ".." || singlePart === "") {
      continue;
    }
    if (dot && singlePart[0] === ".") {
      return true;
    }
    if (underscore && singlePart[0] === "_") {
      return true;
    }
  }
  return false;
};

/**
 * Util func for mkdir -p based on the "path" of original file or folder
 * "a/b/c/" => ["a", "a/b", "a/b/c"]
 * "a/b/c/d/e.txt" => ["a", "a/b", "a/b/c", "a/b/c/d"]
 * @param x string
 * @returns string[] might be empty
 */
export const getFolderLevels = (x: string, addEndingSlash = false) => {
  const res: string[] = [];

  if (x === "" || x === "/") {
    return res;
  }

  const y1 = x.split("/");
  const i = 0;
  for (let index = 0; index + 1 < y1.length; index++) {
    let k = y1.slice(0, index + 1).join("/");
    if (k === "" || k === "/") {
      continue;
    }
    if (addEndingSlash) {
      k = `${k}/`;
    }
    res.push(k);
  }
  return res;
};

export const mkdirpInVault = async (thePath: string, vault: Vault) => {
  // console.debug(thePath);
  const foldersToBuild = getFolderLevels(thePath);
  // console.debug(foldersToBuild);
  for (const folder of foldersToBuild) {
    const r = await vault.adapter.exists(folder);
    // console.debug(r);
    if (!r) {
      console.debug(`mkdir ${folder}`);
      await vault.adapter.mkdir(folder);
    }
  }
};

/**
 * https://stackoverflow.com/questions/8609289
 * @param b Buffer
 * @returns ArrayBuffer
 */
export const bufferToArrayBuffer = (
  b: Buffer | Uint8Array | ArrayBufferView
) => {
  return b.buffer.slice(b.byteOffset, b.byteOffset + b.byteLength);
};

/**
 * Simple func.
 * @param b
 * @returns
 */
export const arrayBufferToBuffer = (b: ArrayBuffer) => {
  return Buffer.from(b);
};

export const arrayBufferToBase64 = (b: ArrayBuffer) => {
  return arrayBufferToBuffer(b).toString("base64");
};

export const arrayBufferToHex = (b: ArrayBuffer) => {
  return arrayBufferToBuffer(b).toString("hex");
};

export const base64ToArrayBuffer = (b64text: string) => {
  return bufferToArrayBuffer(Buffer.from(b64text, "base64"));
};

export const copyArrayBuffer = (src: ArrayBuffer) => {
  const dst = new ArrayBuffer(src.byteLength);
  new Uint8Array(dst).set(new Uint8Array(src));
  return dst;
};

/**
 * https://stackoverflow.com/questions/43131242
 * @param hex
 * @returns
 */
export const hexStringToTypedArray = (hex: string) => {
  const f = hex.match(/[\da-f]{2}/gi);
  if (f === null) {
    throw Error(`input ${hex} is not hex, no way to transform`);
  }
  return new Uint8Array(f.map((h) => Number.parseInt(h, 16)));
};

export const base64ToBase32 = (a: string) => {
  return base32.stringify(Buffer.from(a, "base64"));
};

export const base64ToBase64url = (a: string, pad = false) => {
  let b = a.replace(/\+/g, "-").replace(/\//g, "_");
  if (!pad) {
    b = b.replace(/=/g, "");
  }
  return b;
};

/**
 * iOS Safari could decrypt string with invalid password!
 * So we need an extra way to test the decrypted result.
 * One simple way is testing the result are "valid", printable chars or not.
 *
 * https://stackoverflow.com/questions/6198986
 * https://www.regular-expressions.info/unicode.html
 * Manual test shows that emojis like '🍎' match '\\p{Cs}',
 * so we need to write the regrex in a form that \p{C} minus \p{Cs}
 * @param a
 */
export const isVaildText = (a: string) => {
  if (a === undefined) {
    return false;
  }
  // If the regex matches, the string is invalid.
  return !XRegExp("\\p{Cc}|\\p{Cf}|\\p{Co}|\\p{Cn}|\\p{Zl}|\\p{Zp}", "A").test(
    a
  );
};

/**
 * Use regex to detect a text contains emoji or not.
 * @param a
 * @returns
 */
export const hasEmojiInText = (a: string) => {
  const regex = emojiRegex();
  return regex.test(a);
};

/**
 * Convert the headers to a normal object.
 * @param h
 * @param toLower
 * @returns
 */
export const headersToRecord = (h: Headers, toLower = true) => {
  const res: Record<string, string> = {};
  h.forEach((v, k) => {
    if (toLower) {
      res[k.toLowerCase()] = v;
    } else {
      res[k] = v;
    }
  });
  return res;
};

/**
 * If input is already a folder, returns it as is;
 * And if input is a file, returns its direname.
 * @param a
 * @returns
 */
export const getPathFolder = (a: string) => {
  if (a.endsWith("/")) {
    return a;
  }
  const b = path.posix.dirname(a);
  return b.endsWith("/") ? b : `${b}/`;
};

/**
 * If input is already a folder, returns its folder;
 * And if input is a file, returns its direname.
 * @param a
 * @returns
 */
export const getParentFolder = (a: string) => {
  const b = path.posix.dirname(a);
  if (b === "." || b === "/") {
    // the root
    return "/";
  }
  if (b.endsWith("/")) {
    return b;
  }
  return `${b}/`;
};

/**
 * https://stackoverflow.com/questions/54511144
 * @param a
 * @param delimiter
 * @returns
 */
export const setToString = (a: Set<string>, delimiter = ",") => {
  return [...a].join(delimiter);
};

export const extractSvgSub = (x: string, subEl = "rect") => {
  const parser = new DOMParser();
  const dom = parser.parseFromString(x, "image/svg+xml");
  const svg = dom.querySelector("svg")!;
  svg.setAttribute("viewbox", "0 0 10 10");
  return svg.innerHTML;
};

/**
 * https://stackoverflow.com/questions/18230217
 * @param min
 * @param max
 * @returns
 */
export const getRandomIntInclusive = (min: number, max: number) => {
  const randomBuffer = new Uint32Array(1);
  activeWindow.crypto.getRandomValues(randomBuffer);
  const randomNumber = randomBuffer[0] / (0xffffffff + 1);
  const min2 = Math.ceil(min);
  const max2 = Math.floor(max);
  return Math.floor(randomNumber * (max2 - min2 + 1)) + min2;
};

/**
 * Random buffer
 * @param byteLength
 * @returns
 */
export const getRandomArrayBuffer = (byteLength: number) => {
  const k = activeWindow.crypto.getRandomValues(new Uint8Array(byteLength));
  return bufferToArrayBuffer(k);
};

/**
 * https://stackoverflow.com/questions/958908
 * @param x
 * @returns
 */
export const reverseString = (x: string) => {
  return [...x].reverse().join("");
};

export interface SplitRange {
  partNum: number; // starting from 1
  start: number;
  end: number; // exclusive
}
export const getSplitRanges = (bytesTotal: number, bytesEachPart: number) => {
  const res: SplitRange[] = [];
  if (bytesEachPart >= bytesTotal) {
    res.push({
      partNum: 1,
      start: 0,
      end: bytesTotal,
    });
    return res;
  }
  const remainder = bytesTotal % bytesEachPart;
  const howMany =
    Math.floor(bytesTotal / bytesEachPart) + (remainder === 0 ? 0 : 1);
  for (let i = 0; i < howMany; ++i) {
    res.push({
      partNum: i + 1,
      start: bytesEachPart * i,
      end: Math.min(bytesEachPart * (i + 1), bytesTotal),
    });
  }
  return res;
};

/**
 * https://stackoverflow.com/questions/332422
 * @param obj anything
 * @returns string of the name of the object
 */
export const getTypeName = (obj: any) => {
  return Object.prototype.toString.call(obj).slice(8, -1);
};

/**
 * starting from 1
 * @param x
 * @returns
 */
export const atWhichLevel = (x: string | undefined) => {
  if (
    x === undefined ||
    x === "" ||
    x === "." ||
    x === ".." ||
    x.startsWith("/")
  ) {
    throw Error(`do not know which level for ${x}`);
  }
  let y = x;
  if (x.endsWith("/")) {
    y = x.slice(0, -1);
  }
  return y.split("/").length;
};

export const checkHasSpecialCharForDir = (x: string) => {
  return /[?/\\]/.test(x);
};

export const unixTimeToStr = (x: number | undefined | null, hasMs = false) => {
  if (x === undefined || x === null || Number.isNaN(x)) {
    return undefined;
  }
  if (hasMs) {
    // 1716712162574 => '2024-05-26T16:29:22.574+08:00'
    return activeWindow.moment(x).toISOString(true);
  } else {
    // 1716712162574 => '2024-05-26T16:29:22+08:00'
    return activeWindow.moment(x).format() as string;
  }
};

/**
 * https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Errors/Cyclic_object_value#examples
 * @returns
 */
const getCircularReplacer = () => {
  const seen = new WeakSet();
  return (key: any, value: any) => {
    if (typeof value === "object" && value !== null) {
      if (seen.has(value)) {
        return;
      }
      seen.add(value);
    }
    return value;
  };
};

/**
 * Convert "any" value to string.
 * @param x
 * @returns
 */
export const toText = (x: any) => {
  if (x === undefined || x === null) {
    return `${x}`;
  }
  if (typeof x === "string") {
    return x;
  }
  if (
    x instanceof String ||
    x instanceof Date ||
    typeof x === "number" ||
    typeof x === "bigint" ||
    typeof x === "boolean"
  ) {
    return `${x}`;
  }

  if (
    x instanceof Error ||
    (x?.stack &&
      x?.message &&
      typeof x.stack === "string" &&
      typeof x.message === "string")
  ) {
    return `ERROR! MESSAGE: ${x.message}, STACK: ${x.stack}`;
  }

  try {
    const y = JSON.stringify(x, getCircularReplacer(), 2);
    if (y !== undefined) {
      return y;
    }
    throw new Error("not jsonable");
  } catch {
    return `${x}`;
  }
};

/**
 * On Android the stat has bugs for folders. So we need a fixed version.
 * @param vault
 * @param path
 */
export const statFix = async (vault: Vault, path: string) => {
  const s = await vault.adapter.stat(path);
  if (s === undefined || s === null) {
    throw Error(`${path} doesn't exist cannot run stat`);
  }
  if (s.ctime === undefined || s.ctime === null || Number.isNaN(s.ctime)) {
    s.ctime = undefined as any; // force assignment
  }
  if (s.mtime === undefined || s.mtime === null || Number.isNaN(s.mtime)) {
    s.mtime = undefined as any; // force assignment
  }
  if (
    (s.size === undefined || s.size === null || Number.isNaN(s.size)) &&
    s.type === "folder"
  ) {
    s.size = 0;
  }
  return s;
};

export const isSpecialFolderNameToSkip = (
  x: string,
  more: string[] | undefined
) => {
  const specialFolders = [
    ".git",
    ".github",
    ".gitlab",
    ".svn",
    "node_modules",
    ".DS_Store",
    "__MACOSX ",
    "Icon\r", // https://superuser.com/questions/298785/icon-file-on-os-x-desktop
    "desktop.ini",
    "Desktop.ini",
    "thumbs.db",
    "Thumbs.db",
  ].concat(more !== undefined ? more : []);
  for (const iterator of specialFolders) {
    if (
      x === iterator ||
      x === `${iterator}/` ||
      x.endsWith(`/${iterator}`) ||
      x.endsWith(`/${iterator}/`)
    ) {
      return true;
    }
  }

  // microsoft tmp files...
  const p = x.split("/");
  if (p.length > 0) {
    const f = p[p.length - 1]; // file name
    if (f.startsWith("~$")) {
      const suffixList = ["doc", "docx", "ppt", "pptx", "xls", "xlsx"];
      for (const suffix of suffixList) {
        if (f.endsWith(`.${suffix}`)) {
          return true;
        }
      }
    }
  }

  return false;
};

/**
 *
 * @param x versionX
 * @param y versionY
 * @returns 1(x>y), 0(x==y), -1(x<y)
 */
export const compareVersion = (x: string | null, y: string | null) => {
  if (x === undefined || x === null) {
    return -1;
  }
  if (y === undefined || y === null) {
    return 1;
  }
  if (x === y) {
    return 0;
  }
  const [x1, x2, x3] = x.split(".").map((k) => Number(k));
  const [y1, y2, y3] = y.split(".").map((k) => Number(k));
  if (
    x1 > y1 ||
    (x1 === y1 && x2 > y2) ||
    (x1 === y1 && x2 === y2 && x3 > y3)
  ) {
    return 1;
  }
  return -1;
};

