  }
  throw Error(`not supported stringify option = ${stringify}`);
};

/**
 * https://learn.microsoft.com/en-us/windows/win32/fileio/naming-a-file#naming-conventions
 * https://support.microsoft.com/en-us/office/restrictions-and-limitations-in-onedrive-and-sharepoint-64883a5d-228e-48f5-b3d2-eb39e07630fa#invalidcharacters
 */
export const checkValidName = (x: string) => {
  if (x === undefined || x === "") {
    // what??
    return {
      reason: "empty",
      result: false,
    };
  }

  // The following reserved characters:
  const invalidChars = '*"<>:|?'.split("");
  for (const c of invalidChars) {
    if (x.includes(c)) {
      return {
        reason: `reserved character: ${c}`,
        result: false,
      };
    }
  }

  // directory component
  for (const c of [".", ".."]) {
    if (
      x === c ||
      x.endsWith(`/${c}`) ||
      x.startsWith(`${c}/`) ||
      x.includes(`/${c}/`)
    ) {
      return {
        reason: `directory being ${c}`,
        result: false,
      };
    }
  }

  // reserved file names
  const reservedNames = [
    "CON",
    "PRN",
    "AUX",
    "NUL",
    "COM0",
    "COM1",
    "COM2",
    "COM3",
    "COM4",
    "COM5",
    "COM6",
    "COM7",
    "COM8",
    "COM9",
    "COM¹",
    "COM²",
    "COM³",
    "LPT0",
    "LPT1",
    "LPT2",
    "LPT3",
    "LPT4",
    "LPT5",
    "LPT6",
    "LPT7",
    "LPT8",
    "LPT9",
    "LPT¹",
    "LPT²",
    "LPT³",
  ];
  for (const f of reservedNames) {
    if (
      x === f ||
      x.startsWith(`${f}.`) ||
      x.startsWith(`${f}/`) ||
      x.includes(`/${f}/`) ||
      x.endsWith(`/${f}`) ||
      x.includes(`/${f}.`)
    ) {
      return {
        reason: `reserved folder/file name: ${f}`,
        result: false,
      };
    }
  }

  // Do not end a file or directory name with a space or a period.
  if (
    x.endsWith(" ") ||
    x.endsWith(".") ||
    x.includes(" /") ||
    x.includes("./")
  ) {
    return {
      reason: `folder/file name ending with a space or a period`,
      result: false,
    };
  }

  return {
    reason: "ok",
    result: true,
  };
};

/**
 * Drop-in replacement for `fetch()` with exponential backoff on HTTP 429.
 * Respects the server's `Retry-After` header when present.
 */
export const retryFetch = async (
  input: RequestInfo | URL,
  init?: RequestInit,
  extraHint = ""
): Promise<Response> => {
  const waitSeconds = [1, 2, 4, 8];
  const prefix = extraHint ? `${extraHint}: ` : "";
  for (let idx = 0; idx < waitSeconds.length; idx++) {
    if (idx !== 0) {
      console.warn(`${prefix}retry attempt ${idx + 1} at ${Date.now()}`);
    }
    // retryFetch is a Response-shaped wrapper used by Box and Google Drive
    // for streaming uploads/downloads. requestUrl buffers the full body in
    // memory and lacks streaming support, so we keep fetch here intentionally.
     
    const resp = await fetch(input, init);
    if (resp.status !== 429 || idx === waitSeconds.length - 1) {
      if (resp.status === 429 && idx === waitSeconds.length - 1) {
        throw new Error(`${prefix}429 too many requests after ${idx + 1} retries`);
      }
      return resp;
    }
    const svrSec = Number.parseInt(resp.headers.get("retry-after") || "0") || 0;
    const fallbackSec = waitSeconds[idx];
    const secMin = Math.max(svrSec, fallbackSec);
    const secMax = Math.max(secMin * 1.8, 2);
    console.warn(
      `${prefix}429 on attempt ${idx + 1}, waiting ${secMin}–${secMax}s before retry`
    );
    await delay(secMin * 1000 + Math.random() * (secMax - secMin) * 1000);
  }
  // unreachable, but TypeScript needs it
  throw new Error(`${prefix}retryFetch exhausted all retries`);
};

import type { ProfilerConfig, SUPPORTED_SERVICES_TYPE } from "./baseTypes";
import { type InternalDBs, insertProfilerResultByVault } from "./localdb";
import { roughSizeOfObject, unixTimeToStr } from "./misc";

interface BreakPoint {
  label: string;
  fakeTimeMilli: number; // it's NOT a unix timestamp
  indent: number;
  size?: number;
}

export const DEFAULT_PROFILER_CONFIG: ProfilerConfig = {
  enable: false,
  enablePrinting: false,
  recordSize: false,
};

export class Profiler {
  startTime: number;
  breakPoints: BreakPoint[];
  indent: number;
  enablePrinting: boolean;
  recordSize: boolean;
  constructor(label?: string, enablePrinting?: boolean, recordSize?: boolean) {
    this.breakPoints = [];
    this.indent = 0;
    this.startTime = 0;
    this.enablePrinting = enablePrinting ?? false;
    this.recordSize = recordSize ?? false;

    if (label !== undefined) {
      this.startTime = Date.now();
      const p = {
        label: label,
        fakeTimeMilli: performance.now(),
        indent: this.indent,
      };
      this.breakPoints.push(p);
      if (this.enablePrinting) {
        console.debug(this.toString(-1));
      }
    }
  }

  insert(label: string) {
    if (this.breakPoints.length === 0) {
      this.startTime = Date.now();
    }
    const p = {
      label: label,
      fakeTimeMilli: performance.now(),
      indent: this.indent,
    };
    this.breakPoints.push(p);
    if (this.enablePrinting) {
      console.debug(this.toString(-1));
    }

    return this;
  }

  insertSize(label: string, obj: any) {
    if (!this.recordSize) {
      return;
    }
    if (this.breakPoints.length === 0) {
      this.startTime = Date.now();
    }
    const p = {
      label: label,
      fakeTimeMilli: performance.now(),
      indent: this.indent,
      size: roughSizeOfObject(obj),
    };
    this.breakPoints.push(p);
    if (this.enablePrinting) {
      console.debug(this.toString(-1));
    }

    return this;
  }

  addIndent() {
    this.indent += 2;
  }
  removeIndent() {
    this.indent -= 2;
    if (this.indent < 0) {
      this.indent = 0;
    }
  }

  clear() {
    this.breakPoints = [];
    this.indent = 0;
    this.startTime = 0;
    return this;
  }

  toString(idx?: number) {
    if (idx !== undefined) {
      let i = idx;
      if (idx < 0) {
        i = this.breakPoints.length + idx;
      }
      const label = this.breakPoints?.[i]["label"];
      const indent = this.breakPoints?.[i]["indent"];
      let millsec = 0;
      if (i >= 1) {
        millsec =
          Math.round(
            (this.breakPoints?.[i]["fakeTimeMilli"] -
              this.breakPoints?.[i - 1]["fakeTimeMilli"]) *
              10
          ) / 10.0;
      }
      let res = `${" ".repeat(indent)}[${label}]: ${millsec}ms`;
      if (Object.prototype.hasOwnProperty.call(this.breakPoints[i], "size")) {
        const size = this.breakPoints[i].size as number;
        res += `, size=${size}`;
      }
      return res;
    }

    if (this.breakPoints.length === 0) {
      return "nothing in profiler";
    }

    let res = `[startTime]: ${unixTimeToStr(this.startTime)}`;
    for (let i = 0; i < this.breakPoints.length; ++i) {
      if (i === 0) {
        res += `\n[${this.breakPoints[i]["label"]}]: start`;
      } else {
        res += `\n${this.toString(i)}`;
      }
    }

    return res;
  }

  async save(
    db: InternalDBs,
    vaultRandomID: string,
    remoteType: SUPPORTED_SERVICES_TYPE
  ) {
    await insertProfilerResultByVault(
      db,
      this.toString(),
      vaultRandomID,
      remoteType
    );
  }
}

